INSERT INTO `daming_content_info` VALUES (168, '[{\"name\":\"单选题\",\"paperQuestionVMS\":[{\"id\":74,\"itemOrder\":0},{\"id\":71,\"itemOrder\":1},{\"id\":70,\"itemOrder\":2},{\"id\":67,\"itemOrder\":3},{\"id\":69,\"itemOrder\":4},{\"id\":68,\"itemOrder\":5},{\"id\":72,\"itemOrder\":6},{\"id\":73,\"itemOrder\":7},{\"id\":75,\"itemOrder\":8},{\"id\":66,\"itemOrder\":9}]}]', '2025-11-11 21:20:42');
INSERT INTO `daming_content_info` VALUES (169, '{\"analysis\":\"无\",\"correct\":\"C\",\"questionOptionList\":[{\"content\":\"软件定义\",\"prefix\":\"A\"},{\"content\":\"软件开发\",\"prefix\":\"B\"},{\"content\":\"详细设计\",\"prefix\":\"C\"},{\"content\":\"软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\" 一般说来，软件生命周期由三个大的时期组成，不包括下面哪个时期\"}', '2025-11-19 16:01:26');
INSERT INTO `daming_content_info` VALUES (170, '{\"analysis\":\"<p>正确答案是&nbsp;C。</p><p>解题思路：</p><ol><li>A 选项（时间错误）：软件危机是在&nbsp;20世纪60年代末至70年代​ 全面爆发并被正式提出的，而不是“70年代末期”。这个时间点不准确。</li><li>B 选项（结论错误）：软件工程方法极大地缓解了软件危机，但并未“已经解决”它。随着技术发展，新的复杂性和挑战不断出现，软件危机在某种程度上以新的形式存在。</li><li><span style=\\\"color: rgb(102, 185, 102);\\\">C 选项</span>（定义正确）：这是对“软件危机”最经典和准确的定义，它准确地描述了软件危机是在软件开发和维护过程中遇到的一系列严重问题（如预算超支、进度延误、质量低下、难以维护等）。</li><li>D 选项（定义片面）：软件危机不仅仅是指软件产品本身的质量问题，它更是一个涵盖项目管理、开发过程、技术方法和维护等全过程的综合性问题。这个选项的定义过于狭隘。</li></ol><p>因此，只有&nbsp;C 选项的说法是完全正确的。</p>\",\"correct\":\"C\",\"questionOptionList\":[{\"content\":\"软件危机在20世纪70年代末期全面爆发\",\"prefix\":\"A\"},{\"content\":\"前先进的软件工程方法已经解决了软件危机的问题\",\"prefix\":\"B\"},{\"content\":\"软件危机是指在软件开发和维护过程中所遇到的一系列严重问题\",\"prefix\":\"C\"},{\"content\":\"软件危机是指在软件产品中存在一系列的质量问题\",\"prefix\":\"D\"}],\"questionTitle\":\"下面的( )说法是正确的。\"}', '2025-11-19 16:23:14');
INSERT INTO `daming_content_info` VALUES (171, '{\"analysis\":\"<h3>解析：</h3><p>在软件生命周期的各个阶段中：</p><ul><li>D需求分析阶段：主要任务是确定软件系统要做什么，需要了解用户的需求并将其转化为系统的逻辑模型。数据流图（DFD- Data <span style=\\\"background-color: rgb(255, 255, 255); color: rgb(77, 77, 77);\\\">Flow&nbsp;Diagram</span>）是一种用于描述系统中数据流动和处理过程的图形化工具，它能够帮助分析人员清晰地展现系统的功能和数据关系，属于需求分析阶段的重要工作内容。</li><li>程序设计阶段：主要关注的是如何用具体的编程语言实现软件的功能，重点在于代码的编写，和数据流图这种需求级的建模工具无关。</li><li>详细设计阶段：侧重于对软件的模块内部结构、算法等进行详细的设计，通常使用流程图、伪代码等方式，而不是数据流图（数据流图更多是用于描述系统的整体逻辑功能，而非模块内部的详细设计）。</li><li>软件维护阶段：是对已经投入使用的软件进行修改、完善等工作，以适应新的需求或修复问题，和需求分析阶段的建模工作无关。</li></ul><p>所以画数据流图属于需求分析阶段的工作，答案为A。</p><p><br></p><p><img src=\\\"data:image/png;base64,\\\"></p><p><br></p><p><img src=\\\"data:image/png;base64,\\\"></p><p><br></p><p><br></p>\",\"correct\":\"A\",\"questionOptionList\":[{\"content\":\"需求分析\",\"prefix\":\"A\"},{\"content\":\" 程序设计\",\"prefix\":\"B\"},{\"content\":\" 详细设计\",\"prefix\":\"C\"},{\"content\":\" 软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\"按软件生命周期方法设计软件的过程中，画数据流图属于下面哪个阶段的工作( )。\"}', '2025-11-19 16:35:06');
INSERT INTO `daming_content_info` VALUES (172, '[{\"name\":\"单选题\",\"paperQuestionVMS\":[{\"id\":84,\"itemOrder\":0},{\"id\":78,\"itemOrder\":1},{\"id\":94,\"itemOrder\":2},{\"id\":81,\"itemOrder\":3},{\"id\":80,\"itemOrder\":4},{\"id\":77,\"itemOrder\":5},{\"id\":91,\"itemOrder\":6},{\"id\":79,\"itemOrder\":7},{\"id\":76,\"itemOrder\":8},{\"id\":85,\"itemOrder\":9},{\"id\":92,\"itemOrder\":10},{\"id\":93,\"itemOrder\":11},{\"id\":83,\"itemOrder\":12},{\"id\":95,\"itemOrder\":13},{\"id\":90,\"itemOrder\":14},{\"id\":86,\"itemOrder\":15},{\"id\":89,\"itemOrder\":16},{\"id\":87,\"itemOrder\":17},{\"id\":88,\"itemOrder\":18},{\"id\":96,\"itemOrder\":19}]}]', '2025-11-19 16:37:15');
INSERT INTO `daming_content_info` VALUES (173, '{\"analysis\":\"<h3>解析：</h3><ul><li>A、B、C选项描述的都是瀑布模型的特点或优点：</li><li class=\\\"ql-indent-1\\\">A强调规范化开发（优点）</li><li class=\\\"ql-indent-1\\\">B强调文档规范性（特点/优点）</li><li class=\\\"ql-indent-1\\\">C强调阶段验证（优点）</li><li>D选项揭示了瀑布模型的局限性：瀑布模型要求需求在项目初期完全确定，但实际项目中需求可能变化，这一特点使其难以适应需求变更的场景，因此属于缺点。</li></ul><p><br></p><p><br></p><p><br></p><p><br></p>\",\"correct\":\"D\",\"questionOptionList\":[{\"content\":\"可强迫开发人员采用规范化的方法\",\"prefix\":\"A\"},{\"content\":\"严格地规定了每个阶段必须提交的文档\",\"prefix\":\"B\"},{\"content\":\"要求每个阶段交出的所有产品都必须是经过验证的\",\"prefix\":\"C\"},{\"content\":\"适用于项目开始时需求已确定的情况\",\"prefix\":\"D\"}],\"questionTitle\":\"以下哪一个是瀑布模型的缺点。\"}', '2025-11-19 17:14:56');
INSERT INTO `daming_content_info` VALUES (174, '{\"analysis\":\"<p>解析（正确项）：</p><p><br></p><ul><li>喷泉模型属于<strong>面向对象的软件开发过程模型</strong>，以对象及其交互为核心，最适合面向对象开发方法。</li></ul><p>错误选项简析：</p><p><br></p><ul><li>A 结构化：强调功能分解、数据流图等，更偏过程驱动，不是喷泉模型的思想。</li><li>B 形式化：重在用数学语言严格描述和验证软件，与喷泉模型的“对象驱动”无直接对应。</li><li>D 面向数据：围绕数据结构和数据存取设计展开，与喷泉模型面向对象特征不匹配。</li></ul><p><br></p>\",\"correct\":\"C\",\"questionOptionList\":[{\"content\":\"结构化 \",\"prefix\":\"A\"},{\"content\":\"形式化 \",\"prefix\":\"B\"},{\"content\":\"面向对象 \",\"prefix\":\"C\"},{\"content\":\"面向数据\",\"prefix\":\"D\"}],\"questionTitle\":\"喷泉模型是对象驱动的，适合于( )的开发方法。\"}', '2025-11-19 17:23:15');
INSERT INTO `daming_content_info` VALUES (175, '{\"analysis\":\"<p>正确答案：B</p><p>解析（正确项）：</p><p><br></p><ul><li><span style=\\\"background-color: oklab(0.845175 0.0000383258 0.0000169277 / 0.1);\\\">Rational Rose</span>&nbsp;是典型的<strong>软件工程工具软件</strong>，用于UML建模、分析和设计，直接服务于软件开发过程。</li></ul><p>错误选项简析：</p><p><br></p><ul><li>A 字处理软件：通用办公应用软件，不是专门支持软件工程活动的工具。</li><li>C 操作系统：属于系统软件，提供运行环境，而非工程工具。</li><li>D DBMS：数据库管理系统，负责数据管理和存取，也不是专门的软件工程工具。</li></ul><p><br></p>\",\"correct\":\"B\",\"questionOptionList\":[{\"content\":\"字处理软件\",\"prefix\":\"A\"},{\"content\":\"Rational Rose\",\"prefix\":\"B\"},{\"content\":\"操作系统\",\"prefix\":\"C\"},{\"content\":\"DBMS\",\"prefix\":\"D\"}],\"questionTitle\":\"下列( )属于软件工程工具软件。\"}', '2025-11-19 17:30:13');
INSERT INTO `daming_content_info` VALUES (176, '{\"analysis\":\"<p>正确答案：B</p><p>解析（正确项）：</p><p><br></p><ul><li><span style=\\\"background-color: oklab(0.845175 0.0000383258 0.0000169277 / 0.1);\\\">Rational Rose</span>&nbsp;是典型的<strong>软件工程工具软件</strong>，用于UML建模、分析和设计，直接服务于软件开发过程。</li></ul><p>错误选项简析：</p><p><br></p><ul><li>A 字处理软件：通用办公应用软件，不是专门支持软件工程活动的工具。</li><li>C 操作系统：属于系统软件，提供运行环境，而非工程工具。</li><li>D DBMS：数据库管理系统，负责数据管理和存取，也不是专门的软件工程工具。</li></ul><p><br></p>\",\"correct\":\"B\",\"questionOptionList\":[{\"content\":\"字处理软件\",\"prefix\":\"A\"},{\"content\":\"Rational Rose\",\"prefix\":\"B\"},{\"content\":\"操作系统\",\"prefix\":\"C\"},{\"content\":\"DBMS\",\"prefix\":\"D\"}],\"questionTitle\":\"下列( )属于软件工程工具软件。\"}', '2025-11-19 18:19:40');
INSERT INTO `daming_content_info` VALUES (177, '{\"analysis\":\"<p>描述的就是“成本高、质量差”的矛盾，这是软件危机的定义。错误选项：A 软件工程是解决危机的方法论；B 软件周期是生命周期概念；D 不是专门术语。</p>\",\"correct\":\"C\",\"questionOptionList\":[{\"content\":\"软件工程\",\"prefix\":\"A\"},{\"content\":\"软件周期\",\"prefix\":\"B\"},{\"content\":\"软件危机\",\"prefix\":\"C\"},{\"content\":\"软件产生\",\"prefix\":\"D\"}],\"questionTitle\":\"开发软件所需高成本和产品的低质量之间有着尖锐的矛盾，这种现象称做( )。\"}', '2025-11-19 21:52:09');
INSERT INTO `daming_content_info` VALUES (178, '{\"analysis\":\"OMT（Object Modeling Technique）是 Rumbaugh 提出的面向对象分析与设计方法，其余选项是其它 OO 方法作者。\",\"correct\":\"B\",\"questionOptionList\":[{\"content\":\"Booch\",\"prefix\":\"A\"},{\"content\":\"Rumbaugh\",\"prefix\":\"B\"},{\"content\":\"Coad\",\"prefix\":\"C\"},{\"content\":\"Jacobson\",\"prefix\":\"D\"}],\"questionTitle\":\"OMT 方法是由下面哪位科学家提出的( )。\"}', '2025-11-19 21:52:09');
INSERT INTO `daming_content_info` VALUES (179, '{\"analysis\":\"题干给出的“三要素”正是软件工程方法学的定义，其余选项分别是过程、测试、生命周期概念。\",\"correct\":\"D\",\"questionOptionList\":[{\"content\":\"软件过程\",\"prefix\":\"A\"},{\"content\":\"软件测试\",\"prefix\":\"B\"},{\"content\":\"软件生命周期\",\"prefix\":\"C\"},{\"content\":\"软件工程方法学\",\"prefix\":\"D\"}],\"questionTitle\":\"( )是将系统化的、规范的、可定量的方法应用于软件的开发、运行和维护的过程，它包括方法、工具和过程三个要素。\"}', '2025-11-19 21:52:09');
INSERT INTO `daming_content_info` VALUES (180, '{\"analysis\":\"软件由程序、数据和相关文档组成，题干已有“文档、数据”，因此缺的就是“程序”。\",\"correct\":\"D\",\"questionOptionList\":[{\"content\":\"数据\",\"prefix\":\"A\"},{\"content\":\"软件\",\"prefix\":\"B\"},{\"content\":\"文档\",\"prefix\":\"C\"},{\"content\":\"程序\",\"prefix\":\"D\"}],\"questionTitle\":\"软件是计算机系统中与硬件相互依存的另一部分，它包括文挡、数据及( )。\"}', '2025-11-19 21:52:09');
INSERT INTO `daming_content_info` VALUES (181, '{\"analysis\":\"瀑布模型阶段按固定顺序一次完成，属于线性顺序模型；B/C 带迭代含义，D 更像原型/增量。\",\"correct\":\"A\",\"questionOptionList\":[{\"content\":\"线性顺序模型\",\"prefix\":\"A\"},{\"content\":\"顺序迭代模型\",\"prefix\":\"B\"},{\"content\":\"线性迭代模型\",\"prefix\":\"C\"},{\"content\":\"及早见产品的模型\",\"prefix\":\"D\"}],\"questionTitle\":\"瀑布模型本质上是一种( )。\"}', '2025-11-19 21:52:09');
INSERT INTO `daming_content_info` VALUES (182, '{\"analysis\":\"维护阶段伴随软件整个运行周期，成本通常超过开发期；A/B/C 都在开发期。\",\"correct\":\"D\",\"questionOptionList\":[{\"content\":\"详细设计\",\"prefix\":\"A\"},{\"content\":\"软件编码\",\"prefix\":\"B\"},{\"content\":\"软件测试\",\"prefix\":\"C\"},{\"content\":\"软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\"软件生命周期中所花费用最多的阶段是( )。\"}', '2025-11-19 21:52:09');
