INSERT INTO `daming_content_info` VALUES (189, '{\"analysis\":\"DFD 的核心就是用箭头表示数据流向，因此说“不反映数据流向”是错误的；A/B/C 都是 DFD 的正确特性。\",\"correct\":\"D\",\"questionOptionList\":[{\"content\":\"数据流图将各种信息流抽象成数据流的形式\",\"prefix\":\"A\"},{\"content\":\"数据流图不反映控制关系、调用关系\",\"prefix\":\"B\"},{\"content\":\"数据流图不反映处理逻辑的先后顺序\",\"prefix\":\"C\"},{\"content\":\"数据流图不反映数据的流向\",\"prefix\":\"D\"}],\"questionTitle\":\"下列描述错误的是( )。\"}', '2025-11-19 21:52:09');
