INSERT INTO `daming_content_info` VALUES (204, '{\"analysis\":\"补码：正数补码同原码，负数取反加 1；0.1010 -> 0101 -> 0110，得到 1.0110。\",\"correct\":\"B\",\"questionOptionList\":[{\"content\":\"原码\",\"prefix\":\"A\"},{\"content\":\"补码\",\"prefix\":\"B\"},{\"content\":\"反码\",\"prefix\":\"C\"},{\"content\":\"移码\",\"prefix\":\"D\"}],\"questionTitle\":\"若某数 x 的真值 -0.1010，在计算机中该数表示为 1.0110，则该数所用的编码方法是（         ）\"}', '2025-11-21 13:37:07');
