INSERT INTO `daming_content_info` VALUES (215, '{\"analysis\":\"绝对值过小且为负，属于负下溢。\",\"correct\":\"A\",\"questionOptionList\":[{\"content\":\"负下溢\",\"prefix\":\"A\"},{\"content\":\"正下溢\",\"prefix\":\"B\"},{\"content\":\"负上溢\",\"prefix\":\"C\"},{\"content\":\"正上溢\",\"prefix\":\"D\"}],\"questionTitle\":\"当数据超出计算机所能表示的数据范围称为溢出，浮点数表示中，数据小于计算机所能表示的最小负数时，发生（ ）。\"}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (216, '{\"correct\": \"正确\", \"analysis\": \"移码等于真值加偏移（2^(n−1)），最高位被翻转：0 对应负数范围，1 对应正数与 0。\", \"questionTitle\": \"移码的符号位中 0 表示负数，1 表示正数。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (217, '{\"correct\": \"错误\", \"analysis\": \"原码、补码都是机器数的编码，真值指实际数值，不是编码形式。\", \"questionTitle\": \"原码属于真值，补码属于机器值。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (218, '{\"correct\": \"错误\", \"analysis\": \"移码需翻转符号位（加偏移），正数移码最高位为 1，其余三种符号位 0。\", \"questionTitle\": \"正数的原码、反码、补码和移码都一样。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (219, '{\"correct\": \"正确\", \"analysis\": \"补码是模 2^n 的表示，亦称模 2 补码/位模 2 补码。\", \"questionTitle\": \"补码又称位模2的补码。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (220, '{\"correct\": \"错误\", \"analysis\": \"原码、反码有 +0/-0；补码和移码只有一个 0，且补码区间不对称。\", \"questionTitle\": \"原码、补码、反码、移码的表示区间在数轴都是对称的，都有两个0，即 +0 和 -0。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (221, '{\"correct\": \"错误\", \"analysis\": \"小数点可约定在最低位后表示整数，也可固定在数值中表示小数。\", \"questionTitle\": \"定点数表示数据的小数点位置固定，只能表示固定的小数，不能表示整数。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (222, '{\"correct\": \"正确\", \"analysis\": \"反码对正数不变，对负数符号位 1、数值位取反，故 -0 为全 1。\", \"questionTitle\": \"对于 8 位的反码，+0 的反码是 00000000；-0 的反码是 11111111。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (223, '{\"correct\": \"正确\", \"analysis\": \"移码可视为补码最高位取反（加偏移），数值位保持一致。\", \"questionTitle\": \"移码与补码只有符号位相反，数值位相同。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (224, '{\"correct\": \"正确\", \"analysis\": \"单精度阶码 8 位，偏移量 127，即移码存储。\", \"questionTitle\": \"在 IEEE 754 标准中，单精度浮点数的阶码部分是用移码表示的。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (225, '{\"correct\": \"正确\", \"analysis\": \"负数原码转补码：符号位 1 保持，数值位取反加 1；正数补码同原码。\", \"questionTitle\": \"原码变为补码的规则是符号位不变，数值位取反末尾加 1。\", \"questionOptionList\": [{\"prefix\": \"A\", \"content\": \"正确\"}, {\"prefix\": \"B\", \"content\": \"错误\"}]}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (226, '{\"analysis\":\"\",\"correct\":\"1.存储程序，程序和数据都存在内存里；2.顺序执行为主；3.计算机由五大部件组成，运算器，控制器，存储器，输入输出；4.指令和数据都采用二进制表示；5.指令由操作码和地址码组成\",\"questionOptionList\":[],\"questionTitle\":\"简述：冯诺依曼计算机的主要思想。\"}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (227, '{\"analysis\":\"\",\"correct\":\"1.硬件层；2.微程序层；3.指令集架构层；4.操作系统层；5.应用层\",\"questionOptionList\":[],\"questionTitle\":\"简述，计算机的层次结构。\"}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (228, '{\"analysis\":\"\",\"correct\":\"(1) 结果 -101100，按 5 位字长溢出；(2) 结果 +101101，按 5 位字长溢出\",\"questionOptionList\":[],\"questionTitle\":\"已知 x 和 y，用变形补码计算 x+y，同时指出结果是否溢出。（1）x=-11011，y=-10001 （2）x=+11100，y=+10001\"}', '2025-11-21 13:37:07');
INSERT INTO `daming_content_info` VALUES (229, '{\"analysis\":\"\",\"correct\":\"X=-1.01011×2^-6，Y=1.110×2^-5；对阶相加得约 1.001101×2^-4，正数，未溢出（尾数按 6 位截断/舍入）。\",\"questionOptionList\":[],\"questionTitle\":\"若 X= -43/2048, Y=14/256，设阶码 3 位，尾数 6 位（均不含符号位），阶码和尾数均采用双符号位，且都用补码表示，按浮点运算步骤计算 X+Y。\"}', '2025-11-21 13:37:07');
