INSERT INTO `daming_content_info` VALUES (258, '{\"analysis\":\"<p><strong style=\\\"color: var(--strong-color);\\\">考点：指令格式</strong></p><p><br></p><p><br></p><p><br></p><p><br></p><ul><li><strong style=\\\"color: var(--strong-color);\\\">两部分：</strong> 操作码 + 操作数</li><li><strong style=\\\"color: var(--strong-color);\\\">一句话：</strong> 操作码说明“干什么”，操作数说明“对谁干”。</li><li><strong style=\\\"color: var(--strong-color);\\\">例子：</strong> 指令 <code style=\\\"color: var(--drake-highlight);\\\">ADD R1, R2, R3</code><strong style=\\\"color: var(--strong-color);\\\">操作码：</strong> <code style=\\\"color: var(--drake-highlight);\\\">ADD</code>（执行加法操作）<strong style=\\\"color: var(--strong-color);\\\">操作数：</strong> <code style=\\\"color: var(--drake-highlight);\\\">R1, R2, R3</code>（把寄存器R2和R3的值相加，结果存到R1）</li></ul>\",\"correct\":\"操作码 + 操作数\",\"questionOptionList\":[],\"questionTitle\":\"<p><strong style=\\\"background-color: rgb(255, 255, 255); color: var(--strong-color);\\\">指令由哪两部分组成？</strong></p>\"}', '2025-11-29 16:44:42');
INSERT INTO `daming_content_info` VALUES (261, '[{\"name\":\"主观题\",\"paperQuestionVMS\":[{\"id\":160,\"itemOrder\":0}]}]', '2025-11-29 17:06:56');
INSERT INTO `daming_content_info` VALUES (262, '{\"analysis\":\"<p>计算机网络从逻辑功能上可以分为 <strong>通信子网</strong> 和 <strong>资源子网</strong> 两部分。</p><p>这是计算机网络的一种经典逻辑结构划分，通过将“传输”与“处理”分离，使得网络结构更加清晰。</p><h3>1. 通信子网 (Communication Subnet)</h3><p>通信子网负责网络中的<strong>数据传输、转发和通信控制</strong>。它由各种传输介质（如光纤、双绞线）和网络设备（如路由器、交换机、中继器）组成。</p><ul><li><strong>功能</strong>：路由选择、拥塞控制、差错校验、数据交换。</li><li><strong>对应OSI层级</strong>：主要对应下三层（物理层、数据链路层、网络层）。</li></ul><h3>2. 资源子网 (Resource Subnet)</h3><p>资源子网负责整个网络的<strong>数据处理和资源共享</strong>。它由联网的各类主机（服务器、个人电脑）、终端设备、外部设备（如打印机）以及相关的软件和数据库组成。</p><ul><li><strong>功能</strong>：提供网络资源（硬件/软件/数据资源）、进行信息处理、为用户提供访问接口。</li><li><strong>对应OSI层级</strong>：主要对应上三层（会话层、表示层、应用层），传输层则起到连接两者的桥梁作用。</li></ul><h3>核心区别总结</h3><p><strong>维度通信子网资源子网核心组成</strong>路由器、交换机、传输介质主机(Host)、服务器、终端<strong>主要任务“怎么传”</strong>（搬运数据）<strong>“传什么/怎么用”</strong>（处理数据）<strong>位置</strong>网络的内层（核心部分）网络的外层（用户边缘）</p>\",\"correct\":\"资源子网,通信子网\",\"questionOptionList\":[],\"questionTitle\":\"<p>计算机网络从逻辑上可分为____和____两部分。</p>\"}', '2026-01-02 21:19:14');
INSERT INTO `daming_content_info` VALUES (263, '[{\"name\":\"填空题\",\"paperQuestionVMS\":[{\"id\":161,\"itemOrder\":0}]}]', '2026-01-02 21:20:25');
INSERT INTO `daming_content_info` VALUES (264, '{\"analysis\":\"<h3>1. 传输介质 (Transmission Media)</h3><p>这是通信的物理通路，决定了信号能传多远、有多快。</p><p><br></p><ul><li><strong>导引型传输介质：</strong> 有具体的物理边界。</li><li class=\\\"ql-indent-1\\\"><strong>双绞线（网线）：</strong> 价格便宜，安装方便，广泛用于局域网。</li><li class=\\\"ql-indent-1\\\"><strong>同轴电缆：</strong> 抗干扰能力强，常用于有线电视。</li><li class=\\\"ql-indent-1\\\"><strong>光纤：</strong> 利用光脉冲传输，带宽极大，损耗极低，是现代骨干网的核心。</li><li><strong>非导引型传输介质：</strong> 自由空间。</li><li class=\\\"ql-indent-1\\\"><strong>无线电、微波、红外线：</strong> 用于 WiFi、蓝牙、卫星通信等。</li></ul><h3>2. 接口特性 (Interface Characteristics)</h3><p>物理层定义了连接设备时必须遵守的标准化规格，确保不同厂家生产的设备能“插得上、用得了”。</p><p><br></p><ul><li><strong>机械特性：</strong> 规定接口的形状、尺寸、引脚数量和排列方式（比如 RJ45 水晶头的样子）。</li><li><strong>电气特性：</strong> 规定引脚上的电压范围、阻抗匹配等。</li><li><strong>功能特性：</strong> 规定某条线上出现某一电平代表什么意义（例如：这条线是用来传输数据的，还是用来请求发送的）。</li><li><strong>过程特性：</strong> 规定发送比特流的时间顺序和动作序列（类似于“握手”协议的物理步骤）。</li></ul><h3>3. 信号编码 (Signal Encoding)</h3><p>计算机内部处理的是二进制数字信号，但在传输介质中，需要将其转换成适合传输的信号形式。</p><p><br></p><ul><li><strong>数字到数字（基带传输）：</strong></li><li class=\\\"ql-indent-1\\\"><strong>不归零编码 (NRZ)：</strong> 高电平代表 1，低电平代表 0。</li><li class=\\\"ql-indent-1\\\"><strong>曼彻斯特编码：</strong> 用信号中间的跳变来表示 0 或 1（例如：向上跳变是 1，向下是 0），这自带了时钟同步信号。</li><li><strong>数字到模拟（频带传输）：</strong></li><li class=\\\"ql-indent-1\\\">通过调制（ASK、FSK、PSK）将数字信号加载到模拟载波上，常见于移动通信和早期的拨号上网。</li></ul><h3>4. 同步方式 (Synchronization)</h3><p>为了确保接收方能准确识别发送方发出的每一个比特位，双方的时钟必须步调一致。</p><p><br></p><ul><li><strong>异步传输 (Asynchronous)：</strong> 以字符为单位传输。每个字符前后加上“起始位”和“停止位”。虽然简单，但开销较大（因为有很多冗余位）。</li><li><strong>同步传输 (Synchronous)：</strong> 以数据块为单位传输。发送方和接收方由同一个时钟源控制，或者从信号流中提取时钟信息。它的传输效率更高，适合高速通信。</li></ul><p><strong>介口码步</strong></p>\",\"correct\":\"传输介质,接口特性,信号编码,同步方式\",\"questionOptionList\":[],\"questionTitle\":\"<p>物理层的主要功能包括____、____、____、____</p>\",\"requireOrder\":false}', '2026-01-02 22:19:21');
INSERT INTO `daming_content_info` VALUES (265, '{\"analysis\":\"<h4>1. 封装成帧 (Framing)</h4><p>封装成帧是指在一段数据的<strong>前后分别添加首部和尾部</strong>，从而构成一个帧。</p><p><br></p><ul><li><strong>作用：</strong> 首部和尾部包含了很多控制信息（如地址、协议类型等），最重要的作用之一就是<strong>帧定界</strong>，让接收端能够从物理层收到的比特流中识别出一个帧的开始和结束。</li><li><strong>最大传送单元 (MTU)：</strong> 每种链路层协议都规定了帧的数据部分长度上限。</li></ul><h4>2. 透明传输 (Transparent Transmission)</h4><p>透明传输是指无论发送什么样的比特组合（即便数据中出现了和“帧定界符”一模一样的代码），都能够按照原样发送并正确接收。</p><p><br></p><ul><li><strong>问题所在：</strong> 如果数据中出现了与帧尾部标识符相同的字符，接收端会错误地认为帧已经结束。</li><li><strong>解决方法：</strong> * <strong>字节填充 (Byte Stuffing)：</strong> 在特殊字符前插入转义字符（如 <code>ESC</code>）。</li><li class=\\\"ql-indent-1\\\"><strong>比特填充 (Bit Stuffing)：</strong> 在特定数量的连续 <code>1</code> 之后强制插入一个 <code>0</code>（如 HDLC 协议）。</li></ul><h4>3. 差错检测 (Error Detection)</h4><p>现实中的通信链路并不是理想的，比特在传输过程中可能会产生<strong>差错</strong>（1 变成 0，或 0 变成 1）。</p><p><br></p><ul><li><strong>方法：</strong> 发送方在数据后添加<strong>检错码</strong>（如 <strong>CRC 循环冗余检验</strong>）。</li><li><strong>处理机制：</strong> 接收方收到帧后，通过 CRC 计算校验，如果发现有误，则丢弃该帧，以防错误数据交付给上层（网络层）。</li><li><br></li></ul><blockquote><strong>注意：</strong> 传统的以太网只负责“检错”而不负责“纠错”或“可靠传输”。如果需要可靠传输，通常由传输层（如 TCP）来处理。</blockquote><p><br></p>\",\"correct\":\"封装成帧,透明传输,差错检测\",\"questionOptionList\":[],\"questionTitle\":\"<p>数据链路层的三个基本问题是__,__,__</p>\",\"requireOrder\":false}', '2026-01-03 12:25:22');
INSERT INTO `daming_content_info` VALUES (266, '{\"analysis\":\"<p>IP地址（以最常用的 IPv4 为例）是一个 32 位的二进制数值。为了方便管理和路由选择，它被逻辑地划分为两个层级结构：</p><p><br></p><h4>1. 网络号 (Network ID)</h4><ul><li><strong>作用：</strong> 标识互联网中特定的一个<strong>物理网络</strong>。</li><li><strong>地位：</strong> 同一个物理网络上的所有主机和路由器的端口，其网络号必须是相同的。路由器主要根据网络号来转发数据包。</li></ul><h4>2. 主机号 (Host ID)</h4><ul><li><strong>作用：</strong> 标识该特定网络中的某一台<strong>具体主机</strong>（或接口）。</li><li><strong>地位：</strong> 在同一个网络号范围内，主机号必须是唯一的。</li></ul><h3>如何区分这两部分？</h3><p>在实际应用中，我们不能一眼看出哪部分是网络号，哪部分是主机号，这取决于<strong>子网掩码 (Subnet Mask)</strong>：</p><p><br></p><ul><li><strong>子网掩码中为 \\\"1\\\" 的位</strong>：对应 IP 地址中的网络号部分。</li><li><strong>子网掩码中为 \\\"0\\\" 的位</strong>：对应 IP 地址中的主机号部分。</li></ul><h4>示例：</h4><p>假设 IP 地址为 <code>192.168.1.10</code>，子网掩码为 <code>255.255.255.0</code>：</p><p><br></p><ul><li><strong>网络号</strong>是：<code>192.168.1</code></li><li><strong>主机号</strong>是：<code>10</code></li></ul><p>这意味着这台设备处于 <code>192.168.1.0</code> 这个网络中，它是该网络里的第 <code>10</code> 号主机。</p>\",\"correct\":\"网络标识,主机标识\",\"questionOptionList\":[],\"questionTitle\":\"<p>IP地址由__、__两部分组成。</p>\",\"requireOrder\":false}', '2026-01-03 12:34:24');
INSERT INTO `daming_content_info` VALUES (267, '{\"analysis\":\"<p>TCP 协议中，流量控制是通过<strong>滑动窗口 (Sliding Window)</strong> 机制实现的。</p><h3>详细解析</h3><p>流量控制（Flow Control）的目的是为了让<strong>发送方的发送速率不要太快</strong>，要让接收方来得及接收，防止由于接收端缓冲区溢出而导致的数据丢失。</p><p><br></p><h4>1. 工作原理：接收窗口 (rwnd)</h4><p>在 TCP 报文段的首部中，有一个 16 位的“<strong>窗口 (Window)</strong>”字段。</p><p><br></p><ul><li><strong>通知机制：</strong> 接收方在发送确认报文（ACK）时，会将自己目前的接收缓冲区剩余大小填入这个字段，告知发送方。这个值被称为<strong>接收窗口 (rwnd, receiver window)</strong>。</li><li><strong>发送限制：</strong> 发送方在发送数据时，必须保证：<strong>已发送但未收到确认的数据量 ≤ 接收方通告的窗口大小</strong>。</li></ul><h4>2. “滑动”的含义</h4><p>之所以称为“滑动窗口”，是因为随着数据的发送和确认：</p><p><br></p><ul><li>当发送方收到新的 ACK 时，窗口的左边界会向右移动（代表数据已成功交付）。</li><li>根据接收方反馈的新窗口大小，窗口的右边界也会相应调整（代表允许发送的新数据范围）。</li></ul><h4>3. 零窗口与持续计时器 (Persist Timer)</h4><p>如果接收方的缓冲区满了，它会发送一个 <code>window = 0</code> 的报文。此时发送方必须停止发送。</p><p><br></p><ul><li><strong>潜在问题：</strong> 如果之后接收方缓冲区有了空间并发送了窗口更新报文，但该报文在网络中丢失了，双方就会陷入死锁。</li><li><strong>解决方法：</strong> TCP 为每一个连接设有一个<strong>持续计时器</strong>。只要发送方收到零窗口通知，就启动计时器。若超时，发送方会发送一个极小的“<strong>零窗口探测报文</strong>”，迫使接收方再次告知当前的窗口状态。</li></ul><h3>💡 易混淆概念：流量控制 vs 拥塞控制</h3><ul><li><strong>流量控制：</strong> 是<strong>端到端</strong>的问题。解决的是“发送方发太快，接收方处理不过来”的问题。</li><li><strong>拥塞控制：</strong> 是<strong>全局性</strong>的问题。解决的是“网络中数据太多，导致路由器排队或丢包”的问题（涉及慢启动、拥塞避免等算法）。</li></ul><p><br></p>\",\"correct\":\"滑动窗口\",\"questionOptionList\":[],\"questionTitle\":\"<p>TCP 协议中，流量控制是通过__机制实现的。</p>\",\"requireOrder\":false}', '2026-01-03 12:36:40');
INSERT INTO `daming_content_info` VALUES (268, '{\"analysis\":\"<p>无</p>\",\"correct\":\"非流水线持久连接,流水线持久连接\",\"questionOptionList\":[],\"questionTitle\":\"<p>HTTP协议中，持久连接分为__、__两种方式。</p>\",\"requireOrder\":false}', '2026-01-03 12:37:19');
INSERT INTO `daming_content_info` VALUES (269, '{\"analysis\":\"<p>在网络安全中，用于验证消息完整性的技术是 <strong>散列函数 (Hash Function)</strong> 或 <strong>消息认证码 (MAC)</strong>（也可以填 <strong>数字签名</strong>）。</p><p><br></p><h3>详细解析</h3><p>完整性（Integrity）是指确保信息在传输或存储过程中<strong>未被未经授权地篡改或损坏</strong>。为了实现这一目标，通常会使用以下几种技术：</p><p><br></p><h4>1. 散列函数 (Hash Function / Cryptographic Hash)</h4><ul><li><strong>原理：</strong> 将任意长度的消息映射为固定长度的“指纹”或“摘要”（Digest）。常用的算法有 SHA-256、SM3 等。</li><li><strong>特点：</strong> 只要原始数据发生 1 比特的改变，生成的散列值就会发生巨大的变化（雪崩效应）。</li><li><strong>局限：</strong> 仅靠散列函数无法防御“中间人攻击”。如果攻击者同时修改了消息和散列值，接收者无法察觉。因此，散列值通常需要配合加密技术使用。</li></ul><h4>2. 消息认证码 (MAC, Message Authentication Code)</h4><ul><li><strong>原理：</strong> 在散列函数的基础上引入了<strong>共享密钥</strong>。发送方使用密钥对消息计算 MAC 值，接收方使用同一个密钥进行验证。</li><li><strong>作用：</strong> 它不仅能验证<strong>完整性</strong>（数据没变），还能实现<strong>身份认证</strong>（确认消息确实来自持有密钥的发送者）。</li><li><strong>常见算法：</strong> HMAC（基于哈希的消息认证码）。</li></ul><h4>3. 数字签名 (Digital Signature)</h4><ul><li><strong>原理：</strong> 结合了散列函数和<strong>非对称加密</strong>（公钥/私钥）。发送方用自己的私钥对消息摘要进行签名。</li><li><strong>作用：</strong> 除了提供<strong>完整性</strong>和<strong>身份认证</strong>，数字签名还具备<strong>不可否认性</strong>（Non-repudiation），即发送者事后无法抵赖发送过该消息。</li></ul><h3>技术对比表</h3><p><strong>技术完整性验证身份认证不可否认性核心工具散列函数</strong>✅❌❌算法 (如 SHA-256)<strong>消息认证码 (MAC)</strong>✅✅❌共享密钥 + 算法<strong>数字签名</strong>✅✅✅私钥 + 散列函数</p>\",\"correct\":\"数字签名,散列函数\",\"questionOptionList\":[],\"questionTitle\":\"<p>网络安全中，用于验证消息完整性的技术是__或__</p>\",\"requireOrder\":false}', '2026-01-03 12:40:08');
INSERT INTO `daming_content_info` VALUES (270, '{\"analysis\":\"<h3>答案详解</h3><ul><li><strong>正确答案：</strong> 指数（或 二倍、$2^n$）</li><li><strong>增长机制：</strong> 在慢启动阶段，每当发送方接收到一个确认报文段（ACK）时，拥塞窗口的大小就会加 1（以最大报文段长度 MSS 为单位）。</li><li><strong>数学规律：</strong> 假设初始窗口为 1。</li></ul><ol><li class=\\\"ql-indent-1\\\">发送 1 个报文段，收到 1 个 ACK $\\\\rightarrow$ 窗口变成 <strong>2</strong>。</li><li class=\\\"ql-indent-1\\\">发送 2 个报文段，收到 2 个 ACK $\\\\rightarrow$ 窗口变成 <strong>4</strong>。</li><li>发送 4 个报文段，收到 4 个 ACK $\\\\rightarrow$ 窗口变成 8。</li><li class=\\\"ql-indent-1\\\">以此类推，窗口大小随传输轮次（RTT）呈 $2^n$ 的指数级增长。</li></ol><h3>为什么叫“慢”启动？</h3><p>虽然它的增长速度很快（指数级），但之所以被称为“慢”启动，是因为它在连接建立之初将拥塞窗口设置为 <strong>1 个 MSS</strong>。其目的是为了探测网络的承受能力，避免在一开始就向网络注入大量数据导致拥塞。</p><h3>阶段转换：慢启动阈值 (ssthresh)</h3><p>慢启动并不会无限持续。当拥塞窗口大小达到 <strong>慢启动阈值（ssthresh）</strong> 时，TCP 就会停止指数增长，转而进入 <strong>拥塞避免（Congestion Avoidance）</strong> 阶段，此时窗口增长变为 <strong>线性增长</strong>（加性增加）。</p>\",\"analysisFormat\":\"html\",\"correct\":\"指数\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>在 TCP拥塞控制中，慢启动阶段拥塞窗口大小按__增长。</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-03 16:13:32');
INSERT INTO `daming_content_info` VALUES (271, '{\"analysis\":\"常用的多路复用技术包括 **频分复用（FDM）**、**时分复用（TDM）**、**波分复用（WDM）**。\\n\\n（注：在不同的考试或教材语境下，**码分复用（CDM）** 也常被列为四大常用技术之一。）\\n\\n* * *\\n\\n### 详细解析\\n\\n多路复用（Multiplexing）技术是为了提高传输线路的利用率，让多个用户或多个信号能够同时共享同一条物理信道。\\n\\n| 技术名称     | 英文全称 | 核心原理                                             | 典型应用               |\\n| ------------ | -------- | ---------------------------------------------------- | ---------------------- |\\n| **频分复用** | **FDM**  | 将信道带宽划分为多个子频带，每个信号占用一个频带。   | 无线广播、有线电视     |\\n| **时分复用** | **TDM**  | 将传输时间划分为等长的时隙，每个信号占用一个时隙。   | 电话网络（PCM）、GSM   |\\n| **波分复用** | **WDM**  | **光的频分复用**。在一根光纤中传输不同波长的光信号。 | 光纤骨干网             |\\n| **码分复用** | **CDM**  | 利用不同的码序列（正交码）来区分不同用户的信号。     | 3G/4G 移动通信（CDMA） |\\n\\n* * *\\n\\n### 技术特点对比\\n\\n1.  **频分复用 (FDM)**：所有信号在时间上是**并行**的，但在频率上是**隔离**的。为了防止干扰，各子信道间通常留有“保护频带”。\\n2.  **时分复用 (TDM)**：所有信号在频率上是相同的，但在时间上是**轮流**的。现代通信多使用**统计时分复用（STDM）**，它能根据需求动态分配时隙，效率更高。\\n3.  **波分复用 (WDM)**：本质上是在光通信领域应用的 FDM。\\n\\n频分复用类似短跑同时跑\\n时分复用相当于长跑在内道串行跑步\",\"analysisFormat\":\"markdown\",\"correct\":\"频分复用,时分复用,波分复用\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>常用的多路复用技术包括__、__、__。</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-03 16:19:06');
INSERT INTO `daming_content_info` VALUES (272, '{\"analysis\":\"OSI 七层模型是理论上的“标准”，而 TCP/IP 四层模型是事实上的“标准”。简而言之，TCP/IP 是对 OSI 七层模型的简化和合并。\\n\\n它们的对应关系可以用 **“上三合一，下二合一”** 来快速记忆：\\n\\n* * *\\n\\n### OSI 七层与 TCP/IP 四层对应表\\n\\n| OSI 七层模型层级               | 对应关系     | TCP/IP 四层模型层级    | 常见协议 / 硬件       |\\n| ------------------------------ | ------------ | ---------------------- | --------------------- |\\n| **7\\\\. 应用层** (Application)   | 合并为       | **1\\\\. 应用层**         | HTTP, FTP, DNS, SMTP  |\\n| **6\\\\. 表示层** (Presentation)  | $\\\\uparrow$   |                        | (处理数据格式、加密)  |\\n| **5\\\\. 会话层** (Session)       | $\\\\uparrow$   |                        | (管理会话连接)        |\\n| **4\\\\. 传输层** (Transport)     | **一一对应** | **2\\\\. 传输层**         | **TCP, UDP**          |\\n| **3\\\\. 网络层** (Network)       | **一一对应** | **3\\\\. 网络层** (IP 层) | **IP**, ICMP, ARP     |\\n| **2\\\\. 数据链路层** (Data Link) | 合并为       | **4\\\\. 网络接口层**     | 以太网、Wi-Fi、交换机 |\\n| **1\\\\. 物理层** (Physical)      | $\\\\downarrow$ | (也称网络访问层)       | 网线、集线器、比特流  |\\n\\n* * *\\n\\n### 关键点解析\\n\\n1.  **“上三层”合并：** 在 OSI 模型中，应用、表示、会话层分工明确（如加密属于表示层）。但在 TCP/IP 模型中，这些功能都统称为**应用层**。这更符合软件开发的实际情况，因为程序员在写程序时，通常会把这些逻辑都写在同一个应用进程里。\\n2.  **中间两层不变：** **传输层**和**网络层**（网际层）是互联网的核心，无论在哪个模型里都是独立且极其重要的。你可以把它们想象成网络通信的“腰部”。\\n3.  **“下两层”合并：** OSI 严格区分了**物理硬件**（物理层）和**数据链路**（如 MAC 地址、帧封装）。TCP/IP 将其合并为**网络接口层**，因为它主要关注如何将 IP 数据报发送到特定的物理网络上。\\n\\n* * *\\n\\n### 考试技巧：TCP/IP 到底几层？\\n\\n*   **四层模型**：这是最经典的（如上表）。\\n*   **五层模型**：这是教学中常用的（为了方便对比，把 TCP/IP 的底层重新拆回物理层和数据链路层）。如果考试问“五层”，通常指的是：应用层、传输层、网络层、数据链路层、物理层。\",\"analysisFormat\":\"markdown\",\"correct\":\"0SI应用层、表示展、会话层-TCP/IP应用层\\n\\n0SI传输层→ TCP/IP 传输层\\n\\n0SI网络层→ TCP/IP网络层\\n\\n0SI数据链路层、物理层 → TCP/IP 网络接口层 \",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>简述 0SI七层模型与 TCP/IP四层模型的对应关系</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-03 16:24:16');
INSERT INTO `daming_content_info` VALUES (273, '{\"analysis\":\"\\n**CSMA/CD** 的全称是 **载波监听多点接入/碰撞检测**（Carrier Sense Multiple Access with Collision Detection）。\\n\\n它是以太网中最为经典的一种协议。如果把信道比作一个房间，把数据包比作说话，它的核心逻辑就是：**“先听后说，边说边听；一旦冲突，立即停说，等待重发。”**\\n\\n* * *\\n\\n### 一、 CSMA/CD 的工作过程\\n\\n我们可以将其拆解为四个关键步骤：\\n\\n1.  **先听后说（载波监听）：** 发送数据前，节点会先检测信道上是否有信号在传输。\\n    *   若信道**忙**：继续等待，直到信道空闲。\\n    *   若信道**闲**：等待一个极短的时间（帧间最小间隔）后，开始发送数据。\\n2.  **边说边听（碰撞检测）：** 节点在发送数据帧的过程中，会持续监测信道电压。\\n    *   由于电信号在导线上传播需要时间，可能会出现两个节点同时检测到“空闲”并同时发报的情况，导致信号重叠，即\\\\*\\\\*“碰撞（冲突）”\\\\*\\\\*。\\n3.  **冲突停说（强化告知）：** 一旦检测到碰撞，节点立即停止发送该数据帧，并发送一个 **人为干扰信号（Jamming Signal）**。\\n    *   目的是让网络上所有节点都知道发生了冲突，让大家一起停止发送。\\n4.  **随机重发（二进制指数退避）：** 为了避免两个节点在停止后又同时尝试重发，它们会执行“退避算法”。\\n    *   每个节点随机等待一段时间，再回到第一步重新尝试。等待的时间通常采用 **二进制指数退避算法**。\\n简单来说，**共享式以太网（Shared Ethernet）** 就像是\\\\*\\\\*“一群人在同一个房间里用同一个麦克风说话”\\\\*\\\\*。\\n\\n它是早期局域网的主流组网方式，以下是它的详细定义和特点：\\n\\n### 1\\\\. 核心定义\\n\\n在共享式以太网中，所有的计算机都连接到**同一根传输介质**（如早期的同轴电缆）或同一个\\\\*\\\\*集线器（Hub）\\\\*\\\\*上。\\n\\n*   **共享带宽**：如果网络总带宽是 10Mbps，有 10 台电脑，那么这 10 台电脑要平分这 10Mbps。\\n*   **单一冲突域**：在同一时刻，**只能有一台**电脑发送数据。如果两台电脑同时说话，信号就会在电缆里“撞车”（冲突），导致谁也听不清。\\n\\n### 2\\\\. 硬件标志：集线器（Hub）\\n\\n如果你看到网络连接的核心设备是 **集线器（Hub）** 而不是 **交换机（Switch）**，那么这个网络就是共享式以太网。\\n\\n*   集线器是个“傻瓜”设备：它收到一个数据包后，会盲目地广播给所有端口，不管是不是发给你的，你都会收到。\\n\\n### 3\\\\. 为什么它需要 CSMA/CD？\\n\\n正因为大家都在抢同一个通道，所以必须有一套规则来维持秩序。这就是你前面问到的 **CSMA/CD**：\\n\\n*   **先听再讲**：看看有没有人在用线。\\n*   **边听边讲**：一旦发现别人也在讲（冲突），立刻闭嘴。\\n\\n*   * *\\n\\n### 4\\\\. 共享式 vs. 交换式（现代网络）\\n\\n为了让你更清楚，我们对比一下现在的网络：\\n\\n| 特性         | 共享式以太网 (老旧)        | 交换式以太网 (现代)          |\\n| ------------ | -------------------------- | ---------------------------- |\\n| **核心设备** | **集线器 (Hub)**           | **交换机 (Switch)**          |\\n| **通信方式** | 半双工（不能同时收发）     | 全双工（可以同时收发）       |\\n| **带宽分配** | 所有人共享总带宽           | 每个接口独享带宽             |\\n| **冲突风险** | 经常碰撞，需要 CSMA/CD     | **无碰撞**，不再需要 CSMA/CD |\\n| **形象比喻** | 像单车道，对面来车得停下等 | 像双向多车道，各走各的       |\\n\\n### 总结\\n\\n**共享式以太网**就是指那些使用**集线器**连接、所有设备处于**同一个冲突域**、必须依靠 **CSMA/CD** 协议来协调数据发送的有线局域网。\\n\\n虽然现在家庭和办公室基本都换成了交换机（交换式以太网），但在计算机网络的考试和教材中，它仍然是理解网络基础逻辑（如碰撞检测）的核心场景。\",\"analysisFormat\":\"markdown\",\"correct\":\"工作过程:先听后发、边发边听、冲突停止、随机重发。\\n适用场景:共享式以太网(有线局域网) \",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>说明 CSMA/CD协议的工作过程及其适用场景。</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-03 16:36:31');
INSERT INTO `daming_content_info` VALUES (274, '{\"analysis\":\"### TCP 与 UDP 的主要区别\\n\\n| 维度         | TCP (传输控制协议)                                           | UDP (用户数据报协议)                                         |\\n| ------------ | ------------------------------------------------------------ | ------------------------------------------------------------ |\\n| **连接性**   | **面向连接**：传输数据前必须先建立连接（三次握手）。         | **无连接**：发送数据前不需要建立连接，直接发送。             |\\n| **可靠性**   | **可靠**：通过确认和重传机制保证数据无差错、不丢失、不重复且按序到达。 | **不可靠**：只尽力交付，不保证数据能够准确到达目的地。       |\\n| **控制机制** | **有流量控制和拥塞控制**：能够根据网络状态自动调节发送速度，防止网络拥塞。 | **没有**：不进行任何拥塞控制或流量调节。                     |\\n| **传输模式** | **面向字节流**：将数据看作无结构的字节流，可能对应用层报文进行拆分或合并。 | **面向报文**：完整保留应用层报文的边界，不拆分也不合并。     |\\n| **首部开销** | **首部较大**：标准头部为 **20 字节**，因为需要包含序列号、确认号等复杂控制信息。 | **首部较小**：头部固定为 **8 字节**，仅包含最基本的端口信息和校验和。 |\\n\\n* * *\\n\\n### 总结记忆\\n\\n*   **TCP** 追求的是“稳”：适用于文件传输（FTP）、网页浏览（HTTP）和邮件等严谨场景。\\n*   **UDP** 追求的是“快”：适用于视频会议、直播、语音通话和在线游戏等对实时性要求高的场景。\",\"analysisFormat\":\"markdown\",\"correct\":\"TCP 面向连接，UDP 无连接；\\nTCP 可靠，UDP 不可靠；\\nTCP 有流量控制和拥塞控制，UDP 没有；\\nTCP 面向字节流，UDP 面向报文；\\nTCP 首部较大（20 字节），UDP 首部较小（8 字节）。\\n\\n连接可靠控制面向首部——————联考面孔瘦\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>简述 TCP与 UDP的主要区别。</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-03 17:45:19');
INSERT INTO `daming_content_info` VALUES (275, '{\"analysis\":\"### 1\\\\. 递归查询 (Recursive Query)\\n\\n*   **定义**：客户端向本地 DNS 服务器发出请求后，本地 DNS 服务器负责“包办到底”。\\n*   **过程**：如果本地 DNS 没有缓存该记录，它会替客户端去向其他服务器查询，直到找到最终结果并返回给客户端。\\n*   **特点**：对于客户端来说，只需发送**一次请求**，然后静候结果即可。\\n*   **形象比喻**：**“甩手掌柜”**。你把问题丢给秘书，秘书跑遍所有部门，最后直接把答案告诉你。\\n\\n*   * *\\n\\n### 2\\\\. 迭代查询 (Iterative Query)\\n\\n*   **定义**：本地 DNS 向其他服务器查询时，对方并不直接给出答案，而是给出“线索”。\\n*   **过程**：\\n    1.  本地 DNS 向根域名服务器查询。\\n    2.  根服务器返回下一级服务器的地址（如顶级域名服务器）。\\n    3.  本地 DNS 再根据这个地址向下一级查询，如此反复，依次迭代。\\n*   **特点**：本地 DNS 需要发送**多次请求**，不断从上一级获取下一级的“引荐”。\\n*   **形象比喻**：**“按图索骥”**。你去问领导，领导说：“我不知道，但你可以去问张三”；你再去问张三，张三说：“去问李四”。你得自己一步步找下去。\\n\\n*   * *\\n\\n### 3\\\\. 核心区别对比表\\n\\n| 特性           | 递归查询                                | 迭代查询                                          |\\n| -------------- | --------------------------------------- | ------------------------------------------------- |\\n| **查询者压力** | **大**（需负责跑完全程并返回结果）      | **小**（只负责提供下一跳的指引）                  |\\n| **反馈内容**   | **最终结果**（IP 地址或报错）           | **参考信息**（下一级服务器的地址）                |\\n| **常用场景**   | **客户端  $\\\\leftrightarrow$  本地 DNS** | **本地 DNS  $\\\\leftrightarrow$  根/顶级/权威 DNS** |\",\"analysisFormat\":\"markdown\",\"correct\":\"递归查询：客户端向本地 DNS 发出请求，本地 DNS 负责逐级查询并返回最终结果；\\n\\n迭代查询：本地 DNS 向根域名服务器查询，根返回下一级服务器地址，本地 DNS 再向下一级查询，依次迭代。\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>说明 DNS 的递归查询与选代查询的区别。</p><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-03 17:50:54');
INSERT INTO `daming_content_info` VALUES (276, '{\"analysis\":\"### **路由转发详情表**\\n\\n| 序号  | 目的 IP 地址  | 转发接口 | 理由                                                         |\\n| ----- | ------------- | -------- | ------------------------------------------------------------ |\\n| **1** | 192.168.1.35  | E0       | 目的 IP 与路由表第一条（192.168.1.0/24）匹配，为直接交付，接口为 E0。 |\\n| **2** | 192.168.2.100 | E0       | 目的 IP 与路由表第二条（192.168.2.0/24）匹配，下一跳为 192.168.1.2，通过 E0 接口转发。 |\\n| **3** | 10.1.2.3      | S0       | 目的 IP 与路由表第三条（10.0.0.0/8）匹配，下一跳为 10.0.0.1，接口为 S0。 |\\n| **4** | 172.16.1.1    | S1       | 目的 IP 与前三条路由均不匹配，使用默认路由（0.0.0.0/0），下一跳为 202.120.10.1，接口为 S1。 |\\n| **5** | 8.8.8.8       | S1       | 目的 IP 与前三条路由均不匹配，使用默认路由，下一跳为 202.120.10.1，接口为 S1。 |\\n\\n* * *\\n\\n### **核心概念解析**\\n\\n为了帮助你更好地理解这个表格，这里有几个关键点：\\n\\n*   **直接交付 (Direct Delivery)：** 如序号 1 所示，目的地就在路由器直接连接的网段内。\\n*   **下一跳 (Next Hop)：** 如序号 2 和 3 所示，数据包需要发送给路径上的下一个路由器 IP 地址。\\n*   **默认路由 (Default Route)：** 如序号 4 和 5 所示，当路由表中没有具体的匹配项时，数据包会发送到默认网关（0.0.0.0/0）。\",\"analysisFormat\":\"markdown\",\"correct\":\"占位符\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\" 某路由器 R1 的路由表如下：\\n\\n| 目的网络    | 子网掩码      | 下一跳       | 接口 |\\n| ----------- | ------------- | ------------ | ---- |\\n| 192.168.1.0 | 255.255.255.0 | 直接交付     | E0   |\\n| 192.168.2.0 | 255.255.255.0 | 192.168.1.2  | E0   |\\n| 10.0.0.0    | 255.0.0.0     | 10.0.0.1     | S0   |\\n| 0.0.0.0     | 0.0.0.0       | 202.120.10.1 | S1   |\\n\\n**任务：** 现路由器 R1 收到以下目的 IP 地址的数据包，请判断每个数据包应从哪个接口转发，并说明理由。\\n\\n1.  目的 IP：192.168.1.35\\n2.  目的 IP：192.168.2.100\\n3.  目的 IP：10.1.2.3\\n4.  目的 IP：172.16.1.1\\n5.  目的 IP：8.8.8.8\",\"questionTitleFormat\":\"markdown\"}', '2026-01-03 17:56:49');
INSERT INTO `daming_content_info` VALUES (277, '{\"analysis\":\"在计算机网络中，这四个指标是衡量网络“好坏”的核心维度。我们可以把网络想象成一条**高速公路**，通过这个类比来深入理解这些概念：\\n\\n* * *\\n\\n1\\\\. 带宽 (Bandwidth)\\n------------------\\n\\n带宽通常指网络的**通信能力**，即单位时间内从网络中的某一点到另一点所能通过的“最高数据率”。\\n\\n*   **定义：** 信号传输的频带宽度（物理层）或单位时间内传输的数据量（应用层）。单位通常是 **bps** (bits per second)。\\n*   **类比：** 相当于高速公路的**车道数**。带宽越大，意味着路越宽，理论上每秒能容纳的车辆（数据）就越多。\\n*   **注意：** 带宽反映的是“潜力”，并不代表实际传输速度。\\n\\n2\\\\. 时延 (Delay / Latency)\\n------------------------\\n\\n时延是指数据（报文或分组）从网络的一端传送到另一端所需的时间。\\n\\n* **组成部分：** 1. **发送时延：** 主机将数据帧推向传输线路的时间。 2. **传播时延：** 电磁波在介质（光纤、铜线）中传播所需的时间。 3. **处理时延：** 路由器交换机解析首部、提取数据的时间。 4. **排队时延：** 数据包在路由器缓存中等待转发的时间。\\n\\n* **类比：** 相当于一辆车从起点收费站到终点收费站所花费的**总时间**。\\n\\n* **公式：**\\n  $$\\n  总时延=时延_{发送}+时延_{传播}+时延_{处理}+时延_{排队}\\n  $$\\n\\n* * *\\n\\n3\\\\. 吞吐率 (Throughput)\\n--------------------\\n\\n吞吐率是指在**实际状态下**，单位时间内通过某个网络（或信道、接口）的数据量。\\n\\n*   **定义：** 它是网络性能的真实体现。\\n*   **与带宽的区别：** 带宽是“最大理论值”，而吞吐率是“实际测得值”。吞吐率往往受到带宽、网络拥塞、硬件性能等多种因素的限制。\\n*   **类比：** 即使高速公路有 8 车道（高带宽），但如果前方出事故导致堵车，或者路面有大雾，实际每秒通过的车辆数（吞吐率）就会远低于理论值。\\n\\n4\\\\. 丢包率 (Packet Loss Rate)\\n--------------------------\\n\\n丢包率是指在传输过程中，丢失的数据包数量占总发送数据包数量的比率。\\n\\n*   **原因：** 主要是**网络拥塞**（路由器缓冲区满了，后续来的包只能被扔掉）或**信号干扰**导致的比特错误。\\n*   **类比：** 在运输过程中，因为路太堵或路况太差，导致一部分货车半路抛锚或走错路，没能到达目的地。\\n*   **影响：** 丢包率高会导致数据重传，进而显著增加时延，严重降低用户体验（如视频卡顿、游戏瞬移）。\\n\\n*   * *\\n\\n### 核心指标对比表\\n\\n| 指标       | 关注点   | 理想状态        |\\n| ---------- | -------- | --------------- |\\n| **带宽**   | 理论上限 | 越高越好        |\\n| **时延**   | 响应速度 | 越低越好        |\\n| **吞吐率** | 实际表现 | 越接近带宽越好  |\\n| **丢包率** | 可靠性   | 越趋近于 0 越好 |\\n\\n* * *\\n\\n这些指标之间是相互影响的。例如，当**吞吐率**试图超过**带宽**时，会导致路由器排队加剧，从而增加**时延**，最终引发严重拥塞导致**丢包率**上升。\",\"analysisFormat\":\"markdown\",\"correct\":\"带宽,时延,吞吐量,丢包率\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>计算机网络的性能指标包括 </p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:09:51');
INSERT INTO `daming_content_info` VALUES (278, '{\"analysis\":\"### 1\\\\. 单工 (Simplex)\\n\\n数据只能沿**一个固定方向**传输，任何时候都不能改变方向。\\n\\n*   **特点：** 只有一端能发送数据，另一端只能接收。\\n*   **类比：** 广播电台或电视转播，观众只能收听或收看，不能通过同一频道向电台喊话。\\n*   **典型例子：** 键盘输入到主机、监视器显示输出、传统无线电广播。\\n\\n### 2\\\\. 半双工 (Half-Duplex)\\n\\n数据可以**双向传输**，但**不能同时进行**。在同一时刻，只能有一方发送，另一方接收。\\n\\n*   **特点：** 它可以实现双向通信，但需要切换“发送”和“接收”状态，效率比全双工低。\\n*   **类比：** 窄到只能通过一辆车的单行道。如果对面有车来，你必须停下来等它过去，你才能走。\\n*   **典型例子：** 对讲机（说话时按住按钮，此时不能听；放开按钮才能听）、传统的以太网（使用CSMA/CD协议）。\\n\\n### 3\\\\. 全双工 (Full-Duplex)\\n\\n数据可以**同时进行双向传输**。\\n\\n*   **特点：** 通信双方都有独立的发送和接收能力，允许两端在同一时间内既发又收，传输效率最高。\\n*   **类比：** 宽阔的双向高速公路，两个方向的车流互不干扰。\\n*   **典型例子：** 现代电话通话（双方可以同时说话且都能听到）、现代交换式以太网、光纤通信。\\n\\n*   * *\\n\\n### 传输方式对比表\\n\\n| 方式       | 方向性       | 同时收发 | 效率 |\\n| ---------- | ------------ | -------- | ---- |\\n| **单工**   | 单向         | 否       | 最低 |\\n| **半双工** | 双向（交替） | 否       | 中等 |\\n| **全双工** | 双向（同步） | **是**   | 最高 |\",\"analysisFormat\":\"markdown\",\"correct\":\"单工,半双工,全双工\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>数据通信系统中，三种传输方式为__,__,__</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:11:24');
INSERT INTO `daming_content_info` VALUES (279, '{\"analysis\":\"### 1\\\\. 为什么是 64 字节？\\n\\n这个限制主要源于早期的以太网标准，特别是为了配合 **CSMA/CD**（载波监听多路访问/冲突检测）协议的工作。\\n\\n*   **冲突检测的需求：** 在半双工时代，为了确保发送方能够检测到链路上发生的任何冲突，发送方必须在“最远冲突信号返回”之前仍在发送数据。\\n*   **争用期 (Slot Time)：** 以太网规定了争用期为  $51.2\\\\mu s$ 。在 10 Mbps 的速率下， $51.2\\\\mu s$  恰好能传输  $512$  个比特，即 **64 字节**。\\n*   **结论：** 如果帧长度小于 64 字节，发送方可能在检测到冲突之前就已经把数据发完了，从而无法启动重传机制。\\n\\n### 2\\\\. 64 字节是如何构成的？\\n\\n一个标准的以太网帧（Ethernet II）结构如下：\\n\\n| 组成部分           | 长度 (字节)   | 说明                   |\\n| ------------------ | ------------- | ---------------------- |\\n| 目的 MAC 地址      | 6             | 接收方的物理地址       |\\n| 源 MAC 地址        | 6             | 发送方的物理地址       |\\n| 类型 (Type)        | 2             | 标识上层协议 (如 IPv4) |\\n| **数据 (Payload)** | **46 ~ 1500** | **最小必须为 46 字节** |\\n| 帧校验序列 (FCS)   | 4             | 用于差错检测           |\\n| **总计**           | **64**        | **最小帧长限制**       |\\n\\n> **注意：** 物理层的前导码（Preamble, 8 字节）通常不计入这 64 字节的长度内。\\n\\n### 3\\\\. 如果数据不够 46 字节怎么办？\\n\\n如果上层交付的数据（如简单的 ARP 请求）不足 46 字节，网络适配器会在数据字段后自动填充 **填充字节 (Padding)**，通常补 0，直到帧的总长度达到 64 字节。\",\"analysisFormat\":\"markdown\",\"correct\":\"64\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>以太网帧的最小长度为__字节</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:21:38');
INSERT INTO `daming_content_info` VALUES (280, '{\"analysis\":\"<h3>1. 按作用范围划分（最主流划分）</h3><p>路由选择协议分为 <strong>内部网关协议 (IGP)</strong> 和 <strong>外部网关协议 (EGP)</strong> 两大类。</p><p><br></p><p><br></p><p><br></p><p><br></p><ul><li><strong>内部网关协议 (IGP, Interior Gateway Protocol)：</strong></li><li class=\\\"ql-indent-1\\\"><strong>定义：</strong> 在一个<strong>自治系统 (AS)</strong> 内部使用的路由选择协议。</li><li class=\\\"ql-indent-1\\\"><strong>目标：</strong> 寻找自治系统内部的最短路径，注重效率和收敛速度。</li><li class=\\\"ql-indent-1\\\"><strong>常见协议：</strong> <strong>OSPF</strong>（开放最短路径优先）、<strong>RIP</strong>（路由信息协议）、<strong>IS-IS</strong>、<strong>EIGRP</strong>。</li><li><strong>外部网关协议 (EGP, Exterior Gateway Protocol)：</strong></li><li class=\\\"ql-indent-1\\\"><strong>定义：</strong> 在不同的<strong>自治系统 (AS)</strong> 之间交换路由信息的协议。</li><li class=\\\"ql-indent-1\\\"><strong>目标：</strong> 寻找路径的可达性，并执行各种策略控制（Policy），注重稳定性和控制力。</li><li class=\\\"ql-indent-1\\\"><strong>常见协议：</strong> <strong>BGP</strong>（边界网关协议），它是目前互联网事实上的标准。</li></ul><h3>2. 按算法（工作原理）划分</h3><p>如果你是在考试中遇到此题，有时也可能指以下两类：</p><p><br></p><p><br></p><p><br></p><p><br></p><ul><li><strong>距离矢量路由协议 (Distance Vector)：</strong> 路由器只知道到目的地的距离（如跳数）和方向（下一跳），代表协议是 <strong>RIP</strong>。</li><li><strong>链路状态路由协议 (Link State)：</strong> 路由器掌握全网的拓扑结构图，通过 SPF 算法计算最优路径，代表协议是 <strong>OSPF</strong>。</li></ul><h3>3. 按配置方式划分</h3><ul><li><strong>静态路由 (Static Routing)：</strong> 由网络管理员手动配置，适合小型、简单的网络。</li><li><strong>动态路由 (Dynamic Routing)：</strong> 路由器通过协议自动学习和更新路由表，适合大型、复杂的网络。</li></ul>\",\"analysisFormat\":\"html\",\"correct\":\"内部网关协议,外部网关协议\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>路由选择协议分为__,__两大类</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:22:51');
INSERT INTO `daming_content_info` VALUES (281, '{\"analysis\":\"<h3>1. 慢启动 (Slow Start)</h3><ul><li><strong>原理：</strong> 当主机开始发送数据时，并不清楚网络的负荷情况。为了避免一上来就造成拥塞，由小到大逐渐增大<strong>拥塞窗口 (cwnd)</strong>。</li><li><strong>增长方式：</strong> 通常从 1 个最大报文段 (MSS) 开始，每收到一个确认报文 (ACK)，窗口值就加 1。这使得拥塞窗口呈<strong>指数级增长</strong>。</li><li><strong>停止时机：</strong> 当 <code>cwnd</code> 达到“慢开始门限” (<code>ssthresh</code>) 时，停止使用慢开始，转而执行拥塞避免算法。</li></ul><h3>2. 拥塞避免 (Congestion Avoidance)</h3><ul><li><strong>原理：</strong> 当窗口达到门限值后，为了防止增长过快导致拥塞，让窗口增长变得“缓慢”一些。</li><li><strong>增长方式：</strong> 每经过一个往返时间 (RTT)，拥塞窗口 <code>cwnd</code> 仅增加 1。这使得窗口呈<strong>线性增长</strong>（也称为“加性增”）。</li><li><strong>触发调整：</strong> 一旦发现网络出现拥塞（如出现超时），就将 <code>ssthresh</code> 减半，并将 <code>cwnd</code> 重置为 1，重新开始慢开始。</li></ul><h3>3. 快速重传 (Fast Retransmit)</h3><ul><li><strong>原理：</strong> 要求接收方在收到一个失序的报文段后立即发送重复确认，使发送方尽早知道有报文段丢失。</li><li><strong>触发机制：</strong> 发送方只要一连收到 <strong>3 个重复确认</strong>，就立即重传对方尚未收到的报文段，而不必等待该报文段的重传计时器超时。</li></ul><h3>4. 快速恢复 (Fast Recovery)</h3><ul><li><strong>原理：</strong> 配合快重传使用。当发送方连续收到 3 个重复确认时，由于发送方认为现在只是丢了少数字段，网络并没有发生严重拥塞。</li><li><strong>动作：</strong> 发送方将慢开始门限 <code>ssthresh</code> 和拥塞窗口 <code>cwnd</code> 均设置为当前窗口的一半，然后直接开始执行<strong>拥塞避免算法</strong>（即线性增长），从而跳过了将窗口降为 1 的“慢开始”阶段。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"慢启动,拥塞避免,快速重传,快速恢复\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>TCP 协议中，拥塞控制包括__,__,__,__</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:27:07');
