INSERT INTO `daming_content_info` VALUES (283, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"密码,生物特征,数字证书\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>网络安全中，用于身份认证的常见方式有__,__,__</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:28:30');
INSERT INTO `daming_content_info` VALUES (284, '{\"analysis\":\"<p>VLAN（虚拟局域网）的划分方式多种多样，根据不同的网络需求，常见的划分方式包括以下三种：</p><p><br></p><h3>1. 基于端口划分 (Port-based VLAN)</h3><p>这是<strong>最常用、最直接</strong>的划分方式。</p><p><br></p><ul><li><strong>方法：</strong> 网络管理员手动指定交换机的特定端口属于哪个 VLAN。</li><li><strong>优点：</strong> 配置简单，安全性较高（物理隔离）。</li><li><strong>缺点：</strong> 灵活性差。如果用户移动到另一个办公室（插入了不同的交换机端口），管理员必须重新配置 VLAN。</li><li><strong>类比：</strong> 给办公室的每个插座贴上标签，插在 1 号插座的只能去 A 区，插在 2 号的只能去 B 区。</li></ul><h3>2. 基于 MAC 地址划分 (MAC-based VLAN)</h3><p>这是一种<strong>动态划分</strong>方式。</p><p><br></p><ul><li><strong>方法：</strong> 交换机根据连接设备的 MAC 地址（网卡的唯一硬件标识）来决定其属于哪个 VLAN。</li><li><strong>优点：</strong> 灵活性极高。无论用户拿着电脑插在交换机的哪个端口，其 VLAN 身份保持不变。</li><li><strong>缺点：</strong> 初始配置工作量大。管理员需要手动录入所有终端设备的 MAC 地址。</li><li><strong>类比：</strong> 进门不看你坐哪，而是看你的“身份证号”，无论你坐在哪个工位，你的权限都是固定的。</li></ul><h3>3. 基于协议划分 (Protocol-based VLAN)</h3><ul><li><strong>方法：</strong> 根据数据包所属的网络层协议（如 IPv4、IPv6、IPX 等）来划分 VLAN。</li><li><strong>优点：</strong> 能够将运行不同协议的用户自动隔离开，方便管理不同类型的业务流。</li><li><strong>类比：</strong> 按照“语种”分群，说英语的去 A 区，说中文的去 B 区，互不干扰。</li></ul><h3>补充划分方式（进阶分类）</h3><p>除了上述三种，在复杂的网络环境中还包括：</p><p><br></p><ul><li><strong>基于子网划分 (IP Subnet-based)：</strong> 根据数据包的源 IP 地址段划分。</li><li><strong>基于策略划分 (Policy-based)：</strong> 根据用户、端口、MAC 地址等多种条件的组合进行复杂逻辑划分。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"基于端口,基于mac地址,基于IP子网\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>VLAN的划分方式包括__,__,__</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 10:54:35');
INSERT INTO `daming_content_info` VALUES (285, '{\"analysis\":\"在计算机网络中，**电路交换**与**分组交换**（也称包交换）是两种最基础的数据交换技术。以下是它们的简要对比：\\n\\n### 1\\\\. 电路交换 (Circuit Switching)\\n\\n在通信前，必须先在发送端和接收端之间建立一条**专用的物理通路**。\\n\\n*   **特点：** 独占资源、顺序传输。\\n*   **优点：** \\\\* **低延迟、抖动小：** 一旦建立连接，数据几乎无延迟传输。\\n    *   **带宽保证：** 专用带宽，通信质量有保障，适合语音通话。\\n*   **缺点：** \\\\* **利用率低：** 即使不发数据，通路也一直被占用，造成浪费。\\n    *   **建立连接慢：** 通话前需要漫长的“呼叫建立”过程。\\n\\n### 2\\\\. 分组交换 (Packet Switching)\\n\\n将数据拆分成一个个短小的“分组”（Packet），每个分组独立选择路由进行**存储转发**。\\n\\n*   **特点：** 动态分配资源、逐段转发。\\n*   **优点：** \\\\* **高效：** 多个用户可以共享同一条链路，带宽利用率极高。\\n    *   **灵活：** 无需预先建立连接，若某段路径故障，分组可绕行。\\n*   **缺点：** \\\\* **延迟与排队：** 每个节点处理分组会产生排队时延。\\n    *   **可能丢包：** 网络拥塞时可能发生丢包或乱序。\\n\\n*   * *\\n\\n### 核心区别对比表\\n\\n| 特性         | 电路交换 (如: 传统电话) | 分组交换 (如: 互联网/IP) |\\n| ------------ | ----------------------- | ------------------------ |\\n| **路径**     | 固定、独占专用路径      | 动态、共享公共路径       |\\n| **连接建立** | 必须预先建立 (呼叫阶段) | 无需预先建立             |\\n| **资源利用** | 低 (空闲时也占用)       | 高 (按需分配)            |\\n| **主要应用** | 实时语音、模拟通信      | 数据通信、互联网业务     |\",\"analysisFormat\":\"markdown\",\"correct\":\"区别：电路交互要建立连接，独占资源，分组交换是存储转发的，共享资源\\n优缺点：电路交换实时性强，适合实时通信，不过建立连接后占用的通道即使不传输数据其他人也无法使用，通路一直占用，效率低，利用率低\\n分组交换适合突发情况，不需要建立连接和用完的断开连接的善后操作，效率高，不过可能出现拥塞和延迟\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>简述分组交换与电路交换的区别及优缺点</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-05 11:03:22');
INSERT INTO `daming_content_info` VALUES (286, '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"arp——address resolution protocol，地址解析协议，将IP地址解析为mac地址\\n工作过程：广播arp请求，目标主机响应arp请求，缓存arp表项\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>说明 ARP 协议的作用及其工作过程。</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-05 11:06:01');
INSERT INTO `daming_content_info` VALUES (287, '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"nat——network address translation  网络地址转换\\n将内网ip转为公网ip，有静态nat，动态nat，和pat端口地址转换\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>什么是NAT,简述其工作原理及类型</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-05 11:08:12');
INSERT INTO `daming_content_info` VALUES (288, '{\"analysis\":\"### HTTP GET 与 POST 的核心区别\\n\\n| 特性          | **GET**                                        | **POST**                             |\\n| ------------- | ---------------------------------------------- | ------------------------------------ |\\n| **数据位置**  | 参数存放在 **URL**（Query String）中           | 数据存放在 **请求体 (Body)** 中      |\\n| **安全性**    | **较低**（数据在地址栏可见，会被记录）         | **较高**（数据不可见，适合敏感信息） |\\n| **数据长度**  | 受限（通常浏览器限制在 2KB 左右）              | **无限制**（适合上传大数据）         |\\n| **幂等性**    | **幂等**（多次执行结果相同，不改动服务器数据） | **非幂等**（通常用于创建/修改数据）  |\\n| **缓存/书签** | 可被缓存、可收藏为书签                         | **不可被缓存**、不可收藏为书签       |\\n\\n* * *\\n\\n### 形象理解\\n\\n*   **GET**：就像寄一张**明信片**，内容写在背面，所有人（路由器、日志等）都能直接看到，空间有限。\\n*   **POST**：就像寄一个**信封**，内容密封在里面，更安全且能装更多东西（如文件）。\",\"analysisFormat\":\"markdown\",\"correct\":\"1.get方法从服务器获取资源，post方法从服务器提交数据\\n2.get具有幂等性，post不具有幂等性\\n3.get参数在url里，post参数在请求体里\\n4.get可以缓存，post不可缓存\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>简述HTTP 协议中GET与POST 方法的区别。</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-05 11:11:19');
INSERT INTO `daming_content_info` VALUES (289, '{\"analysis\":\"防火墙是网络安全的第一道防线，它像是一个**数字哨兵**，部署在不同网络安全域之间（如企业内网和互联网），根据规则对进出的流量进行审查。\\n\\n以下是针对你提到的基本功能和分类进行的详细解析：\\n\\n* * *\\n\\n一、 基本功能解析\\n---------\\n\\n### 1\\\\. 访问控制 (Access Control)\\n\\n*   **解析：** 这是防火墙最核心的功能。它通过一套**规则集**（白名单或黑名单），决定哪些流量可以进入网络，哪些必须被拦截。\\n*   **类比：** 就像大楼门口的保安，只允许持有工牌（符合特定 IP 或端口）的人进入。\\n\\n### 2\\\\. 日志记录 (Logging)\\n\\n*   **解析：** 记录所有通过或被拒绝的流量详情。这对于**安全审计**和**事后追溯**至关重要。\\n*   **作用：** 如果网络遭到攻击，管理员可以通过查看日志发现攻击者的来源、攻击时间及手段。\\n\\n### 3\\\\. 网络地址转换 (NAT)\\n\\n*   **解析：** 将内网使用的私有 IP 地址转换为公有 IP 地址后再发送到互联网，隐藏内网真实拓扑。\\n*   **作用：** 既解决了公网 IP 不足的问题，又提高了安全性，因为外部黑客很难直接定位到内网的具体主机。\\n\\n### 4\\\\. 入侵检测 (Intrusion Detection)\\n\\n*   **解析：** 现代防火墙（如下一代防火墙 NGFW）通常集成此功能。它不仅看“谁”在发数据，还看数据里“装了什么”，通过匹配特征码来发现潜在的木马或攻击行为。\\n\\n*   * *\\n\\n二、 分类解析\\n-------\\n\\n### 1\\\\. 包过滤防火墙 (Packet Filtering Firewall)\\n\\n*   **原理：** 工作在 **OSI 网络层**。它只检查数据包的报头（源/目的 IP、端口号、协议类型），不看数据内容。\\n*   **优点：** 速度快、性能开销小。\\n*   **缺点：** 无法防范隐藏在合法协议中的应用层攻击（如 SQL 注入）。\\n*   **地位：** 第一代防火墙技术。\\n\\n### 2\\\\. 状态检测防火墙 (Stateful Inspection Firewall)\\n\\n*   **原理：** 工作在 **网络层和传输层**。它不仅检查报头，还会跟踪一个连接的“状态”（如是否经过了三次握手）。如果一个回来的包没有对应的“发起申请”，就会被拦截。\\n*   **优点：** 安全性高于包过滤，且比应用网关效率高。\\n*   **地位：** 目前工业界应用最广泛的防火墙技术。\\n\\n### 3\\\\. 应用网关防火墙 (Application Gateway Firewall)\\n\\n*   **原理：** 工作在 **应用层**。它像一个“中转代理”，会拆开数据包去看具体的应用协议内容（如 HTTP、FTP 的指令）。\\n*   **优点：** 能够进行深度的内容检查，安全性最高。\\n*   **缺点：** 处理速度最慢，因为每一层都要解包检查，容易成为网络瓶颈。\\n\\n*   * *\\n\\n### 对比总结\\n\\n| 类型         | 工作层次          | 安全等级 | 性能速度 |\\n| ------------ | ----------------- | -------- | -------- |\\n| **包过滤**   | 网络层 (IP)       | 低       | 极快     |\\n| **状态检测** | 传输层 (TCP/UDP)  | 中       | 很快     |\\n| **应用网关** | 应用层 (HTTP/FTP) | 高       | 较慢     |\",\"analysisFormat\":\"markdown\",\"correct\":\"基本功能有，访问控制，日志记录，网络地址转换，入侵检测\\n分类有包过滤防火墙，状态检测防火墙，应用网关防火墙\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>说明防火墙的基本功能及其分类。</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-05 11:39:51');
INSERT INTO `daming_content_info` VALUES (290, '{\"analysis\":\"| 序号  | 目的 IP 地址 | 转发接口 | 理由                                                         |\\n| ----- | ------------ | -------- | ------------------------------------------------------------ |\\n| **1** | 172.16.1.88  | **E0**   | 目的 IP 与路由表第一条（172.16.1.0/24）匹配，为直接交付，接口为 E0。 |\\n| **2** | 172.16.2.200 | **E0**   | 目的 IP 与路由表第二条（172.16.2.0/24）匹配，下一跳为 172.16.1.2，通过 E0 接口转发。 |\\n| **3** | 192.168.0.10 | **S0**   | 目的 IP 与路由表第三条（192.168.0.0/24）匹配，下一跳为 192.168.0.1，接口为 S0。 |\\n| **4** | 10.10.10.10  | **S1**   | 目的 IP 与前三条路由均不匹配，使用**默认路由**（0.0.0.0/0），下一跳为 203.100.50.1，接口为 S1。 |\\n| **5** | 8.8.4.4      | **S1**   | 目的 IP 与前三条路由均不匹配，使用**默认路由**，下一跳为 203.100.50.1，接口为 S1。 |\\n\\n* * *\\n\\n### 核心知识点总结\\n\\n*   **最长前缀匹配原则**：路由器在转发时，会将目的 IP 与路由表中的掩码进行“与”运算，匹配最精确（掩码最长）的那一条。\\n*   **默认路由**：当目的地址无法匹配任何特定路由条目时，数据包会按照 `0.0.0.0` 这一项指定的路径（默认网关）发出。\\n*   **直接交付**：表示目的主机就在该接口连接的网段内，不需要经过下一个路由器。\",\"analysisFormat\":\"markdown\",\"correct\":\"1\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"**某路由器 R2 的路由表如下：**\\n\\n| 目的网络    | 子网掩码      | 下一跳       | 接口 |\\n| ----------- | ------------- | ------------ | ---- |\\n| 172.16.1.0  | 255.255.255.0 | 直接交付     | E0   |\\n| 172.16.2.0  | 255.255.255.0 | 172.16.1.2   | E0   |\\n| 192.168.0.0 | 255.255.255.0 | 192.168.0.1  | S0   |\\n| 0.0.0.0     | 0.0.0.0       | 203.100.50.1 | S1   |\\n\\n**现路由器 R2 收到以下目的 IP 地址的数据包，请判断每个数据包应从哪个接口转发，并说明理由。**\\n\\n6.  目的 IP：172.16.1.88\\n7.  目的 IP：172.16.2.200\\n8.  目的 IP：192.168.0.10\\n9.  目的 IP：10.10.10.10\\n10.  目的 IP：8.8.4.4\",\"questionTitleFormat\":\"markdown\"}', '2026-01-05 11:56:00');
INSERT INTO `daming_content_info` VALUES (291, '[{\"name\":\"填空题\",\"paperQuestionVMS\":[{\"id\":182,\"itemOrder\":0},{\"id\":179,\"itemOrder\":1},{\"id\":180,\"itemOrder\":2},{\"id\":162,\"itemOrder\":3},{\"id\":164,\"itemOrder\":4},{\"id\":181,\"itemOrder\":5},{\"id\":177,\"itemOrder\":6},{\"id\":161,\"itemOrder\":7},{\"id\":168,\"itemOrder\":8},{\"id\":167,\"itemOrder\":9},{\"id\":169,\"itemOrder\":10},{\"id\":165,\"itemOrder\":11},{\"id\":166,\"itemOrder\":12},{\"id\":163,\"itemOrder\":13},{\"id\":175,\"itemOrder\":14},{\"id\":178,\"itemOrder\":15},{\"id\":176,\"itemOrder\":16}]},{\"name\":\"主观题\",\"paperQuestionVMS\":[{\"id\":188,\"itemOrder\":17},{\"id\":174,\"itemOrder\":18},{\"id\":172,\"itemOrder\":19},{\"id\":170,\"itemOrder\":20},{\"id\":183,\"itemOrder\":21},{\"id\":171,\"itemOrder\":22},{\"id\":185,\"itemOrder\":23},{\"id\":186,\"itemOrder\":24},{\"id\":173,\"itemOrder\":25},{\"id\":184,\"itemOrder\":26},{\"id\":187,\"itemOrder\":27}]}]', '2026-01-05 12:01:35');
INSERT INTO `daming_content_info` VALUES (292, '{\"analysis\":\"防火墙是网络安全的第一道防线，它像是一个**数字哨兵**，部署在不同网络安全域之间（如企业内网和互联网），根据规则对进出的流量进行审查。\\n\\n以下是针对你提到的基本功能和分类进行的详细解析：\\n\\n* * *\\n\\n一、 基本功能解析\\n---------\\n\\n### 1\\\\. 访问控制 (Access Control)\\n\\n*   **解析：** 这是防火墙最核心的功能。它通过一套**规则集**（白名单或黑名单），决定哪些流量可以进入网络，哪些必须被拦截。\\n*   **类比：** 就像大楼门口的保安，只允许持有工牌（符合特定 IP 或端口）的人进入。\\n\\n### 2\\\\. 日志记录 (Logging)\\n\\n*   **解析：** 记录所有通过或被拒绝的流量详情。这对于**安全审计**和**事后追溯**至关重要。\\n*   **作用：** 如果网络遭到攻击，管理员可以通过查看日志发现攻击者的来源、攻击时间及手段。\\n\\n### 3\\\\. 网络地址转换 (NAT)\\n\\n*   **解析：** 将内网使用的私有 IP 地址转换为公有 IP 地址后再发送到互联网，隐藏内网真实拓扑。\\n*   **作用：** 既解决了公网 IP 不足的问题，又提高了安全性，因为外部黑客很难直接定位到内网的具体主机。\\n\\n### 4\\\\. 入侵检测 (Intrusion Detection)\\n\\n*   **解析：** 现代防火墙（如下一代防火墙 NGFW）通常集成此功能。它不仅看“谁”在发数据，还看数据里“装了什么”，通过匹配特征码来发现潜在的木马或攻击行为。\\n\\n*   * *\\n\\n二、 分类解析\\n-------\\n\\n### 1\\\\. 包过滤防火墙 (Packet Filtering Firewall)\\n\\n*   **原理：** 工作在 **OSI 网络层**。它只检查数据包的报头（源/目的 IP、端口号、协议类型），不看数据内容。\\n*   **优点：** 速度快、性能开销小。\\n*   **缺点：** 无法防范隐藏在合法协议中的应用层攻击（如 SQL 注入）。\\n*   **地位：** 第一代防火墙技术。\\n\\n### 2\\\\. 状态检测防火墙 (Stateful Inspection Firewall)\\n\\n*   **原理：** 工作在 **网络层和传输层**。它不仅检查报头，还会跟踪一个连接的“状态”（如是否经过了三次握手）。如果一个回来的包没有对应的“发起申请”，就会被拦截。\\n*   **优点：** 安全性高于包过滤，且比应用网关效率高。\\n*   **地位：** 目前工业界应用最广泛的防火墙技术。\\n\\n### 3\\\\. 应用网关防火墙 (Application Gateway Firewall)\\n\\n*   **原理：** 工作在 **应用层**。它像一个“中转代理”，会拆开数据包去看具体的应用协议内容（如 HTTP、FTP 的指令）。\\n*   **优点：** 能够进行深度的内容检查，安全性最高。\\n*   **缺点：** 处理速度最慢，因为每一层都要解包检查，容易成为网络瓶颈。\\n\\n*   * *\\n\\n### 对比总结\\n\\n| 类型         | 工作层次          | 安全等级 | 性能速度 |\\n| ------------ | ----------------- | -------- | -------- |\\n| **包过滤**   | 网络层 (IP)       | 低       | 极快     |\\n| **状态检测** | 传输层 (TCP/UDP)  | 中       | 很快     |\\n| **应用网关** | 应用层 (HTTP/FTP) | 高       | 较慢     |\",\"analysisFormat\":\"markdown\",\"correct\":\"<p>1</p>\",\"correctFormat\":\"html\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"测试md格式\\n防火墙是网络安全的第一道防线，它像是一个**数字哨兵**，部署在不同网络安全域之间（如企业内网和互联网），根据规则对进出的流量进行审查。\\n\\n以下是针对你提到的基本功能和分类进行的详细解析：\\n\\n* * *\\n\\n一、 基本功能解析\\n---------\\n\\n### 1\\\\. 访问控制 (Access Control)\\n\\n*   **解析：** 这是防火墙最核心的功能。它通过一套**规则集**（白名单或黑名单），决定哪些流量可以进入网络，哪些必须被拦截。\\n*   **类比：** 就像大楼门口的保安，只允许持有工牌（符合特定 IP 或端口）的人进入。\\n\\n### 2\\\\. 日志记录 (Logging)\\n\\n*   **解析：** 记录所有通过或被拒绝的流量详情。这对于**安全审计**和**事后追溯**至关重要。\\n*   **作用：** 如果网络遭到攻击，管理员可以通过查看日志发现攻击者的来源、攻击时间及手段。\\n\\n### 3\\\\. 网络地址转换 (NAT)\\n\\n*   **解析：** 将内网使用的私有 IP 地址转换为公有 IP 地址后再发送到互联网，隐藏内网真实拓扑。\\n*   **作用：** 既解决了公网 IP 不足的问题，又提高了安全性，因为外部黑客很难直接定位到内网的具体主机。\\n\\n### 4\\\\. 入侵检测 (Intrusion Detection)\\n\\n*   **解析：** 现代防火墙（如下一代防火墙 NGFW）通常集成此功能。它不仅看“谁”在发数据，还看数据里“装了什么”，通过匹配特征码来发现潜在的木马或攻击行为。\\n\\n*   * *\\n\\n二、 分类解析\\n-------\\n\\n### 1\\\\. 包过滤防火墙 (Packet Filtering Firewall)\\n\\n*   **原理：** 工作在 **OSI 网络层**。它只检查数据包的报头（源/目的 IP、端口号、协议类型），不看数据内容。\\n*   **优点：** 速度快、性能开销小。\\n*   **缺点：** 无法防范隐藏在合法协议中的应用层攻击（如 SQL 注入）。\\n*   **地位：** 第一代防火墙技术。\\n\\n### 2\\\\. 状态检测防火墙 (Stateful Inspection Firewall)\\n\\n*   **原理：** 工作在 **网络层和传输层**。它不仅检查报头，还会跟踪一个连接的“状态”（如是否经过了三次握手）。如果一个回来的包没有对应的“发起申请”，就会被拦截。\\n*   **优点：** 安全性高于包过滤，且比应用网关效率高。\\n*   **地位：** 目前工业界应用最广泛的防火墙技术。\\n\\n### 3\\\\. 应用网关防火墙 (Application Gateway Firewall)\\n\\n*   **原理：** 工作在 **应用层**。它像一个“中转代理”，会拆开数据包去看具体的应用协议内容（如 HTTP、FTP 的指令）。\\n*   **优点：** 能够进行深度的内容检查，安全性最高。\\n*   **缺点：** 处理速度最慢，因为每一层都要解包检查，容易成为网络瓶颈。\\n\\n*   * *\\n\\n### 对比总结\\n\\n| 类型         | 工作层次          | 安全等级 | 性能速度 |\\n| ------------ | ----------------- | -------- | -------- |\\n| **包过滤**   | 网络层 (IP)       | 低       | 极快     |\\n| **状态检测** | 传输层 (TCP/UDP)  | 中       | 很快     |\\n| **应用网关** | 应用层 (HTTP/FTP) | 高       | 较慢     |\",\"questionTitleFormat\":\"markdown\"}', '2026-01-05 12:44:08');
INSERT INTO `daming_content_info` VALUES (293, '{\"analysis\":\"<h3>1. 完备性 (Completeness)</h3><p>指令集必须能够实现所有可能的运算和控制功能。</p><p><br></p><ul><li><strong>含义：</strong> 程序员或编译器能够使用该指令集编写出任何复杂的程序，而不需要借助指令集之外的操作。</li><li><strong>基本组成：</strong> 必须包含算术运算、逻辑运算、数据传输、程序控制（跳转/分支）以及输入输出指令。</li></ul><h3>2. 规整性 (Regularity)</h3><p>规整性决定了指令集的易用性和硬件实现的复杂度，主要包括以下三个子属性：</p><p><br></p><ul><li><strong>对称性 (Symmetry)：</strong> 同一类指令的所有操作数都应该可以使用相同的寻址方式（例如：加法指令和减法指令对操作数的限制应当一致）。</li><li><strong>均匀性 (Uniformity)：</strong> 各种指令应支持相同的数据类型（例如：如果整数能进行加减，浮点数也应该能进行同样的逻辑处理）。</li><li><strong>独立性：</strong> 指令的功能应独立于寄存器或存储器的位置。</li></ul><h3>3. 高效性 (Efficiency)  </h3><p>高效性是指指令集的执行速度和空间利用率。</p><p><br></p><ul><li><strong>含义：</strong> 能够用最少的指令条数、最快的执行时间来完成特定的任务。</li><li><strong>体现：</strong> 在 RISC 中体现为适合流水线处理；在 CISC 中体现为单条复杂指令能完成较多工作。此外，指令编码的密度（节省存储空间）也是高效性的体现。</li></ul><h3>4. 兼容性 (Compatibility)</h3><p>这是指令集长久生命力的保证，通常分为两个方向：</p><p><br></p><ul><li><strong>向后兼容 (Backward Compatibility)：</strong> 新型号的 CPU 能够运行旧型号 CPU 的所有指令（例如 x86 指令集的长期演进）。</li><li><strong>向上兼容 (Upward Compatibility)：</strong> 旧型号 CPU 编写的软件，在同一系列的新机器上能够运行得更好或完全不需修改。</li></ul><p><br></p><p><br></p><p>晚归高渐离</p>\",\"analysisFormat\":\"html\",\"correct\":\"完整性,规整性,高效性,兼容性\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">指令集应满足哪几个要求？</span></p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-05 17:36:28');
INSERT INTO `daming_content_info` VALUES (294, '{\"analysis\":\"<p>简单来说，软件生命周期的<strong>定义时期</strong>就是动工前的“<strong>搞清楚阶段</strong>”，主要分这三步：</p><p><br></p><ol><li><strong>问题定义</strong>：弄明白<strong>你要解决什么麻烦</strong>？（定目标）</li><li><strong>可行性研究</strong>：分析这事儿<strong>值不值得做、能不能做成</strong>？（避坑）</li><li><strong>需求分析</strong>：定好软件<strong>具体要实现哪些功能</strong>。（列清单）</li></ol><p><strong>一句话总结：</strong></p><p>就是先看<strong>干什么</strong>，再看<strong>能不能干</strong>，最后定好<strong>怎么算干完</strong>。</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>需求分析、总体设计、测试</p>\",\"prefix\":\"A\"},{\"content\":\"<p>总体设计、详细设计、编码</p>\",\"prefix\":\"B\"},{\"content\":\"<p>问题定义、可行性研究、需求分析</p>\",\"prefix\":\"C\"},{\"content\":\"<p>业务建模、需求分析、体系结构设计</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"color: rgb(31, 31, 31); background-color: rgb(255, 255, 255);\\\">在软件生命周期的软件定义时期，主要包括哪三个阶段</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:26:31');
INSERT INTO `daming_content_info` VALUES (295, '{\"analysis\":\"<p>瀑布模型（Waterfall Model）是软件工程中最经典的开发模型。用大白话讲，它就像<strong>工厂的流水线</strong>或是<strong>盖房子</strong>。</p><p>其主要特征可以概括为以下三点：</p><p><br></p><h3>1. 顺序性（按部就班）</h3><p>像下楼梯一样，必须<strong>走完一步才能走下一步</strong>。你不能还没画好图纸（设计）就开始砌墙（编码），也不能还没砌墙就开始刷漆（测试）。</p><p><br></p><h3>2. 依赖性（承上启下）</h3><p>每个阶段的<strong>产出</strong>就是下一个阶段的<strong>输入</strong>。</p><p><br></p><ul><li>比如：只有拿到了“需求说明书”，设计人员才能开始画架构图。</li></ul><p><br></p><p>**</p><h3>3. 推迟实现（见效晚）</h3><p>在瀑布模型中，只有到整个流程的<strong>后期</strong>（编码和测试阶段），才能看到实际运行的代码。前期基本都在写文档、开会。</p><h3>💡 解析小贴士：</h3><ul><li><strong>优点</strong>：非常规范，每个阶段都有文档，适合需求明确、变动小的项目（如航天、银行核心系统）。</li><li><strong>缺点</strong>：太死板。如果最后测试发现需求搞错了，回头改的成本极高（就像房子盖好了发现地基歪了）。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>强调减少文档，增加沟通</p>\",\"prefix\":\"A\"},{\"content\":\"<p>阶段间具有顺序性和依赖性</p>\",\"prefix\":\"B\"},{\"content\":\"<p>以用户原型驱动开发</p>\",\"prefix\":\"C\"},{\"content\":\"<p>按二维结构组织，x轴为时间</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">瀑布模型的主要特征是？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:30:23');
INSERT INTO `daming_content_info` VALUES (296, '{\"analysis\":\"<h3>为什么选它？</h3><ul><li><strong>对付“需求模糊”</strong>：用户说不清楚要什么时，你先花几天功夫做一个“简陋但能动”的壳子（原型）给他们看。用户一看：“哎，这个搜素框位置不对”，需求一下子就明确了。</li><li><strong>满足“尽早看到效果”</strong>：不像瀑布模型要等几个月才给看成品，原型模型可能在项目开始的一两周，用户就能在电脑上点点看了。</li></ul><h3>它的工作套路：</h3><ol><li><strong>快速分析</strong>：简单聊聊大概要啥。</li><li><strong>构建原型</strong>：用最快速度做个“买家秀”。</li><li><strong>用户评价</strong>：用户试用并吐槽（反馈）。</li><li><strong>修正模型</strong>：根据吐槽修改。</li><li><strong>反复循环</strong>：直到用户说“这就是我想要的”。</li></ol><h3>💡 解析小贴士：</h3><ul><li><strong>要注意的是</strong>：原型往往只是个“空壳子”，后台数据可能是假的。所以要提醒用户：<strong>你看的东西还不能正式上线，这只是个草图。</strong></li><li><strong>考点区分</strong>：如果题目强调“<strong>风险大</strong>”，选<strong>螺旋模型</strong>；如果强调“<strong>需求模糊且想快点看到东西</strong>”，选<strong>快速原型模型</strong>。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>维护模型</p>\",\"prefix\":\"A\"},{\"content\":\"<p>统一过程模型</p>\",\"prefix\":\"B\"},{\"content\":\"<p>瀑布模型</p>\",\"prefix\":\"C\"},{\"content\":\"<p>快速原型模型</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">如果一个项目的需求非常模糊，且用户希望尽早看到系统效果，最适合采用哪种模型？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:32:39');
INSERT INTO `daming_content_info` VALUES (297, '{\"analysis\":\"<p>在统一过程模型（RUP）中，这个阶段被称为 <strong>初始阶段 (Inception Phase)</strong>。</p><p>大白话解析：</p><p><br></p><h3>核心目标：</h3><p>这个阶段就是项目的**“准入期”**，主要是为了回答两个核心问题：</p><p><br></p><ol><li><strong>做什么？</strong>（划定系统范围，别把项目做成“无底洞”）。</li><li><strong>能不能做？</strong>（评估业务可行性，看赚钱不赚钱，技术上行不行）。</li></ol><h3>这个阶段干点啥？</h3><ul><li><strong>定范围</strong>：确定系统的边界，明确哪些功能要做，哪些不做。</li><li><strong>算细账</strong>：搞一个简单的“商业案例”，算算成本和收益。</li><li><strong>估风险</strong>：看看项目里有没有什么“深坑”。</li><li><strong>定初稿</strong>：找准核心用户，列出大概 20% 的核心功能（用例）。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>转换阶段(Transition)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>初始阶段 (Inception)</p>\",\"prefix\":\"B\"},{\"content\":\"<p>构建阶段（Construction)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>细化阶段(Elaboration)</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">统一过程模型（RUP）中，哪一个阶段的目标是划定系统范围，评估业务可行性？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:38:33');
INSERT INTO `daming_content_info` VALUES (298, '{\"analysis\":\"<p>敏捷原则是\\\"增加沟通，减少文档”，与瀑布模型相反。</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>强调快速迭代和及早考虑测试</p>\",\"prefix\":\"A\"},{\"content\":\"<p>开发人员通常需要是多功能型的\\\"全能选手\\\"</p>\",\"prefix\":\"B\"},{\"content\":\"<p>主张通过增加文档来降低沟通成本</p>\",\"prefix\":\"C\"},{\"content\":\"<p>适用于需求变化较频繁的项目</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">关于敏捷开发模型的原则，下列说法错误的是？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:57:01');
INSERT INTO `daming_content_info` VALUES (299, '{\"analysis\":\"<p><span style=\\\"background-color: rgb(196, 238, 208); color: rgb(31, 31, 31);\\\">根据笔记，分析和设计阶段主要考虑的是系统的逻辑模型，而非物理实现。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">判断：瀑布模型在编码前设置了系统分析和设计阶段，主要考虑系统的物理实现。</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:57:42');
INSERT INTO `daming_content_info` VALUES (300, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>项目的风险等级</p>\",\"prefix\":\"A\"},{\"content\":\"<p>代码行数</p>\",\"prefix\":\"B\"},{\"content\":\"<p>核心工作流 (如需求、分析设计等)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>时间轴 (如初始、细化等)</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">在统一过程模型（RUP）的二维结构中，y轴代表的是什么？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 14:59:52');
INSERT INTO `daming_content_info` VALUES (301, '{\"analysis\":\"<p><img src=\\\"data:image/png;base64,\\\"></p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>软件维护时期</p>\",\"prefix\":\"A\"},{\"content\":\"<p>软件开发时期</p>\",\"prefix\":\"B\"},{\"content\":\"<p>编码阶段</p>\",\"prefix\":\"C\"},{\"content\":\"<p>需求分析阶段</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">软件生命周期中，历时最长、成本通常最高的时期是？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:00:32');
INSERT INTO `daming_content_info` VALUES (302, '{\"analysis\":\"<p>笔记中提到开发人员挑完成什么需求，体现了团队的自主性。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">判断：敏捷开发中的“自主管理”意味着开发人员可以自由挑选想要完成的需求。</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:01:08');
INSERT INTO `daming_content_info` VALUES (303, '{\"analysis\":\"<p><span style=\\\"background-color: rgb(196, 238, 208); color: rgb(31, 31, 31);\\\">这是RUP官方定义的三大支柱。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>用例驱动，以体系结构为核心，增量且迭代</p>\",\"prefix\":\"A\"},{\"content\":\"<p>仅仅适用于小型全栈团队</p>\",\"prefix\":\"B\"},{\"content\":\"<p>快速编码，放弃文档</p>\",\"prefix\":\"C\"},{\"content\":\"<p>线性推进，每个阶段必须评审</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">统一过程模型（RUP）的核心特征可以概括为：</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:02:20');
INSERT INTO `daming_content_info` VALUES (304, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>软件定义</p>\",\"prefix\":\"A\"},{\"content\":\"<p>软件开发</p>\",\"prefix\":\"B\"},{\"content\":\"<p>详细设计</p>\",\"prefix\":\"C\"},{\"content\":\"<p>软件维护</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">一般说来，软件生命周期由三个大的时期组成，不包括下面哪个时期( )。</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:04:11');
INSERT INTO `daming_content_info` VALUES (305, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>需求分析</p>\",\"prefix\":\"A\"},{\"content\":\"<p>程序设计</p>\",\"prefix\":\"B\"},{\"content\":\"<p>详细设计</p>\",\"prefix\":\"C\"},{\"content\":\"<p>软件维护</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">按软件生命周期方法设计软件的过程中，画数据流图属于下面哪个阶段的工作(&nbsp;&nbsp;)。</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:04:48');
INSERT INTO `daming_content_info` VALUES (306, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>可强迫开发人员采用规范化的方法。</p>\",\"prefix\":\"A\"},{\"content\":\"<p>严格地规定了每个阶段必须提交的文档。</p>\",\"prefix\":\"B\"},{\"content\":\"<p>要求每个阶段交出的所有产品都必须是经过验证的。</p>\",\"prefix\":\"C\"},{\"content\":\"<p>适用于项目开始时需求已确定的情况。</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><br></p><p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">以下哪一个是瀑布模型的缺点。( )</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:05:37');
