INSERT INTO `daming_content_info` VALUES (308, '{\"analysis\":\"<p>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">OMT（Object Modeling Technique）是由</span>\\t<a href=\\\"https://baike.baidu.com/item/James%20Rumbaugh/517232?fromModule=lemma_inlink\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\" style=\\\"background-color: rgb(255, 255, 255); color: rgb(19, 110, 194);\\\">James Rumbaugh</a>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">等人于1991年提出的面向对象建模方法，采用对象模型、动态模型和</span>\\t<a href=\\\"https://baike.baidu.com/item/%E5%8A%9F%E8%83%BD%E6%A8%A1%E5%9E%8B/563406?fromModule=lemma_inlink\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\" style=\\\"background-color: rgb(255, 255, 255); color: rgb(19, 110, 194);\\\">功能模型</a>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">三个维度对系统进行结构化分析与设计。对象模型通过</span>\\t<a href=\\\"https://baike.baidu.com/item/%E7%B1%BB%E5%9B%BE/4670826?fromModule=lemma_inlink\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\" style=\\\"background-color: rgb(255, 255, 255); color: rgb(19, 110, 194);\\\">类图</a>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">描述静态数据结构，动态模型用</span>\\t<a href=\\\"https://baike.baidu.com/item/%E7%8A%B6%E6%80%81%E5%9B%BE/4925373?fromModule=lemma_inlink\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\" style=\\\"background-color: rgb(255, 255, 255); color: rgb(19, 110, 194);\\\">状态图</a>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">刻画系统状态变化，功能模型以</span>\\t<a href=\\\"https://baike.baidu.com/item/%E6%95%B0%E6%8D%AE%E6%B5%81%E5%9B%BE/4136477?fromModule=lemma_inlink\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\" style=\\\"background-color: rgb(255, 255, 255); color: rgb(19, 110, 194);\\\">数据流图</a>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">定义系统功能需求，三者协同覆盖软件开发的系统分析、设计和实现阶段。该方法强调图形化建模，适用于数据密集型系统开发，其技术框架为后续</span>\\t<a href=\\\"https://baike.baidu.com/item/UML/446747?fromModule=lemma_inlink\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\" style=\\\"background-color: rgb(255, 255, 255); color: rgb(19, 110, 194);\\\">UML</a>\\t<span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">标准的形成奠定了基础。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>Booch</p>\",\"prefix\":\"A\"},{\"content\":\"<p>Rumbaugh</p>\",\"prefix\":\"B\"},{\"content\":\"<p>Coad</p>\",\"prefix\":\"C\"},{\"content\":\"<p>Jacobson</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">OMT 方法是由下面哪位科学家提出的( )</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:08:11');
INSERT INTO `daming_content_info` VALUES (309, '{\"analysis\":\"<p>答案是：<strong>完善性维护 (Perfective Maintenance)</strong>。</p><h3>大白话解析</h3><p>为什么它最重要？因为软件只要在使用，用户就会不断提新要求。</p><p><br></p><ul><li><strong>占大头</strong>：在所有的维护活动中，完善性维护通常占到 <strong>50% - 60%</strong> 以上的工作量。</li><li><strong>保青春</strong>：为了让软件不被时代淘汰，你需要不断给它<strong>增加新功能</strong>、<strong>优化性能</strong>、<strong>美化界面</strong>。这就像房子装修好了，你后期换个更智能的锁、加个洗碗机，都是为了住得更舒服。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>完善性维护</p>\",\"prefix\":\"A\"},{\"content\":\"<p>改正性维护</p>\",\"prefix\":\"B\"},{\"content\":\"<p>适应性维护</p>\",\"prefix\":\"C\"},{\"content\":\"<p>预防性维护</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><br></p><p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">各种软件维护的类型中最重要的是( )。</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:10:22');
