INSERT INTO `daming_content_info` VALUES (330, '{\"analysis\":\"<p>软件可靠性定义表明了一个程序按照用户的要求和设计的目标，执行其功能的正确程度。一个可靠的程序应要求是正确的、完整</p><p>的、一致的和健壮的，是指能够以数字概念来描述可靠性的数学表达式中所使用的量。</p><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>硬件可靠性的定量度量</p>\",\"prefix\":\"A\"},{\"content\":\"<p>软件可靠性的定量指标</p>\",\"prefix\":\"B\"},{\"content\":\"<p>系统的定量度量</p>\",\"prefix\":\"C\"},{\"content\":\"<p>可靠性的度量</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>（ ）是指能够以数字概念来描述可靠性的数学表达式中所使用的量。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:47:29');
INSERT INTO `daming_content_info` VALUES (331, '{\"analysis\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(168, 168, 179);\\\">McCabe度量法是由Thomas McCabe提出的一种基于程序控制流的复杂性度量方法。McCabe复杂性度量又称环路度量，它认为程序的复杂性很大程度上取决于控制的复杂性。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>代码行度量</p>\",\"prefix\":\"A\"},{\"content\":\"<p>环路度量</p>\",\"prefix\":\"B\"},{\"content\":\"<p>程序量度量</p>\",\"prefix\":\"C\"},{\"content\":\"<p>功能性度量</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>McCabe复杂性度量又称为（ ）。</h3>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:48:23');
INSERT INTO `daming_content_info` VALUES (332, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>通用性</p>\",\"prefix\":\"A\"},{\"content\":\"<p>效率</p>\",\"prefix\":\"B\"},{\"content\":\"<p>质量</p>\",\"prefix\":\"C\"},{\"content\":\"<p> 人机界面</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>软件可移植性是用来衡量软件的（ ）重要尺度之一。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:49:25');
INSERT INTO `daming_content_info` VALUES (333, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>错误检测</p>\",\"prefix\":\"A\"},{\"content\":\"<p>故障排除</p>\",\"prefix\":\"B\"},{\"content\":\"<p>调试</p>\",\"prefix\":\"C\"},{\"content\":\"<p>测试</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>从已经发现故障的存在到找到准确的故障位置并确定故障的性质，这一过程称为（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:50:06');
INSERT INTO `daming_content_info` VALUES (334, '{\"analysis\":\"<p>回归测试指在软件维护阶段，为了检测代码修改而引入的错误所进行的测试活动。回归测试是软件维护阶段的重要工作，同时也</p><p>是校正性维护中最常用的方法。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>校正性维护</p>\",\"prefix\":\"A\"},{\"content\":\"<p>适应性维护</p>\",\"prefix\":\"B\"},{\"content\":\"<p> 完善性维护</p>\",\"prefix\":\"C\"},{\"content\":\"<p>预防性维护</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>回归测试是（ ）中最常用的方法。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:50:48');
INSERT INTO `daming_content_info` VALUES (335, '{\"analysis\":\"<p><br></p><p>在模块测试过程中，自底向上的测试随着上移，驱动模块逐步减少，测试开销小，而自顶向上的测试需要设计较多的桩模块，测</p><p>试开销大，所以采用自底向上的测试比自顶向下的测试好。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>好</p>\",\"prefix\":\"A\"},{\"content\":\"<p>差</p>\",\"prefix\":\"B\"},{\"content\":\"<p>一样</p><p><br></p>\",\"prefix\":\"C\"},{\"content\":\"<p>未知</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>在模块测试的过程中，采用自底向上的测试比自顶向下的测试（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:51:29');
INSERT INTO `daming_content_info` VALUES (336, '{\"analysis\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(168, 168, 179);\\\">测试是对软件规格说明、设计和编码的最后复审，所以软件测试贯穿在整个软件开发期的全过程。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>程序编程阶段</p>\",\"prefix\":\"A\"},{\"content\":\"<p>软件开发全过程</p>\",\"prefix\":\"B\"},{\"content\":\"<p>软件允许阶段</p>\",\"prefix\":\"C\"},{\"content\":\"<p>软件设计阶段</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>软件测试是保证软件质量的重要措施，它的实施应该在（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:53:02');
INSERT INTO `daming_content_info` VALUES (337, '{\"analysis\":\"<p><br></p><h3><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(168, 168, 179);\\\">软件开发需求分析对应的是测试阶段的确认测试，软件设计对应的是集成测试（组装测试），编码阶段对应的是单元测试。</span></h3><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>组装测试、确认测试、单元测试</p><p><br></p>\",\"prefix\":\"A\"},{\"content\":\"<p>单元测试、组装测试、确认测试</p>\",\"prefix\":\"B\"},{\"content\":\"<p> 单元测试、确认测试、组装测试</p>\",\"prefix\":\"C\"},{\"content\":\"<p>确认测试、组装测试、单元测试</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>从下列叙述中选出能够与软件开发需求分析、设计、编码相对应的软件测试（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:54:40');
INSERT INTO `daming_content_info` VALUES (338, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>使用的方便性</p>\",\"prefix\":\"A\"},{\"content\":\"<p>简洁性</p>\",\"prefix\":\"B\"},{\"content\":\"<p>可靠性</p>\",\"prefix\":\"C\"},{\"content\":\"<p>设备独立性</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>为了提高软件的可移植性，应注意提高软件的（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:55:45');
INSERT INTO `daming_content_info` VALUES (339, '{\"analysis\":\"<p><br></p><p>因果图的基本原理是通过画因果图，把自然语言描述的功能说明转换为判定表，最后为判定表的每一列设计一个测试用例，它能</p><p>有效地检测输入条件的各种组合可能会引起的错误。</p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>等价类划分法</p>\",\"prefix\":\"A\"},{\"content\":\"<p>边界值分析法</p>\",\"prefix\":\"B\"},{\"content\":\"<p>错误推测法</p>\",\"prefix\":\"C\"},{\"content\":\"<p> 因果图法</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>在黑盒测试中，着重检查输入条件的组合是（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:58:35');
INSERT INTO `daming_content_info` VALUES (340, '{\"analysis\":\"<p><br></p><p>单元测试主要从下面五个基本特征进行测试，分别是：模块接口、局部数据结构、独立路径和出错处理。而系统功能通常是在系</p><p>统测试时进行的。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>系统功能</p>\",\"prefix\":\"A\"},{\"content\":\"<p>局部数据结构</p>\",\"prefix\":\"B\"},{\"content\":\"<p>重要的执行路径</p>\",\"prefix\":\"C\"},{\"content\":\"<p>错误处理</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>单元测试主要针对模块的几个基本特征进行测试，该阶段不能完成的测试是（ ）。</h3><p> </p><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 15:59:53');
INSERT INTO `daming_content_info` VALUES (341, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"单元测试,集成测试,确认测试,系统测试\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<h3>软件产品在交付使用之前一般要经过以下四步测试：_____、_____、_____、和_____。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-14 16:01:01');
INSERT INTO `daming_content_info` VALUES (342, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"等价类划分法,正好等于,刚刚大于,刚刚小于\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<h3>使用边界值分析方法设计测试用例时一般与_____结合起来。但它不是从一个等价类中任选一个例子作为代表，而是将测试边界情况作为重点目标，选取_____、_____或_____边界值的测试数据。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-14 16:01:58');
INSERT INTO `daming_content_info` VALUES (343, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"有效性测试,功能,性能,需求规格说明书\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<h3>确认测试又称_____。它的任务是检查软件的_____与_____是否 与_____中确定的指标相符合。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-14 16:02:27');
