INSERT INTO `daming_content_info` VALUES (346, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>等价类划分</p>\",\"prefix\":\"A\"},{\"content\":\"<p>边界值分析</p>\",\"prefix\":\"B\"},{\"content\":\"<p>因果图</p>\",\"prefix\":\"C\"},{\"content\":\"<p>判定表</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>在设计测试用例时，( )是用得最多的一种黑盒测试方法。</h3>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:12:20');
INSERT INTO `daming_content_info` VALUES (347, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>对象模型、动态模型、功能模型</p>\",\"prefix\":\"A\"},{\"content\":\"<p>对象模型、数据模型、功能模型</p>\",\"prefix\":\"B\"},{\"content\":\"<p>数据模型、动态模型、功能模型</p>\",\"prefix\":\"C\"},{\"content\":\"<p>对象模型、动态模型、数据模型</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>面向对象模型主要由以下哪些模型组成( )</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:16:13');
INSERT INTO `daming_content_info` VALUES (348, '{\"analysis\":\"<p>答案是：<strong>B、边界值分析测试</strong>。</p><h3>💡 大白话解析</h3><p>要区分白盒和黑盒测试，最简单的办法就是看测试员**“盯着哪儿看”**：</p><p><br></p><ul><li><strong>白盒测试（看代码内部）</strong>：测试员像有“透视眼”一样，盯着程序的<strong>源代码、逻辑结构、路径</strong>去测。</li><li class=\\\"ql-indent-1\\\"><strong>A、基本路径测试</strong>：检查代码里的每一条路是不是都能走通。</li><li class=\\\"ql-indent-1\\\"><strong>C、循环覆盖测试</strong>：专门盯着 <code>for</code> 或 <code>while</code> 循环，看循环 0 次、1 次、多次有没有问题。</li><li class=\\\"ql-indent-1\\\"><strong>D. 逻辑覆盖测试</strong>：看代码里的 <code>if...else</code> 判定条件是否都执行到了。</li><li><strong>黑盒测试（只看输入输出）</strong>：测试员把软件当成一个“看不见内部的黑盒子”。他不关心代码怎么写，只关心：<strong>我输入这个，你能不能给我正确的结果？</strong></li><li class=\\\"ql-indent-1\\\"><strong>B、边界值分析测试</strong>：这就是典型的黑盒法。比如输入框规定填 1-100，我试一下 1 和 100。我不需要看代码是怎么写的，我只需要看界面反馈对不对。</li></ul><h3>🚀 考试速记口诀</h3><ul><li><strong>白盒看“逻辑”</strong>：只要选项里带**“覆盖”<strong>、</strong>“路径”<strong>、</strong>“结构”**，基本都是白盒。</li><li><strong>黑盒看“数据”</strong>：只要选项里带**“等价类”<strong>、</strong>“边界值”<strong>、</strong>“错误推测”<strong>、</strong>“因果图”**，都是黑盒。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(24, 30, 51);\\\">基本路径测试</span></p>\",\"prefix\":\"A\"},{\"content\":\"<p>边界值分析测试</p><p><br></p>\",\"prefix\":\"B\"},{\"content\":\"<p>循环覆盖测试</p>\",\"prefix\":\"C\"},{\"content\":\"<p>逻辑覆盖测试</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<h3>以下哪种测试方法不属于白盒测试技术( )</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:17:39');
INSERT INTO `daming_content_info` VALUES (349, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"OOA,OOD,OOP\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<h3>软件的面向对象开发方法包括____ ， ____，&nbsp;____三部分。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-14 16:18:37');
