INSERT INTO `daming_content_info` VALUES (351, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"questionTitle\":\"<h3>耦合用于衡量一个模块内部的各个元素彼此结合的紧密程度。( )</h3><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:19:24');
INSERT INTO `daming_content_info` VALUES (352, '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>内容耦合&lt;控制耦合&lt;标记耦合&lt;数据耦合</p>\",\"prefix\":\"A\"},{\"content\":\"<p>数据耦合&lt;控制耦合&lt;标记耦合&lt;内容耦合</p>\",\"prefix\":\"B\"},{\"content\":\"<p>数据耦合&lt;标记耦合&lt;控制耦合&lt;内容耦合</p>\",\"prefix\":\"C\"},{\"content\":\"<p>标记耦合&lt;数据耦合&lt;控制耦合&lt;内容耦合</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">在耦合度从低到高的排序中，下列哪组排序是正确的？</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:27:59');
INSERT INTO `daming_content_info` VALUES (353, '{\"analysis\":\"<p><span style=\\\"background-color: rgb(196, 238, 208); color: rgb(31, 31, 31);\\\">传递整个数据结构而非单一数据项，即为标记耦合。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>标记耦合（Stamp Coupling)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>数据耦合</p>\",\"prefix\":\"B\"},{\"content\":\"<p>公共耦合</p>\",\"prefix\":\"C\"},{\"content\":\"<p>控制耦合</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">当一个模块通过参数表传递的是一个复杂的数据结构（如整个记录、数组或对象），而目标模块只使用了其中的一部分数据时，这种耦合被称为：</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:28:26');
INSERT INTO `daming_content_info` VALUES (354, '{\"analysis\":\"<p><span style=\\\"background-color: rgb(196, 238, 208); color: rgb(31, 31, 31);\\\">根据笔记：初态只有一个，终态可以有多个（或没有）。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">判断：在状态转换图中，初态可以有多个，但终态只能有一个。</span></p><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-14 16:29:37');
