INSERT INTO `daming_content_info` VALUES (364, '{\"analysis\":\"两个或两个以上的进程互相持有对方资源且不释放导致所有进程阻塞的状态\",\"analysisFormat\":\"markdown\",\"correct\":\"<p>两个或两个以上的进程互相持有对方资源且不释放导致所有进程阻塞的状态</p>\",\"correctFormat\":\"html\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>什么是死锁状态</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 11:25:35');
INSERT INTO `daming_content_info` VALUES (365, '{\"analysis\":\"两个或两个以上进程**互相持有对方所需资源且不释放**而导致的所有相关进程处于阻塞状态\\n\\n**四个必要条件**\\n\\n- **互斥 (Mutual Exclusion)：** 一种资源每次只能被**一个进程**使用。就像独木桥，一次只能过一个人。\\n- **非抢占性 (No Preemption)：** 资源不能被强制剥夺。只有当进程使用完毕后，才**自愿释放**，别人不能从它手里抢走。\\n- **占用等待 (Hold and Wait)：** 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程**既不释放已有的，也不停止索取别人的**。\\n- **循环等待 (Circular Wait)：** 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个**闭合的环**（A等B，B等C，C等A）。\\n\\n------\\n\\n**一句话总结：** 大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。\\n\\n \",\"analysisFormat\":\"markdown\",\"correct\":\"两个或两个以上进程**互相持有对方所需资源且不释放**而导致的所有相关进程处于阻塞状态\\n\\n**四个必要条件**\\n\\n- **互斥 (Mutual Exclusion)：** 一种资源每次只能被**一个进程**使用。就像独木桥，一次只能过一个人。\\n- **非抢占性 (No Preemption)：** 资源不能被强制剥夺。只有当进程使用完毕后，才**自愿释放**，别人不能从它手里抢走。\\n- **占用等待 (Hold and Wait)：** 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程**既不释放已有的，也不停止索取别人的**。\\n- **循环等待 (Circular Wait)：** 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个**闭合的环**（A等B，B等C，C等A）。\\n\\n------\\n\\n**一句话总结：** 大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。\\n\\n \",\"correctFormat\":\"markdown\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>死锁的四个必要条件 </p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 11:27:00');
