INSERT INTO `daming_content_info` VALUES (369, '{\"analysis\":\"<p>:<strong><u>一类是有结构文件，称为记录文件</u></strong>;<strong><u>另一个是无结构文件，称为流式文件</u></strong></p><p><br></p><p>记录/流式</p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>:<strong><u>一类是有结构文件，称为记录文件</u></strong>;<strong><u>另一个是无结构文件，称为流式文件</u></strong></p><p><br></p><p>记录/流式</p>\",\"correctFormat\":\"html\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>文件的逻辑结构可分为两大类</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 11:56:51');
INSERT INTO `daming_content_info` VALUES (370, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"<p>1</p>\",\"correctFormat\":\"html\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p><img src=\\\"data:image/png;base64,\\\"></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 12:11:00');
INSERT INTO `daming_content_info` VALUES (371, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"**就绪态**：万事俱备，只欠 CPU。进程已获得除 CPU 时间片以外的所有必要资源。\\n\\n**运行态**：正在开工。进程已获得 CPU 时间片，程序正在处理机上执行。\\n\\n**阻塞态**：等待补给。因等待 I/O 或其他事件而无法执行，**即使** CPU 空闲也无法运行。\\n\\n\\n\\n就绪->运行：处理机从就绪队列里选一个进程执行\\n\\n运行->就绪：时间片用完或给高优先级进程让出处理机\\n\\n运行->阻塞：因等待IO事件或其他事件而暂时无法继续执行从而进入阻塞状态\\n\\n阻塞->就绪：进程等待的事件完成，进程被唤醒并进入就绪队列\\n\\n\",\"correctFormat\":\"markdown\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>进程有哪三种状态，他们之间是如何转换的</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 12:25:49');
INSERT INTO `daming_content_info` VALUES (372, '{\"analysis\":\"**就绪态**：万事俱备，只欠 CPU。进程已获得除 CPU 时间片以外的所有必要资源。\\n\\n**运行态**：正在开工。进程已获得 CPU 时间片，程序正在处理机上执行。\\n\\n**阻塞态**：等待补给。因等待 I/O 或其他事件而无法执行，**即使** CPU 空闲也无法运行。\\n\\n\\n\\n就绪->运行：处理机从就绪队列里选一个进程执行\\n\\n运行->就绪：时间片用完或给高优先级进程让出处理机\\n\\n运行->阻塞：因等待IO事件或其他事件而暂时无法继续执行从而进入阻塞状态\\n\\n阻塞->就绪：进程等待的事件完成，进程被唤醒并进入就绪队列\\n\\n\",\"analysisFormat\":\"markdown\",\"correct\":\"1\",\"correctFormat\":\"markdown\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>进程有哪三种状态，他们之间是如何转换的</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 12:25:58');
INSERT INTO `daming_content_info` VALUES (373, '{\"analysis\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"correctFormat\":\"html\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<h2><strong>tomasulo算法是什么及其基本思想</strong></h2>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 15:19:10');
INSERT INTO `daming_content_info` VALUES (374, '{\"analysis\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"analysisFormat\":\"markdown\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctFormat\":\"markdown\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 15:53:41');
INSERT INTO `daming_content_info` VALUES (375, '{\"analysis\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频繁阻塞\\n\\n4.**访存频繁**：支持复杂的访存指令，但受限于内存\\n\\n5.**功耗大**：芯片控制逻辑复杂且面积大发热高\",\"analysisFormat\":\"markdown\",\"correct\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频繁阻塞\\n\\n4.**访存频繁**：支持复杂的访存指令，但受限于内存\\n\\n5.**功耗大**：芯片控制逻辑复杂且面积大发热高\",\"correctFormat\":\"markdown\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<h2><strong>cics指令集存在哪些问题</strong></h2>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 16:02:24');
INSERT INTO `daming_content_info` VALUES (376, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"堆栈,累加器,通用寄存器组\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p>区分不同指令集结构的主要因素是存放操作数的存储单元类型，有哪些类型</p>\",\"questionTitleFormat\":\"html\",\"requireOrder\":false}', '2026-01-15 16:06:39');
INSERT INTO `daming_content_info` VALUES (377, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"optionFormat\":\"html\",\"questionOptionList\":[{\"content\":\"<p>存储器-存储器型结构 (Memory-to-Memory Architecture)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>通用寄存器型结构(General-Purpose Register Architecture)</p>\",\"prefix\":\"B\"},{\"content\":\"<p>堆栈型结构(Stack Architecture)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>累加器型结构 (Accumulator Architecture)</p>\",\"prefix\":\"D\"}],\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">区分不同指令集结构（ISA）的最主要因素是指令中存放操作数的存储单元类型。如果一个指令集结构要求所有操作数都必须显式或隐式地从一个特定的、唯一的存储位置获取，并在运算后将结果存回该位置，这种结构通常被称为：</span></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 16:07:44');
