INSERT INTO `daming_content_info` VALUES (379, '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"<p><img src=\\\"https://daming-paper.oss-cn-guangzhou.aliyuncs.com/quiz/paper/answer/2026/01/15/3da4d837f56b49418d3e8275120378de.png\\\"></p>\",\"correctFormat\":\"html\",\"optionFormat\":\"html\",\"questionOptionList\":[],\"questionTitle\":\"<p class=\\\"ql-align-justify\\\">考虑某一两级Cache：第一级Cache为L1，第二级Cache为L2。</p><p class=\\\"ql-align-justify\\\">（1）假设在1000次访存中，L1的不命中是40次，L2的不命中是20次。求各种局部不命中率和全局不命中率。</p><p class=\\\"ql-align-justify\\\">（2）假设L2的命中时间是10个时钟周期，L2的不命中开销是100时钟周期，L1的命中时间是1个时钟周期，平均每条指令访存1.5次，不考虑写操作的影响。问：平均访存时间是多少？每条指令的平均停顿时间是多少个时钟周期？&nbsp;&nbsp;</p><p><br></p>\",\"questionTitleFormat\":\"html\"}', '2026-01-15 16:27:28');
