INSERT INTO `daming_notice` VALUES (1, '系统维护通知666', '尊敬的用户，系统将于本周六（2025年11月23日）凌晨2:00-4:00进行系统维护升级，期间将暂停服务，请各位用户合理安排考试时间。给您带来的不便敬请谅解！', 1, 1, 1, '2025-11-23 14:02:03', 100, 8, '0', 'admin', '2025-11-23 14:02:03', 'admin', '2026-01-08 22:48:22', '系统维护公告');
INSERT INTO `daming_notice` VALUES (2, '新功能上线公告', '亲爱的用户们，我们很高兴地宣布，数据大屏功能正式上线！您可以在个人中心查看详细的学习数据统计，包括考试成绩趋势、错题分析、学习时间分布等，快来体验吧！', 2, 1, 0, '2025-11-23 14:02:03', 90, 1, '0', 'admin', '2025-11-23 14:02:03', 'admin', '2025-11-23 14:42:36', '新功能发布');
INSERT INTO `daming_notice` VALUES (3, '考试规则说明', '为了保证考试的公平公正，请各位考生注意以下事项：\n1. 考试过程中请独立完成，不得借助任何外部资源\n2. 每道题目都有时间限制，请合理分配答题时间\n3. 提交后不可修改答案，请仔细检查后再提交\n4. 系统会自动记录考试过程，请诚信考试', 1, 0, 1, '2025-11-23 14:02:03', 80, 6, '0', 'admin', '2025-11-23 14:02:03', NULL, '2025-12-23 23:22:42', '考试规则');
INSERT INTO `daming_notice` VALUES (4, '学习资料更新', '本周新增了100道Java高级编程题目和50道数据库优化题目，欢迎大家前往题库练习。同时，我们还整理了常见错题解析文档，可在错题本中查看详细解答。', 3, 0, 1, '2025-11-23 14:02:03', 70, 4, '0', 'admin', '2025-11-23 14:02:03', NULL, '2025-12-23 23:22:44', '题库更新');
