INSERT INTO `daming_question` VALUES (182, 5, 284, '基于端口,基于mac地址,基于IP子网', 1, 0, 4, '2026-01-05 10:54:35', '2026-01-05 10:54:35');
INSERT INTO `daming_question` VALUES (183, 3, 285, '区别：电路交互要建立连接，独占资源，分组交换是存储转发的，共享资源\n优缺点：电路交换实时性强，适合实时通信，不过建立连接后占用的通道即使不传输数据其他人也无法使用，通路一直占用，效率低，利用率低\n分组交换适合突发情况，不需要建立连接和用完的断开连接的善后操作，效率高，不过可能出现拥塞和延迟', 1, 0, 4, '2026-01-05 11:03:22', '2026-01-05 11:03:22');
INSERT INTO `daming_question` VALUES (184, 3, 286, 'arp——address resolution protocol，地址解析协议，将IP地址解析为mac地址\n工作过程：广播arp请求，目标主机响应arp请求，缓存arp表项', 1, 0, 4, '2026-01-05 11:06:01', '2026-01-05 11:06:01');
INSERT INTO `daming_question` VALUES (185, 3, 287, 'nat——network address translation  网络地址转换\n将内网ip转为公网ip，有静态nat，动态nat，和pat端口地址转换', 1, 0, 4, '2026-01-05 11:08:12', '2026-01-05 11:08:12');
INSERT INTO `daming_question` VALUES (186, 3, 288, '1.get方法用于资源的获取，post方法用于提交数据\n2.get具有幂等性，post不具有幂等性\n3.get参数在url里，post参数在请求体里\n4.get可以缓存，post不可缓存', 1, 0, 4, '2026-01-05 11:11:19', '2026-01-05 11:11:19');
INSERT INTO `daming_question` VALUES (187, 3, 289, '基本功能有，访问控制，日志记录，网络地址转换，入侵检测\n分类有包过滤防火墙，状态检测防火墙，应用网关防火墙', 1, 0, 4, '2026-01-05 11:39:51', '2026-01-05 11:39:51');
