INSERT INTO `daming_question` VALUES (260, 3, 365, '互斥,请求和保持,循环等待,不可剥夺', 1, 0, 5, '2026-01-15 11:27:00', '2026-01-15 11:27:00');
INSERT INTO `daming_question` VALUES (261, 3, 366, '<p>预防、避免、检测、解除死锁</p><p><strong>育碧简介</strong></p>', 1, 0, 5, '2026-01-15 11:30:10', '2026-01-15 11:30:10');
