INSERT INTO `daming_question` VALUES (264, 3, 369, '<p>:<strong><u>一类是有结构文件，称为记录文件</u></strong>;<strong><u>另一个是无结构文件，称为流式文件</u></strong></p><p><br></p><p>记录/流式</p>', 1, 0, 5, '2026-01-15 11:56:51', '2026-01-15 11:56:51');
