INSERT INTO `daming_question` VALUES (267, 3, 373, '<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>', 1, 0, 3, '2026-01-15 15:19:10', '2026-01-15 15:19:10');
INSERT INTO `daming_question` VALUES (268, 3, 374, '**减少命中时间**\n\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\n\n2.使对cache访问流水化并行处理\n\n**降低不命中率**\n\n1.增加cache的容量或cache块大小\n\n2.采用组相联映射\n\n**减少不命中开销**\n\n1.使用两级cache\n\n2.让读不命中优先于写', 1, 0, 3, '2026-01-15 15:53:41', '2026-01-15 15:53:41');
INSERT INTO `daming_question` VALUES (269, 3, 375, '1.**译码难**：变长指令，格式复杂\n\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\n\n3.**流水线难**：CPI差异大，流水线频繁阻塞\n\n4.**访存频繁**：支持复杂的访存指令，但受限于内存\n\n5.**功耗大**：芯片控制逻辑复杂且面积大发热高', 1, 0, 3, '2026-01-15 16:02:24', '2026-01-15 16:02:24');
INSERT INTO `daming_question` VALUES (270, 5, 376, '堆栈,累加器,通用寄存器组', 1, 0, 3, '2026-01-15 16:06:39', '2026-01-15 16:06:39');
INSERT INTO `daming_question` VALUES (271, 1, 377, 'D', 1, 0, 3, '2026-01-15 16:07:44', '2026-01-15 16:07:44');
INSERT INTO `daming_question` VALUES (272, 5, 378, '细分瓶颈段,重复设置瓶颈段', 1, 0, 3, '2026-01-15 16:16:26', '2026-01-15 16:16:26');
