INSERT INTO `daming_question_answer` VALUES (2375, 'wx_twODT_RY', 97, 319, '<p>172.16.1.88要从172.16.1.0接口转发，因为开头是172.16.1，下一跳直接交付，接口是E0</p><p>172.16.2.200要从172.16.2.0接口转发，因为开头是172.16.2，下一跳是172.16.1.2，接口是E0</p><p>192.168.0.0要从192.168.0.1接口转发，因为开头是192.168.0，下一跳是192.168.0.1，接口是S0</p><p>10.10.10.10没有对应的接口，所以目的网络是0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p><span style=\"color: rgb(36, 41, 46);\">8.8.4.4</span>没有对应的接口，所以目的网络是0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p><br></p>', '2026-01-06 10:37:11', 3, 188, 4, 0, 1, 0, 17, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2376, 'wx_twODT_RY', 97, 319, '<p>172.16.1.88要从172.16.1.0接口转发，因为开头是172.16.1，下一跳直接交付，接口是E0</p><p>172.16.2.200要从172.16.2.0接口转发，因为开头是172.16.2，下一跳是172.16.1.2，接口是E0</p><p>192.168.0.0要从192.168.0.1接口转发，因为开头是192.168.0，下一跳是192.168.0.1，接口是S0</p><p>10.10.10.10没有对应的接口，所以目的网络是0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p><span style=\"color: rgb(36, 41, 46);\">8.8.4.4</span>没有对应的接口，所以目的网络是0.0.0.0，下一跳是203.100.50.1，接口是S1</p>', '2026-01-06 10:37:11', 3, 174, 4, 0, 1, 0, 18, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2377, 'wx_twODT_RY', 97, 319, '<p>TCP面向连接，可靠，面向字节流，首部20字节，幂</p><p>UDP无连接，不可靠，面向报文，首部8字节，非幂</p>', '2026-01-06 10:37:11', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2378, 'wx_twODT_RY', 97, 319, '<p>OSI七层模型的应用层、会话层是TCP/IP的应用层</p><p>OSI七层模型的运输层是TCP/IP的运输层</p><p>OSI七层模型的网络层是TCP/IP的网络层</p><p>OSI七层模型的数据链路层、物理层是TCP/IP的网络接口层</p>', '2026-01-06 10:37:11', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2379, 'wx_twODT_RY', 97, 319, '<p>分组交换：共享资源，效率高，资源利用率高</p><p>电路交换：独占资源，效率低，资源浪费</p>', '2026-01-06 10:37:11', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2380, 'wx_twODT_RY', 97, 319, '<p>CSMA/CD的工作过程：发前先听，边法边听，冲突停止，随机重传</p><p>适用场景：</p>', '2026-01-06 10:37:11', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2381, 'wx_twODT_RY', 97, 319, '<p>NAT是网络地址转换，将私有IP转换为公有IP，工作原理是内网访问外网的时候，NAT替换内网的IP和端口，NAT有内部网关协议和外部网关协议</p>', '2026-01-06 10:37:11', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2382, 'wx_twODT_RY', 97, 319, '<p>GET：向服务器获取数据，GET的参数在URL中</p><p>POST:向服务器提交数据，参数在请求体中</p>', '2026-01-06 10:37:11', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2383, 'wx_twODT_RY', 97, 319, '<p>DNS的递归查询：客户端向本地DNS请求，DNS逐级查询并返回结果</p><p>迭代查询：本地DNS向根域名服务器请求，根返回下一级服务器地址，DNS找到下一级服务器</p>', '2026-01-06 10:37:11', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2384, 'wx_twODT_RY', 97, 319, '<p>ARP协议的作用：将IP地址转换成MAC地址</p><p>工作过程：广播ARP地址，主机回复ARP，ARP缓存</p>', '2026-01-06 10:37:11', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2385, 'wx_twODT_RY', 97, 319, '<p>防火墙的基本功能：入侵检测</p><p>分类：包过滤防火墙、状态检测防火墙、应用类别防火墙</p>', '2026-01-06 10:37:11', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
