INSERT INTO `daming_question_answer` VALUES (2431, 'wx_twODT_RY', 97, 321, '<p>目的IP是172.16.1.88，与第一条目的网络（172.16.1.0）匹配，下一跳是直接交付，通过E0接口转发</p><p>目的IP是172.16.2.0，与第二条目的网络（172.16.2.0）匹配，下一跳是172.16.1.2，通过E0接口转发</p><p>目的网络是192.168.0.10，与第三条目的网络（192.168.0.0）匹配，下一跳是192.168.0.1，通过S0端口转发</p><p>目的网络是10.10.10.10，没有匹配的目的网络，匹配0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p>目的网络是8.8.4.4，没有匹配的目的网络，匹配0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p><br></p>', '2026-01-06 11:15:36', 3, 188, 4, 1, 1, 0, 17, 2, '太对了兄弟，我直接把这宝贵的一分给你');
INSERT INTO `daming_question_answer` VALUES (2432, 'wx_twODT_RY', 97, 321, '<p>目的IP是172.16.1.88，与第一条目的网络（172.16.1.0）匹配，下一跳是直接交付，通过E0接口转发</p><p><br></p><p>目的IP是172.16.2.0，与第二条目的网络（172.16.2.0）匹配，下一跳是172.16.1.2，通过E0接口转发</p><p><br></p><p>目的网络是192.168.0.10，与第三条目的网络（192.168.0.0）匹配，下一跳是192.168.0.1，通过S0端口转发</p><p><br></p><p>目的网络是10.10.10.10，没有匹配的目的网络，匹配0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p><br></p><p>目的网络是8.8.4.4，没有匹配的目的网络，匹配0.0.0.0，下一跳是203.100.50.1，接口是S1</p>', '2026-01-06 11:15:36', 3, 174, 4, 1, 1, 0, 18, 2, '屌爆了这都会，期末考包高分过的兄弟');
INSERT INTO `daming_question_answer` VALUES (2433, 'wx_twODT_RY', 97, 321, '<p>TCP面向连接，可靠，面向字节流，有流量控制和拥塞控制，首部较大，有20字节</p><p>UDP无连接，不可靠，面向报文，没有流量控制和拥塞控制，首部较小，只有8字节</p>', '2026-01-06 11:15:36', 3, 172, 4, 1, 1, 0, 19, 2, '666');
INSERT INTO `daming_question_answer` VALUES (2434, 'wx_twODT_RY', 97, 321, '<p>OSI七层模型的应用层、表示层、会话层是TCP/IP四层模型的应用层</p><p>OSI七层模型的传输层是TCP/IP四层模型的传输层</p><p>OSI七层模型的网络层是TCP/IP四层模型的网络层</p><p>OSI七层模型的数据链路层、物理层是TCP/IP四层模型的网络接口层</p>', '2026-01-06 11:15:36', 3, 170, 4, 1, 1, 0, 20, 2, '666');
INSERT INTO `daming_question_answer` VALUES (2435, 'wx_twODT_RY', 97, 321, '<p>分组交换：建立连接，独占资源，适用实时数据，效率低，资源浪费</p><p>电路交换：存储转发，共享资源，适用突发数据，效率高，但可能会拥塞和延迟</p>', '2026-01-06 11:15:36', 3, 183, 4, 1, 1, 0, 21, 2, '666');
INSERT INTO `daming_question_answer` VALUES (2436, 'wx_twODT_RY', 97, 321, '<p>CSMA/CD协议的工作过程：先发后听，边发边听，冲突停止，随机重发</p><p>适用场景：共享式以太网（有限局域网）</p>', '2026-01-06 11:15:36', 3, 171, 4, 1, 1, 0, 22, 2, '6');
INSERT INTO `daming_question_answer` VALUES (2437, 'wx_twODT_RY', 97, 321, '<p>NAT：网络地址转换，将私有IP转换为公有IP</p><p>工作原理：内网主机访问外网时，NAT路由器替换内网主机的源IP和端口</p><p>类型：静态NAT、动态NAT、RAT</p>', '2026-01-06 11:15:36', 3, 185, 4, 1, 1, 0, 23, 2, '666');
INSERT INTO `daming_question_answer` VALUES (2438, 'wx_twODT_RY', 97, 321, '<p>GET：向服务器获取资源，GET的参数在URL中，幂</p><p>POST：向服务器请求数据，GET的参数在请求体中，非幂</p>', '2026-01-06 11:15:36', 3, 186, 4, 1, 1, 0, 24, 2, '6');
INSERT INTO `daming_question_answer` VALUES (2439, 'wx_twODT_RY', 97, 321, '<p>递归查询：客户端向本地DNS查询，本地DMS逐级查询并返回最终结果</p><p>迭代查询：本地DNS向根域名服务器发出请求，根返回下一级服务器的地址，本地DNS继续向下一级查询，逐级递减</p>', '2026-01-06 11:15:36', 3, 173, 4, 1, 1, 0, 25, 2, '666666');
INSERT INTO `daming_question_answer` VALUES (2440, 'wx_twODT_RY', 97, 321, '<p>ARP协议的作用：将IP地址翻译成MAC地址</p><p>工作过程：广播ARP请求，目标主机回复ARP，缓存ARP表项</p>', '2026-01-06 11:15:36', 3, 184, 4, 1, 1, 0, 26, 2, '6');
INSERT INTO `daming_question_answer` VALUES (2441, 'wx_twODT_RY', 97, 321, '<p>防火墙基本功能：网络地址转换、入侵检测</p><p>分类：包过滤防火墙、状态检测防火墙、应用网关防火墙</p>', '2026-01-06 11:15:36', 3, 187, 4, 1, 1, 0, 27, 2, '66666');
