INSERT INTO `daming_question_answer` VALUES (2657, '8888', 97, 329, '<p>TCP面向连接，而且可靠，只能一对一，且有流量控制和拥塞避免；UDP面向无连接，不可靠，可以一对一、一对多、多对一、多对多，无流量控制和拥塞避免</p>', '2026-01-07 22:17:25', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2658, '8888', 97, 329, '<p>OSI 七层 模型中的应用层、会话层、表示层 对应 TCP/IP模型中的 应用层</p><p>OSI 七层模型的数据链路层、物理层 对应 TCP/IP模型中的网络接口层 ，总体而言上三合一，下二合一</p>', '2026-01-07 22:17:25', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2659, '8888', 97, 329, '<p>电路交换在通信前，必须在发送端和接收端间建立专用的物理通路，特点是独占资源，顺序传输，优点是低延迟，抖动小，缺点是利用率低</p><p>分组交换将数据拆分成一个短小的分组，每个分组独立选择路由进行存储转发，特点是动态分配资源，逐段转发，优点是利用率高，灵活，缺点是延迟高，会丢包</p>', '2026-01-07 22:17:25', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2660, '8888', 97, 329, '<p>工作过程：先听后发，边听边发，冲突停止，随机重发</p><p>适用场景：共享式以太网</p>', '2026-01-07 22:17:25', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2661, '8888', 97, 329, '<p>NAT是网络地址转换，是解决公网IP地址资源不足的技术，实现了私有IP转换成公网IP</p><p>工作原理是源私有IP替换为公网IP</p><p>类型有静态NAT、动态NAT、PAT</p>', '2026-01-07 22:17:25', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2662, '8888', 97, 329, '<p>GET是请求URL标志的文档，参数附在URL后面，并且是明文传输</p><p>POST是向服务器发送数据，参数放在请求体中，相对更安全</p>', '2026-01-07 22:17:25', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2663, '8888', 97, 329, '<p>递归查询是主机向本地域名服务器的查询，迭代查询是本地域名服务器向根域名服务器进行循环查询</p>', '2026-01-07 22:17:25', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2664, '8888', 97, 329, '<p>ARP是地址解析协议，是TCP/IP协议中数据链路层和网络层之间的核心协议</p><p>ARP可以实现IP地址到MAC地址的映射转换，通过广播请求到单播响应，最后到缓存映射</p>', '2026-01-07 22:17:25', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2665, '8888', 97, 329, '<p>基本功能为访问控制、数据包过滤、NAT转换、日志审计、基础攻击防护</p><p>按技术分为包过滤、状态检测、应用代理</p><p>按部署位置分为边界防火墙、内网防火墙</p>', '2026-01-07 22:17:25', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2666, '1235467890', 97, 330, '基于端口,基于MAC地址,基于IP子网', '2026-01-07 22:54:48', 5, 182, 4, 1, 1, 1, 0, 2, NULL);
