INSERT INTO `daming_question_answer` VALUES (2825, '8888', 97, 335, '<p>TCP面向连接，是可靠的，只能一对一连接，TCP有流量控制和拥塞避免</p><p>UDP面向无连接的，是不可靠的，可以一对一、一对多、多对一、多对多，没有流量控制和拥塞避免</p>', '2026-01-08 22:15:16', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2826, '8888', 97, 335, '<p>OSI 七层模型中的应用层、会话层、表示层 对应 TCP/IP 四层模型中的应用层</p><p>OSI 七层模型中的数据链路层、物理层 对应 TCP/IP 四层模型中的网络接口层</p><p>总体来说上三合一，下二合一</p>', '2026-01-08 22:15:16', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2827, '8888', 97, 335, '<p>电路交换在通信前，要在发送端和接收端间建立专用的物理通道，特点是独占资源、顺序传输，优点是低延迟，抖动小，缺点是利用率低</p><p>分组交换是将数据拆分成一个较小的分组，每个分组各自选择路由协议进行存储转发，特点是动态分配资源、逐段转发，优点是利用率高，灵活，缺点是高延迟，会丢包</p>', '2026-01-08 22:15:16', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2828, '8888', 97, 335, '<p>工作过程：先来后发，边发边听，冲突停止，随机重发</p><p>使用场景是共享式以太网</p>', '2026-01-08 22:15:16', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2829, '8888', 97, 335, '<p>NAT是地址转换协议，解决了公网IP地址资源不足的问题</p><p>工作原理是将源私有IP替换成公网IP</p><p>类型有动态NAT、静态NAT、PAT</p>', '2026-01-08 22:15:16', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2830, '8888', 97, 335, '<p>GET是请求URL标志的文档，参数附在URL后面，明文传输，安全性低</p><p>POST是向服务器请求数据，参数放在请求体中，较为安全</p>', '2026-01-08 22:15:16', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2831, '8888', 97, 335, '<p>递归查询是主机向本地域名服务器发起查询，完成域名到IP的映射；迭代查询是本地域名服务器向根域名服务器进行循环查询</p>', '2026-01-08 22:15:16', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2832, '8888', 97, 335, '<p>ARP是地址解析协议，是TCP/IP 协议中数据链路层和网络层之间核心的协议</p><p>ARP可以实现IP到MAC地址的映射转换</p><p>工作过程广播请求、单播响应、缓存映射</p>', '2026-01-08 22:15:16', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2833, '8888', 97, 335, '<p>基本功能：访问控制、数据包过滤、NAT转换、日志审计、基础防护攻击</p><p>按技术分类：包过滤、状态检测、应用代理</p><p>按部署位置分类：边界防火墙、内网防火墙</p><p><br></p>', '2026-01-08 22:15:16', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
