INSERT INTO `daming_question_answer` VALUES (2935, '8888', 97, 339, '未填', '2026-01-10 21:36:49', 3, 188, 4, 0, 1, 0, 17, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2936, '8888', 97, 339, '未填', '2026-01-10 21:36:49', 3, 174, 4, 0, 1, 0, 18, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2937, '8888', 97, 339, '<p>TCP是面向连接的，可靠的，只能一对一连接，有流量控制和拥塞避免</p><p>UDP是面向无连接的，不可靠的，可以一对一、一对多、多对一、多对多连接，无流量控制和拥塞避免</p>', '2026-01-10 21:36:49', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2938, '8888', 97, 339, '<p>OSI 七层模型中的应用层、会话层、表示层 对应 TCP/IP四层模型 中的 应用层</p><p>OSI 七层模型中的数据链路层、物理层 对应 TCP/IP 四层模型中的网络接口层	</p>', '2026-01-10 21:36:49', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2939, '8888', 97, 339, '<p>电路交换在通信前，在发送端和接收端间建立专用的物理通路，特点是独占资源，顺序传输，优点是低时延，抖动小，缺点是利用率低</p><p>分组交换是将数据拆分成一个较小的分组，每个分组各自选择路由协议进行存储转发，特点是动态资源分配、逐段转发，优点是利用率高、灵活，缺点是高时延，会丢包	</p><p><br></p>', '2026-01-10 21:36:49', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2940, '8888', 97, 339, '<p>工作过程：先来宪发，边发边听，冲突停止，随机重发</p><p>适用场景：共享式以太网</p>', '2026-01-10 21:36:49', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2941, '8888', 97, 339, '<p>NAT是地址转换协议，解决了公网IP地址资源不足的技术问题</p><p>工作原理是源私有IP替换成公网IP</p><p>类型：动态NAT、静态NAT、PAT</p>', '2026-01-10 21:36:49', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2942, '8888', 97, 339, '<p>GET是请求URL标志的文档，参数附在URL后面，以明文传输，安全性低</p><p>POST是向服务器请求数据，参数放在请求体中，较为安全</p>', '2026-01-10 21:36:49', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2943, '8888', 97, 339, '<p>递归查询是主机向本地域名服务器发起查询，DNS将域名映射到IP</p><p>迭代查询是本地域名服务器向根域名服务器进行循环查询</p>', '2026-01-10 21:36:49', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2944, '8888', 97, 339, '<p>ARP是地址解析协议，是TCP/IP 协议中数据链路层和网络层间的核心协议</p><p>作用是IP地址到MAC地址间的映射转换</p><p>工作过程是请求广播，单播响应，缓存映射	</p>', '2026-01-10 21:36:49', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2945, '8888', 97, 339, '<p>基本功能：访问控制、数据包过滤、NAT转换、日志审计、基础防护攻击</p><p>按技术分类：包过滤、状态检测、应用代理</p><p>按部署位置分类：边界防火墙、内网防火墙</p>', '2026-01-10 21:36:49', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2946, 'wx_twODT_RY', 97, 340, '基于端口,基于MAC地址,基于IP子网', '2026-01-11 00:12:53', 5, 182, 4, 1, 1, 1, 0, 2, NULL);
INSERT INTO `daming_question_answer` VALUES (2947, 'wx_twODT_RY', 97, 340, '慢启动,拥塞避免,快速重传,快速恢复', '2026-01-11 00:12:53', 5, 179, 4, 1, 1, 1, 1, 2, NULL);
