INSERT INTO `daming_question_answer` VALUES (2963, 'wx_twODT_RY', 97, 340, '<p>目的 IP：172.16.1.88，与第一条端口<span style=\"color: rgb(36, 41, 46);\">172.16.1.0相匹配，为直接交付，接口是E0</span></p><p>目的 IP：172.16.2.200，与第二条端口172.16.2.0<span style=\"color: rgb(36, 41, 46);\">相匹配，下一跳是172.16.1.2，接口是E0</span></p><p>目的 IP：192.168.0.10，与第三条端口192.168.0.0<span style=\"color: rgb(36, 41, 46);\">相匹配，下一跳是</span>192.168.0.1<span style=\"color: rgb(36, 41, 46);\">，接口是S0</span></p><p>目的 IP：<span style=\"color: rgb(36, 41, 46);\">10.10.10.10</span>，与前三条端口都不匹配<span style=\"color: rgb(36, 41, 46);\">，匹配</span>默认路由0.0.0.0，<span style=\"color: rgb(36, 41, 46);\">下一跳是203.100.50.1，接口是S1</span></p><p>目的 IP：<span style=\"color: rgb(36, 41, 46);\">8.8.4.4</span>，与前三条端口都不匹配<span style=\"color: rgb(36, 41, 46);\">，匹配</span>默认路由0.0.0.0，<span style=\"color: rgb(36, 41, 46);\">下一跳是203.100.50.1，接口是S1</span></p>', '2026-01-11 00:12:53', 3, 188, 4, 0, 1, 0, 17, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2964, 'wx_twODT_RY', 97, 340, '<p>目的 IP：172.16.1.88，与第一条端口172.16.1.0相匹配，为直接交付，接口是E0</p><p><br></p><p>目的 IP：172.16.2.200，与第二条端口172.16.2.0相匹配，下一跳是172.16.1.2，接口是E0</p><p><br></p><p>目的 IP：192.168.0.10，与第三条端口192.168.0.0相匹配，下一跳是192.168.0.1，接口是S0</p><p><br></p><p>目的 IP：10.10.10.10，与前三条端口都不匹配，匹配默认路由0.0.0.0，下一跳是203.100.50.1，接口是S1</p><p><br></p><p>目的 IP：8.8.4.4，与前三条端口都不匹配，匹配默认路由0.0.0.0，下一跳是203.100.50.1，接口是S1</p>', '2026-01-11 00:12:53', 3, 174, 4, 0, 1, 0, 18, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2965, 'wx_twODT_RY', 97, 340, '<p>TCP：面向连接，可靠，面向报文，首部较大有20字节</p><p>UDP：无连接，不可靠，面向报文段，首部只有8字节</p>', '2026-01-11 00:12:53', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2966, 'wx_twODT_RY', 97, 340, '<p>0SI七层模型的应用层/会话层/表示层是TCP/IP四层模型的应用层</p><p>0SI七层模型的网络层是TCP/IP四层模型的网络层</p><p>0SI七层模型的传输层是TCP/IP四层模型的传输层</p><p>0SI七层模型的物理链路层、物理层是TCP/IP四层模型的网络接口层</p>', '2026-01-11 00:12:53', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2967, 'wx_twODT_RY', 97, 340, '<p>电路交换：建立连接，独占资源，适合实时通信，效率低，资源浪费</p><p>分组交换：存储转发，共享资源，适合突发数据，效率高，但可能拥塞或延迟</p>', '2026-01-11 00:12:53', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2968, 'wx_twODT_RY', 97, 340, '<p>CSMA/CD协议的工作过程：先听后发，边发边听，冲突停止，随机重发</p><p>适用场景：共享式以太网（有线局域网）</p>', '2026-01-11 00:12:53', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2969, 'wx_twODT_RY', 97, 340, '<p>NAT：网络地址转换，可以将私有IP转换为公有IP</p><p>工作原理：内网主机访问外网时，NAT路由器替换内网的源IP和端口</p><p>类型：静态NAT、动态NAT、PAT</p>', '2026-01-11 00:12:53', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2970, 'wx_twODT_RY', 97, 340, '<p>GET：向服务器获取数据，参数在URL中，可缓存，幂</p><p>POST：向服务器提交数据，参数在请求体中，不可缓存，非幂</p>', '2026-01-11 00:12:53', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2971, 'wx_twODT_RY', 97, 340, '<p>递归查询：客户端向本地DNS发出请求，本地DNS逐级查询并返回结果</p><p>迭代查询：本地DNS向根域名服务器发出请求，根返回下一级服务器地址，本地DNS逐级迭代查询，向下一级服务器查询并返回结果</p>', '2026-01-11 00:12:53', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2972, 'wx_twODT_RY', 97, 340, '<p>ARP协议：将IP地址转换为MAC地址</p><p>工作过程：ARP发出请求，目标主机回复ARP，缓存ARP表项</p>', '2026-01-11 00:12:53', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (2973, 'wx_twODT_RY', 97, 340, '<p>防火墙的基本功能：入侵检测、访问控制、日志记录、网络地址转换</p><p>分类：包过滤防火墙、状态检测防火墙、应用网关防火墙</p>', '2026-01-11 00:12:53', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
