INSERT INTO `daming_question_answer` VALUES (3105, '8888', 97, 345, '<p>TCP面向连接，是可靠的，只能一对一连接，TCP有流量控制和拥塞控制</p><p>UDP面向无连接的，是不可靠的，支持一对一、一对多、多对一、多对多连接，无流量控制和拥塞控制</p><p><br></p>', '2026-01-11 23:23:15', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3106, '8888', 97, 345, '<p>OSI 七层模型中的应用层、会话层、表示层 对应TCP/IP四层模型中的 应用层</p><p>OSI七层模型中的 数据链路层、物理层 对应TCP/IP 四层模型中的网络接口层</p>', '2026-01-11 23:23:15', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3107, '8888', 97, 345, '<p>电路交换在通信前，要在发送端和接收端间建立专用的物理通道，特点是独占资源、顺序传输，优点是低时延，抖动小，缺点是利用率低</p><p>分组交换是将数据拆分成一个较小的分组，每个分组各自选择路由协议进行存储转发，特点是动态资源分配、逐段转发，优点是利用率高，灵活，缺点是高时延，会丢包</p>', '2026-01-11 23:23:15', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3108, '8888', 97, 345, '<p>工作过程：先来先发，边发边听，冲突停止，随机重发</p><p>适用场景：共享式以太网	</p>', '2026-01-11 23:23:15', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3109, '8888', 97, 345, '<p>NAT是地址转换协议，是解决了公网IP地址资源不足的技术</p><p>工作原理是源私有IP替换成公网IP</p><p>类型有动态NAT、静态NAT、PAT</p>', '2026-01-11 23:23:15', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3110, '8888', 97, 345, '<p>GET是请求URL标志的文档，参数附在URL后面，参数以明文传输，安全性低</p><p>POST是向服务器请求数据，参数放在请求体中，较为安全</p>', '2026-01-11 23:23:15', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3111, '8888', 97, 345, '<p>递归查询是主机向本地域名服务器发起查询，使得DNS协议映射域名到IP地址</p><p>迭代查询是本地域名服务器向根域名服务器进行循环查询</p>', '2026-01-11 23:23:15', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3112, '8888', 97, 345, '<p>ARP是地址解析协议，是TCP/IP 协议中数据链路层、网络层间的核心协议</p><p>作用是IP地址到MAC地址的映射转换</p><p>工作过程是请求广播、单播响应、缓存映射</p>', '2026-01-11 23:23:15', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3113, '8888', 97, 345, '<p>基本功能：访问控制、数据包过滤、NAT转换、日志审计、基础攻击防护</p><p>按技术分类：包过滤、状态检测、应用代理</p><p>按部署分类：边界防火墙、内网防火墙</p>', '2026-01-11 23:23:15', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3114, 'jackson', 97, 346, '未填', '2026-01-12 00:29:48', 5, 182, 4, 0, 1, 0, 0, 2, NULL);
INSERT INTO `daming_question_answer` VALUES (3115, 'jackson', 97, 346, '慢启动,拥挤避免,快速恢复,快速重传', '2026-01-12 00:29:48', 5, 179, 4, 0, 1, 0, 1, 2, NULL);
