INSERT INTO `daming_question_answer` VALUES (3216, 'wx_Aaov5Wkk', 97, 349, '未填', '2026-01-12 13:02:32', 3, 174, 4, 0, 1, 0, 18, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3217, 'wx_Aaov5Wkk', 97, 349, '<p>TCP面向连接。UDP无连接；</p><p>TCP可靠，UDP不可靠</p><p>TCP有流量控制和拥塞控制，UDP</p><p>TCP面向字节流	UDP面向报文</p><p>TCP首部较大	UDP首部较小</p>', '2026-01-12 13:02:32', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3218, 'wx_Aaov5Wkk', 97, 349, '<p>OSI应用层、表示层、会话层 对应 TCP/IP 应用层</p><p>OSI传输层 对应 TCP/IP传输层</p><p>OSI网络层 对应 TCP/IP网络层</p><p>OSI数据链路层、物理层 对应 tcp/IP 网络接口层</p>', '2026-01-12 13:02:32', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3219, 'wx_Aaov5Wkk', 97, 349, '<p>电路交换：建立连接、独占资源、适合实时通信；效率低、资源浪费</p><p>分组交换：存储转发、共享资源、适合突发数据；效率高，但可能拥塞和延迟</p>', '2026-01-12 13:02:32', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3220, 'wx_Aaov5Wkk', 97, 349, '<p>工作过程：先听后发、变法边听、冲突停止、随即重发。</p><p>使用场景：共享式以太网（有线局域网）</p>', '2026-01-12 13:02:32', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3221, 'wx_Aaov5Wkk', 97, 349, '<p>NAT：网络地址转换，将私有IP转换为公有IP</p><p>工作原理：内网主机访问外网时，NAT路由器替换源IP和端口</p><p>类型：静态NAT，动态NAT，PAT</p>', '2026-01-12 13:02:32', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3222, 'wx_Aaov5Wkk', 97, 349, '<p>GET：从服务器获取资源；参数在URL；可缓存；幂等；</p><p>POST：向服务器提交数据；在请求体中，一般不可缓存；非幂等。</p>', '2026-01-12 13:02:32', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3223, 'wx_Aaov5Wkk', 97, 349, '<p>递归查询：客户想本地DNS发送请求，本地DNS负责逐级查询并返回最终结果</p><p>迭代查询：本地DNS向根域名服务器查询，根返回下一级服务器地址，本地DNS再向下一级查询，一次迭代</p>', '2026-01-12 13:02:32', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3224, 'wx_Aaov5Wkk', 97, 349, '<p>作用：将IP地址解析为MAC地址</p><p>工作过程：广播ARP请求，目标主机回复ARP响应，缓存ARP表项</p>', '2026-01-12 13:02:32', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3225, 'wx_Aaov5Wkk', 97, 349, '<p>功能：访问控制，日志记录，网络地址转换、入侵检测；</p><p>分类：包过滤防火墙、状态检测防火墙、应用网关防火墙</p>', '2026-01-12 13:02:32', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
