INSERT INTO `daming_question_answer` VALUES (3329, '8888', 97, 353, '<p>TCP是面向连接的，是可靠的，只能一对一连接，TCP又流量控制和拥塞控制</p><p>UDP是面向无连接的，不可靠的，支持一对一、一对多、多对一、多对多连接，没有流量控制和拥塞控制</p>', '2026-01-12 20:40:36', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3330, '8888', 97, 353, '<p>OSI七层模型中的应用层、会话层、表示层 对应 TCP/IP四层模型中的应用层</p><p>OSI七层模型中的数据链路层、物理层 对应 TCP/IP四层模型中的网络接口层</p>', '2026-01-12 20:40:36', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3331, '8888', 97, 353, '<p>电路交换在通信前，必须在发送端和接收端间建立专用的物理通道，特点是独占资源、顺序传输，优点是低时延、抖动小，缺点是利用率低</p><p>分组交换是将数据拆分成一个较小的分组，每个分组各自选择路由协议进行存储转发，特点是动态分配资源、逐段转发，优点是利用率高、灵活，缺点是高时延、会丢包</p>', '2026-01-12 20:40:36', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3332, '8888', 97, 353, '<p>工作过程：先来先发、边发 边听、冲突停止、随机重发</p><p>适用场景：共享式以太网</p>', '2026-01-12 20:40:36', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3333, '8888', 97, 353, '<p>NAT是地址转换协议，是解决了公网IP地址资源不足的技术</p><p>工作原理是源私有IP替换成公网IP</p><p>类型有动态NAT、静态NAT、PAT</p>', '2026-01-12 20:40:36', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3334, '8888', 97, 353, '<p>GET是请求URL标志的文档，参数放在URL后，以明文传输，安全性低</p><p>POST是向服务器请求数据，参数放在请求体中，较为安全</p>', '2026-01-12 20:40:36', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3335, '8888', 97, 353, '<p>递归查询是主机向本地域名服务器发起查询，使得DNS域名系统映射出真实IP。</p><p>迭代查询是本地域名服务器向根域名服务器进行循环查询</p>', '2026-01-12 20:40:36', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3336, '8888', 97, 353, '<p>ARP是地址解析协议，是TCP/IP协议中数据链路层、网络层间的核心协议</p><p>作用是IP地址到MAC地址之间的映射转换</p><p>工作过程是请求广播、单播响应、缓存映射</p>', '2026-01-12 20:40:36', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3337, '8888', 97, 353, '<p>基本功能：访问控制、数据包过滤、NAT转换、日志审计、基础攻击防护</p><p>按技术分类：包过滤、状态检测、应用代理</p><p>按部署位置分: 边界防火墙、内网防火墙</p><p><br></p><p>什么是子网划分，作用是什么，举例说明</p><p>子网划分是将一个大的网络划分成较多的小的子网</p><p>作用是提高了IP地址的利用率，便于管理、增强安全性，减少广播域</p><p>比如192.168.1.0/24可划分为4个资源，每个子网容纳62台主机</p>', '2026-01-12 20:40:36', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3338, 'wx_a3PGqPlE', 97, 354, '基于端口,基于mac地址,基于ip子网', '2026-01-12 21:04:10', 5, 182, 4, 1, 1, 1, 0, 2, NULL);
