INSERT INTO `daming_question_answer` VALUES (3637, '123123', 97, 364, '<p>TCP 面向接口，可靠，支持流量控制和拥塞控制，面向字节流，首部较大占20字节</p><p>UDP 无接口，不可靠，不支持流量控制和拥塞控制，面向报文，首部较小占8字节</p>', '2026-01-12 23:32:44', 3, 172, 4, 0, 1, 0, 19, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3638, '123123', 97, 364, '<p>OSI 应用层、表示层、会话层；TCP 应用层</p><p>网络层 = 网络层</p><p>传输层 = 传输层</p><p>数据链路层、物理层 = 网络接口层</p>', '2026-01-12 23:32:44', 3, 170, 4, 0, 1, 0, 20, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3639, '123123', 97, 364, '<p>电路交换：建立连接、独享资源，适合实时通信；效率低，资源浪费</p><p>分组交换：存储转发、共享资源，适合突发数据；效率高，但可能导致拥塞和延迟；</p>', '2026-01-12 23:32:44', 3, 183, 4, 0, 1, 0, 21, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3640, '123123', 97, 364, '<p>工作过程：先听后发、边发边听、冲突中断、随机重发</p><p>适用场景：有线局域网</p>', '2026-01-12 23:32:44', 3, 171, 4, 0, 1, 0, 22, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3641, '123123', 97, 364, '<p>工作原理：网络地址转化，核心是将私有IP转化为共有IP</p><p>类型：静态NAT，动态NAT，PAT</p>', '2026-01-12 23:32:44', 3, 185, 4, 0, 1, 0, 23, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3642, '123123', 97, 364, '<p>GET：获取数据，参数在URL地址上，可缓存，是幂等的</p><p>POST：提交数据，参数在请求体上，不可缓存，不是幂等的</p>', '2026-01-12 23:32:44', 3, 186, 4, 0, 1, 0, 24, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3643, '123123', 97, 364, '<p>递归查询：客户端向本地DNS发送请求，本地DNS进行逐级查询并返回最终结果</p><p>迭代查询：本地DNS向根域名服务器查询，根域名返回下一级服务器地址，本地DNS再向下一级查询，依次迭代</p>', '2026-01-12 23:32:44', 3, 173, 4, 0, 1, 0, 25, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3644, '123123', 97, 364, '<p>作业：将IP地址解析为MAC地址</p><p>工作过程：广播发送 ARP请求，目标主机回复ARP响应，缓存ARP表项</p>', '2026-01-12 23:32:44', 3, 184, 4, 0, 1, 0, 26, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (3645, '123123', 97, 364, '<p>基本功能：访问控制、日志记录、网络地址转接、入侵检测等</p><p>分类：过滤防火墙、状态检测防火墙、应用网关防火墙</p>', '2026-01-12 23:32:44', 3, 187, 4, 0, 1, 0, 27, 1, NULL);
