INSERT INTO `daming_question_answer` VALUES (5111, '100547sad', 99, 399, '<p>1.不具有交互性，利用率高，吞吐量高</p><p>2.多用户时间片轮转，交互性好</p><p>3.相应及时，可靠性高，资源利用率低</p>', '2026-01-15 21:12:37', 3, 254, 5, 0, 1, 0, 0, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5112, '100547sad', 99, 399, '<p>一次仅一个进程使用的资源</p>', '2026-01-15 21:12:37', 3, 257, 5, 0, 1, 0, 1, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5113, '100547sad', 99, 399, '<p>进程中访问临界资源的那段程序</p>', '2026-01-15 21:12:37', 3, 258, 5, 0, 1, 0, 2, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5114, '100547sad', 99, 399, '<p>这组进程的所有程序都在等待其他程序释放资源而不能自己释放资源，处于资源拿到了，但是没有完全拿到的僵局。</p>', '2026-01-15 21:12:37', 3, 259, 5, 0, 1, 0, 3, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5115, '100547sad', 99, 399, '<p>互斥、循环等待，占用等待，非抢占性</p>', '2026-01-15 21:12:37', 3, 260, 5, 0, 1, 0, 4, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5116, '100547sad', 99, 399, '<p>预防死锁，避免，检测，解除</p>', '2026-01-15 21:12:37', 3, 261, 5, 0, 1, 0, 5, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5117, '100547sad', 99, 399, '<p>结构文件 ，一个记录以上构成，记录式文件，</p><p>无结果文件， 字符流构成   ，流式文件</p>', '2026-01-15 21:12:37', 3, 264, 5, 0, 1, 0, 6, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5118, '100547sad', 99, 399, '未填', '2026-01-15 21:12:37', 3, 265, 5, 0, 1, 0, 7, 1, NULL);
INSERT INTO `daming_question_answer` VALUES (5119, '100547sad', 99, 399, '<p>运行态，就绪态，阻塞态</p>', '2026-01-15 21:12:37', 3, 266, 5, 0, 1, 0, 8, 1, NULL);
