INSERT INTO `forum_post` VALUES (1, 1, 'admin', '管理员', 'https://cdn.zww0891.fun/northern-lights-6862969_1920.jpg', '欢迎来到刷题论坛！', '大家好，这里是刷题系统的论坛板块，欢迎大家交流学习心得、分享做题技巧！\n\n有任何问题都可以在这里发帖讨论哦～', NULL, 209, 25, 27, 1, 1, 1, '2025-11-23 22:08:18', '2026-02-04 10:57:56');
INSERT INTO `forum_post` VALUES (2, 1, 'admin', '管理员', 'https://cdn.zww0891.fun/northern-lights-6862969_1920.jpg', '如何高效刷题？分享我的经验', '经过一段时间的刷题，我总结了一些经验：\n\n1. **制定计划**：每天固定时间刷题，养成习惯\n2. **循序渐进**：从简单到困难，逐步提升\n3. **总结归纳**：做完题要总结知识点\n4. **温故知新**：定期复习做过的题\n\n大家有什么好的方法也可以分享！', NULL, 95, 15, 1, 0, 1, 1, '2025-11-23 22:08:18', '2026-01-08 22:48:33');
INSERT INTO `forum_post` VALUES (3, 1, 'admin', '管理员', 'https://cdn.zww0891.fun/northern-lights-6862969_1920.jpg', '计算机组成原理重点知识点整理', '最近在复习计组，整理了一些重点：\n\n## 1. 冯·诺依曼结构\n- 存储程序工作方式\n- 五大组成部分\n\n## 2. 存储系统\n- Cache映射方式\n- 虚拟存储\n\n希望对大家有帮助！', NULL, 57, 10, 0, 0, 0, 1, '2025-11-23 22:08:18', '2026-01-08 22:48:35');
INSERT INTO `forum_post` VALUES (4, 3, 'zww2', '6666', '', '测试测试测试测试测试', '测试测试测试测试测试', '[\"https://daming-paper.oss-cn-guangzhou.aliyuncs.com/quiz/paper/answer/2025/11/23/e6149daf60b9488ca1c6c40b9c36991d.jpg\"]', 3, 0, 0, 0, 0, 0, '2025-11-23 22:08:59', '2025-11-24 15:58:13');
