INSERT INTO `sys_oper_log` VALUES (575, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"无\",\"correct\":\"C\",\"correctArray\":[],\"items\":[{\"content\":\"软件定义\",\"prefix\":\"A\"},{\"content\":\"软件开发\",\"prefix\":\"B\"},{\"content\":\"详细设计\",\"prefix\":\"C\"},{\"content\":\"软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\" 一般说来，软件生命周期由三个大的时期组成，不包括下面哪个时期\",\"questionType\":1,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-19 16:01:26', 155);
INSERT INTO `sys_oper_log` VALUES (576, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"<p>正确答案是&nbsp;C。</p><p>解题思路：</p><ol><li>A 选项（时间错误）：软件危机是在&nbsp;20世纪60年代末至70年代​ 全面爆发并被正式提出的，而不是“70年代末期”。这个时间点不准确。</li><li>B 选项（结论错误）：软件工程方法极大地缓解了软件危机，但并未“已经解决”它。随着技术发展，新的复杂性和挑战不断出现，软件危机在某种程度上以新的形式存在。</li><li><span style=\\\"color: rgb(102, 185, 102);\\\">C 选项</span>（定义正确）：这是对“软件危机”最经典和准确的定义，它准确地描述了软件危机是在软件开发和维护过程中遇到的一系列严重问题（如预算超支、进度延误、质量低下、难以维护等）。</li><li>D 选项（定义片面）：软件危机不仅仅是指软件产品本身的质量问题，它更是一个涵盖项目管理、开发过程、技术方法和维护等全过程的综合性问题。这个选项的定义过于狭隘。</li></ol><p>因此，只有&nbsp;C 选项的说法是完全正确的。</p>\",\"correct\":\"C\",\"correctArray\":[],\"items\":[{\"content\":\"软件危机在20世纪70年代末期全面爆发\",\"prefix\":\"A\"},{\"content\":\"前先进的软件工程方法已经解决了软件危机的问题\",\"prefix\":\"B\"},{\"content\":\"软件危机是指在软件开发和维护过程中所遇到的一系列严重问题\",\"prefix\":\"C\"},{\"content\":\"软件危机是指在软件产品中存在一系列的质量问题\",\"prefix\":\"D\"}],\"questionTitle\":\"下面的( )说法是正确的。\",\"questionType\":1,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-19 16:23:14', 11);
INSERT INTO `sys_oper_log` VALUES (577, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"<h3>解析：</h3><p>在软件生命周期的各个阶段中：</p><ul><li>D需求分析阶段：主要任务是确定软件系统要做什么，需要了解用户的需求并将其转化为系统的逻辑模型。数据流图（DFD- Data <span style=\\\"background-color: rgb(255, 255, 255); color: rgb(77, 77, 77);\\\">Flow&nbsp;Diagram</span>）是一种用于描述系统中数据流动和处理过程的图形化工具，它能够帮助分析人员清晰地展现系统的功能和数据关系，属于需求分析阶段的重要工作内容。</li><li>程序设计阶段：主要关注的是如何用具体的编程语言实现软件的功能，重点在于代码的编写，和数据流图这种需求级的建模工具无关。</li><li>详细设计阶段：侧重于对软件的模块内部结构、算法等进行详细的设计，通常使用流程图、伪代码等方式，而不是数据流图（数据流图更多是用于描述系统的整体逻辑功能，而非模块内部的详细设计）。</li><li>软件维护阶段：是对已经投入使用的软件进行修改、完善等工作，以适应新的需求或修复问题，和需求分析阶段的建模工作无关。</li></ul><p>所以画数据流图属于需求分析阶段的工作，答案为A。</p><p><br></p><p><img src=\\\"data:image/png;base64,', NULL, 1, '\r\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'content\' at row 1\r\n### The error may exist in file [E:\\区块链比赛\\区块链赛前B站笔记++++\\Spring系列\\个人项目实战\\刷题项目\\project\\daming-admin\\dm_questionBank\\target\\classes\\mapper\\quiz\\DamingContentInfoMapper.xml]\r\n### The error may involve com.dm.quiz.mapper.DamingContentInfoMapper.insertContentInfo-Inline\r\n### The error occurred while setting parameters\r\n### SQL: insert into daming_content_info          ( content )           values ( ? )\r\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'content\' at row 1\n; Data truncation: Data too long for column \'content\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'content\' at row 1', '2025-11-19 16:34:16', 490);
INSERT INTO `sys_oper_log` VALUES (578, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"<h3>解析：</h3><p>在软件生命周期的各个阶段中：</p><ul><li>D需求分析阶段：主要任务是确定软件系统要做什么，需要了解用户的需求并将其转化为系统的逻辑模型。数据流图（DFD- Data <span style=\\\"background-color: rgb(255, 255, 255); color: rgb(77, 77, 77);\\\">Flow&nbsp;Diagram</span>）是一种用于描述系统中数据流动和处理过程的图形化工具，它能够帮助分析人员清晰地展现系统的功能和数据关系，属于需求分析阶段的重要工作内容。</li><li>程序设计阶段：主要关注的是如何用具体的编程语言实现软件的功能，重点在于代码的编写，和数据流图这种需求级的建模工具无关。</li><li>详细设计阶段：侧重于对软件的模块内部结构、算法等进行详细的设计，通常使用流程图、伪代码等方式，而不是数据流图（数据流图更多是用于描述系统的整体逻辑功能，而非模块内部的详细设计）。</li><li>软件维护阶段：是对已经投入使用的软件进行修改、完善等工作，以适应新的需求或修复问题，和需求分析阶段的建模工作无关。</li></ul><p>所以画数据流图属于需求分析阶段的工作，答案为A。</p><p><br></p><p><img src=\\\"data:image/png;base64,', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-19 16:35:06', 67);
INSERT INTO `sys_oper_log` VALUES (579, '试卷', 1, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/paper', '127.0.0.1', '内网IP', '{\"enableAntiCheat\":false,\"paperName\":\"期中考试\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"无\",\"correct\":\"C\",\"id\":76,\"items\":[{\"content\":\"软件定义\",\"prefix\":\"A\"},{\"content\":\"软件开发\",\"prefix\":\"B\"},{\"content\":\"详细设计\",\"prefix\":\"C\"},{\"content\":\"软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\" 一般说来，软件生命周期由三个大的时期组成，不包括下面哪个时期\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"<p>正确答案是&nbsp;C。</p><p>解题思路：</p><ol><li>A 选项（时间错误）：软件危机是在&nbsp;20世纪60年代末至70年代​ 全面爆发并被正式提出的，而不是“70年代末期”。这个时间点不准确。</li><li>B 选项（结论错误）：软件工程方法极大地缓解了软件危机，但并未“已经解决”它。随着技术发展，新的复杂性和挑战不断出现，软件危机在某种程度上以新的形式存在。</li><li><span style=\\\"color: rgb(102, 185, 102);\\\">C 选项</span>（定义正确）：这是对“软件危机”最经典和准确的定义，它准确地描述了软件危机是在软件开发和维护过程中遇到的一系列严重问题（如预算超支、进度延误、质量低下、难以维护等）。</li><li>D 选项（定义片面）：软件危机不仅仅是指软件产品本身的质量问题，它更是一个涵盖项目管理、开发过程、技术方法和维护等全过程的综合性问题。这个选项的定义过于狭隘。</li></ol><p>因此，只有&nbsp;C 选项的说法是完全正确的。</p>\",\"correct\":\"C\",\"id\":77,\"items\":[{\"content\":\"软件危机在20世纪70年代末期全面爆发\",\"prefix\":\"A\"},{\"content\":\"前先进的软件工程方法已经解决了软件危机的问题\",\"prefix\":\"B\"},{\"content\":\"软件危机是指在软件开发和维护过程中所遇到的一系列严重问题\",\"prefix\":\"C\"},{\"content\":\"软件危机是指在软件产品中存在一系列的质量问题\",\"prefix\":\"D\"}],\"questionTitle\":\"下面的( )说法是正确的。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"<h3>解析：</h3><p>在软件生命周期的各个阶段中：</p><ul><li>D需求分析阶段：主要任务是确定软件系统要做什么，需要了解用户的需求并将其转化为系统的逻辑模型。数据流图（DFD- Data <span style=\\\"background-color: rgb(255, 255, 255); color: rgb(77, 77, 77);\\\">Flow&nbsp;Diagram</span>）是一种用于描述系统中数据流动和处理过程的图形化工具，它能够帮助分析人员清晰地展现系统的功能和数据关系，属于需求分析阶段的重要工作内容。</li><li>程序设计阶段：主要关注的是如何用具体的编程语言实现软件的功能，重点在于代码的编写，和数据流图这种需求级的建模工具无关。</li><li>详细设计阶段：侧重于对软件的模块内部结构、算法等进行详细的设计，通常使用流程图、伪代码等方式，而不是数据流图（数据流图更多是用于描述系统的整体逻辑功能，而非模块内部的详细设计）。</li><li>软件维护阶段：是对已经投入使用的软件进行修改、完善等工作，以适应新的需求或修复问题，和需求分析阶段的建模工作无关。</li></ul><p>所以画数据流图属于需求分析阶段的工作，答案为A。</p><p><br></p><p><img src=\\\"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAr8AAAF0CAIAAAClvMZTAAAQAElEQVR4AezdBZyWxfYHcGmUlBAkBEUEC7CxE+Pa3d15rWt3x1Wxu659r4Xdii0WJSEhzdJLwwL6/8p4n/97312WjffdYvZzPsN55jlz5sxv5plz5gws1X9c9k/fvn3Hjx+/aNGiP4r589nPo659qjd66I0flGff8kxaJyNHjiymyuWIT5kyJa', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperId\":90,\"paperName\":\"期中考试\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"无\",\"correct\":\"C\",\"id\":76,\"itemOrder\":0,\"items\":[{\"content\":\"软件定义\",\"prefix\":\"A\"},{\"content\":\"软件开发\",\"prefix\":\"B\"},{\"content\":\"详细设计\",\"prefix\":\"C\"},{\"content\":\"软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\" 一般说来，软件生命周期由三个大的时期组成，不包括下面哪个时期\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"<p>正确答案是&nbsp;C。</p><p>解题思路：</p><ol><li>A 选项（时间错误）：软件危机是在&nbsp;20世纪60年代末至70年代​ 全面爆发并被正式提出的，而不是“70年代末期”。这个时间点不准确。</li><li>B 选项（结论错误）：软件工程方法极大地缓解了软件危机，但并未“已经解决”它。随着技术发展，新的复杂性和挑战不断出现，软件危机在某种程度上以新的形式存在。</li><li><span style=\\\"color: rgb(102, 185, 102);\\\">C 选项</span>（定义正确）：这是对“软件危机”最经典和准确的定义，它准确地描述了软件危机是在软件开发和维护过程中遇到的一系列严重问题（如预算超支、进度延误、质量低下、难以维护等）。</li><li>D 选项（定义片面）：软件危机不仅仅是指软件产品本身的质量问题，它更是一个涵盖项目管理、开发过程、技术方法和维护等全过程的综合性问题。这个选项的定义过于狭隘。</li></ol><p>因此，只有&nbsp;C 选项的说法是完全正确的。</p>\",\"correct\":\"C\",\"id\":77,\"itemOrder\":1,\"items\":[{\"content\":\"软件危机在20世纪70年代末期全面爆发\",\"prefix\":\"A\"},{\"content\":\"前先进的软件工程方法已经解决了软件危机的问题\",\"prefix\":\"B\"},{\"content\":\"软件危机是指在软件开发和维护过程中所遇到的一系列严重问题\",\"prefix\":\"C\"},{\"content\":\"软件危机是指在软件产品中存在一系列的质量问题\",\"prefix\":\"D\"}],\"questionTitle\":\"下面的( )说法是正确的。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"<h3>解析：</h3><p>在软件生命周期的各个阶段中：</p><ul><li>D需求分析阶段：主要任务是确定软件系统要做什么，需要了解用户的需求并将其转化为系统的逻辑模型。数据流图（DFD- Data <span style=\\\"background-color: rgb(255, 255, 255); color: rgb(77, 77, 77);\\\">Flow&nbsp;Diagram</span>）是一种用于描述系统中数据流动和处理过程的图形化工具，它能够帮助分析人员清晰地展现系统的功能和数据关系，属于需求分析阶段的重要工作内容。</li><li>程序设计阶段：主要关注的是如何用具体的编程语言实现软件的功能，重点在于代码的编写，和数据流图这种需求级的建模工具无关。</li><li>详细设计阶段：侧重于对软件的模块内部结构、算法等进行详细的设计，通常使用流程图、伪代码等方式，而不是数据流图（数据流图更多是用于描述系统的整体逻辑功能，而非模块内部的详细设计）。</li><li>软件维护阶段：是对已经投入使用的软件进行修改、完善等工作，以适应新的需求或修复问题，和需求分析阶段的建模工作无关。</li></ul><p>所以画数据流图属于需求分析阶段的工作，答案为A。</p><p><br></p><p><img src=\\\"data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAr8AAAF0CAIAAAClvMZTAAAQAElEQVR4AezdBZyWxfYHcGmUlBAkBEUEC7CxE+Pa3d15rWt3x1Wxu659r4Xdii0WJSEhzdJLwwL6/8p4n/97312WjffdYvZzPsN55jlz5sxv5', 0, NULL, '2025-11-19 16:37:15', 107);
INSERT INTO `sys_oper_log` VALUES (580, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"<h3>解析：</h3><ul><li>A、B、C选项描述的都是瀑布模型的特点或优点：</li><li class=\\\"ql-indent-1\\\">A强调规范化开发（优点）</li><li class=\\\"ql-indent-1\\\">B强调文档规范性（特点/优点）</li><li class=\\\"ql-indent-1\\\">C强调阶段验证（优点）</li><li>D选项揭示了瀑布模型的局限性：瀑布模型要求需求在项目初期完全确定，但实际项目中需求可能变化，这一特点使其难以适应需求变更的场景，因此属于缺点。</li></ul><p><br></p><p><br></p><p><br></p><p><br></p>\",\"correct\":\"D\",\"correctArray\":[],\"items\":[{\"content\":\"可强迫开发人员采用规范化的方法\",\"prefix\":\"A\"},{\"content\":\"严格地规定了每个阶段必须提交的文档\",\"prefix\":\"B\"},{\"content\":\"要求每个阶段交出的所有产品都必须是经过验证的\",\"prefix\":\"C\"},{\"content\":\"适用于项目开始时需求已确定的情况\",\"prefix\":\"D\"}],\"questionTitle\":\"以下哪一个是瀑布模型的缺点。\",\"questionType\":1,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-19 17:14:56', 25);
INSERT INTO `sys_oper_log` VALUES (581, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"<p>解析（正确项）：</p><p><br></p><ul><li>喷泉模型属于<strong>面向对象的软件开发过程模型</strong>，以对象及其交互为核心，最适合面向对象开发方法。</li></ul><p>错误选项简析：</p><p><br></p><ul><li>A 结构化：强调功能分解、数据流图等，更偏过程驱动，不是喷泉模型的思想。</li><li>B 形式化：重在用数学语言严格描述和验证软件，与喷泉模型的“对象驱动”无直接对应。</li><li>D 面向数据：围绕数据结构和数据存取设计展开，与喷泉模型面向对象特征不匹配。</li></ul><p><br></p>\",\"correct\":\"C\",\"correctArray\":[],\"items\":[{\"content\":\"结构化 \",\"prefix\":\"A\"},{\"content\":\"形式化 \",\"prefix\":\"B\"},{\"content\":\"面向对象 \",\"prefix\":\"C\"},{\"content\":\"面向数据\",\"prefix\":\"D\"}],\"questionTitle\":\"喷泉模型是对象驱动的，适合于( )的开发方法。\",\"questionType\":1,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-19 17:23:16', 95);
INSERT INTO `sys_oper_log` VALUES (582, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '127.0.0.1', '内网IP', '{\"analysis\":\"<p>正确答案：B</p><p>解析（正确项）：</p><p><br></p><ul><li><span style=\\\"background-color: oklab(0.845175 0.0000383258 0.0000169277 / 0.1);\\\">Rational Rose</span>&nbsp;是典型的<strong>软件工程工具软件</strong>，用于UML建模、分析和设计，直接服务于软件开发过程。</li></ul><p>错误选项简析：</p><p><br></p><ul><li>A 字处理软件：通用办公应用软件，不是专门支持软件工程活动的工具。</li><li>C 操作系统：属于系统软件，提供运行环境，而非工程工具。</li><li>D DBMS：数据库管理系统，负责数据管理和存取，也不是专门的软件工程工具。</li></ul><p><br></p>\",\"correct\":\"B\",\"correctArray\":[],\"items\":[{\"content\":\"字处理软件\",\"prefix\":\"A\"},{\"content\":\"Rational Rose\",\"prefix\":\"B\"},{\"content\":\"操作系统\",\"prefix\":\"C\"},{\"content\":\"DBMS\",\"prefix\":\"D\"}],\"questionTitle\":\"下列( )属于软件工程工具软件。\",\"questionType\":1,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-11-19 17:30:13', 32);
