INSERT INTO `sys_oper_log` VALUES (597, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoCompose()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose', '127.0.0.1', '内网IP', '{\"enableAntiCheat\":false,\"paperName\":\"期中考试\",\"paperType\":1,\"rules\":[{\"questionCount\":20,\"questionType\":1,\"sectionName\":\"单选题\"}],\"subjectId\":1,\"suggestTime\":60}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperName\":\"期中考试\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"测试旨在发现尽可能多的缺陷并评估风险，无法证明绝对正确，也不同于调试。\",\"correct\":\"B\",\"id\":89,\"itemOrder\":0,\"items\":[{\"content\":\"证明软件是正确的\",\"prefix\":\"A\"},{\"content\":\"发现错误、降低错误带来的风险\",\"prefix\":\"B\"},{\"content\":\"排除软件中所有的错误\",\"prefix\":\"C\"},{\"content\":\"与软件调试相同\",\"prefix\":\"D\"}],\"questionTitle\":\"软件测试的目标是( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"瀑布模型阶段按固定顺序一次完成，属于线性顺序模型；B/C 带迭代含义，D 更像原型/增量。\",\"correct\":\"A\",\"id\":87,\"itemOrder\":1,\"items\":[{\"content\":\"线性顺序模型\",\"prefix\":\"A\"},{\"content\":\"顺序迭代模型\",\"prefix\":\"B\"},{\"content\":\"线性迭代模型\",\"prefix\":\"C\"},{\"content\":\"及早见产品的模型\",\"prefix\":\"D\"}],\"questionTitle\":\"瀑布模型本质上是一种( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"<h3>解析：</h3><p>在软件生命周期的各个阶段中：</p><ul><li>D需求分析阶段：主要任务是确定软件系统要做什么，需要了解用户的需求并将其转化为系统的逻辑模型。数据流图（DFD- Data <span style=\\\"background-color: rgb(255, 255, 255); color: rgb(77, 77, 77);\\\">Flow&nbsp;Diagram</span>）是一种用于描述系统中数据流动和处理过程的图形化工具，它能够帮助分析人员清晰地展现系统的功能和数据关系，属于需求分析阶段的重要工作内容。</li><li>程序设计阶段：主要关注的是如何用具体的编程语言实现软件的功能，重点在于代码的编写，和数据流图这种需求级的建模工具无关。</li><li>详细设计阶段：侧重于对软件的模块内部结构、算法等进行详细的设计，通常使用流程图、伪代码等方式，而不是数据流图（数据流图更多是用于描述系统的整体逻辑功能，而非模块内部的详细设计）。</li><li>软件维护阶段：是对已经投入使用的软件进行修改、完善等工作，以适应新的需求或修复问题，和需求分析阶段的建模工作无关。</li></ul><p>所以画数据流图属于需求分析阶段的工作，答案为A。</p><p><br></p><p><img src=\\\"data:image/png;base64,', 0, NULL, '2025-11-19 21:56:06', 64);
INSERT INTO `sys_oper_log` VALUES (598, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoCompose()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose', '127.0.0.1', '内网IP', '{\"enableAntiCheat\":false,\"paperName\":\"期中考试\",\"paperType\":1,\"rules\":[{\"questionCount\":5,\"questionType\":1,\"sectionName\":\"单选题\"}],\"subjectId\":1,\"suggestTime\":60}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperName\":\"期中考试\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"维护阶段伴随软件整个运行周期，成本通常超过开发期；A/B/C 都在开发期。\",\"correct\":\"D\",\"id\":88,\"itemOrder\":0,\"items\":[{\"content\":\"详细设计\",\"prefix\":\"A\"},{\"content\":\"软件编码\",\"prefix\":\"B\"},{\"content\":\"软件测试\",\"prefix\":\"C\"},{\"content\":\"软件维护\",\"prefix\":\"D\"}],\"questionTitle\":\"软件生命周期中所花费用最多的阶段是( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"OMT（Object Modeling Technique）是 Rumbaugh 提出的面向对象分析与设计方法，其余选项是其它 OO 方法作者。\",\"correct\":\"B\",\"id\":84,\"itemOrder\":1,\"items\":[{\"content\":\"Booch\",\"prefix\":\"A\"},{\"content\":\"Rumbaugh\",\"prefix\":\"B\"},{\"content\":\"Coad\",\"prefix\":\"C\"},{\"content\":\"Jacobson\",\"prefix\":\"D\"}],\"questionTitle\":\"OMT 方法是由下面哪位科学家提出的( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"DFD 的核心就是用箭头表示数据流向，因此说“不反映数据流向”是错误的；A/B/C 都是 DFD 的正确特性。\",\"correct\":\"D\",\"id\":95,\"itemOrder\":2,\"items\":[{\"content\":\"数据流图将各种信息流抽象成数据流的形式\",\"prefix\":\"A\"},{\"content\":\"数据流图不反映控制关系、调用关系\",\"prefix\":\"B\"},{\"content\":\"数据流图不反映处理逻辑的先后顺序\",\"prefix\":\"C\"},{\"content\":\"数据流图不反映数据的流向\",\"prefix\":\"D\"}],\"questionTitle\":\"下列描述错误的是( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"E-R 三要素：实体(Entity)、联系(Relationship)、属性(Attribute)。\",\"correct\":\"C\",\"id\":91,\"itemOrder\":3,\"items\":[{\"content\":\"数据、对象、实体\",\"prefix\":\"A\"},{\"content\":\"控制、联系、对象\",\"prefix\":\"B\"},{\"content\":\"实体、联系、属性\",\"prefix\":\"C\"},{\"content\":\"实体、属性、操作\",\"prefix\":\"D\"}],\"questionTitle\":\"在E-R模型中，包含以下基本成分( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"完善性维护通过增功能、提性能持续提升价值，被认为最关键；B/C/D 分别对应修错、适应、预防。\",\"correct\":\"A\",\"id\":90,\"itemOrder\":4,\"items\":[{\"content\":\"完善性维护\",\"prefix\":\"A\"},{\"content\":\"改正性维护\",\"prefix\":\"B\"},{\"content\":\"适应性维护\",\"prefix\":\"C\"},{\"content\":\"预防性维护\",\"prefix\":\"D\"}],\"questionTitle\":\"各种软件维护的类型中最重要的是( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1}]}],\"paperType\":1,\"questionCount\":5,\"score\":5,\"subjectId\":1,\"suggestTime\":60}}', 0, NULL, '2025-11-19 21:56:10', 11);
