INSERT INTO `sys_oper_log` VALUES (613, '题目表', 6, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.importData()', 'POST', 1, 'admin', '研发部门', '/quiz/question/importData', '127.0.0.1', '内网IP', '', NULL, 1, '很抱歉，部分数据导入失败！共 14 条，错误如下：<br/>1、题干 移码的符号位中 0 表示负数，1 表示正数。 导入失败：题目类型不能为空<br/>2、题干 原码属于真值，补码属于机器值。 导入失败：题目类型不能为空<br/>3、题干 正数的原码、反码、补码和移码都一样。 导入失败：题目类型不能为空<br/>4、题干 补码又称位模2的补码。 导入失败：题目类型不能为空<br/>5、题干 原码、补码、反码、移码的表示区间在数轴都是对称的，都有两个0，即 +0 和 -0。 导入失败：题目类型不能为空<br/>6、题干 定点数表示数据的小数点位置固定，只能表示固定的小数，不能表示整数。 导入失败：题目类型不能为空<br/>7、题干 对于 8 位的反码，+0 的反码是 00000000；-0 的反码是 11111111。 导入失败：题目类型不能为空<br/>8、题干 移码与补码只有符号位相反，数值位相同。 导入失败：题目类型不能为空<br/>9、题干 在 IEEE 754 标准中，单精度浮点数的阶码部分是用移码表示的。 导入失败：题目类型不能为空<br/>10、题干 原码变为补码的规则是符号位不变，数值位取反末尾加 1。 导入失败：题目类型不能为空<br/>11、题干 简述：冯诺依曼计算机的主要思想。 导入失败：题目类型不能为空<br/>12、题干 简述，计算机的层次结构。 导入失败：题目类型不能为空<br/>13、题干 已知 x 和 y，用变形补码计算 x+y，同时指出结果是否溢出。（1）x=-11011，y=-10001 （2）x=+11100，y=+10001 导入失败：题目类型不能为空<br/>14、题干 若 X= -43/2048, Y=14/256，设阶码 3 位，尾数 6 位（均不含符号位），阶码和尾数均采用双符号位，且都用补码表示，按浮点运算步骤计算 X+Y。 导入失败：题目类型不能为空', '2025-11-21 12:32:45', 452);
INSERT INTO `sys_oper_log` VALUES (614, '题目表', 6, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.importData()', 'POST', 1, 'admin', '研发部门', '/quiz/question/importData', '127.0.0.1', '内网IP', '', '{\"msg\":\"恭喜您，数据已全部导入成功！共 26 ??????admin??????<br/>1??? 若某数 x 的真值 -0.1010，在计算机中该数表示为 1.0110，则该数所用的编码方法是（         ） ????<br/>2??? 定点 8 位字长，2 的补码表示 8 位二进制整数，可表示的数范围为（        ）。 ????<br/>3??? 机器系统中采用补码运算的目的是为了(         )。 ????<br/>4??? 假定下列字符码中有奇偶校验位，但没有数据出错误，采用奇校验的字符码是（          ）。 ????<br/>5??? 在计算机的性能指标中，吞吐量是（          ）。 ????<br/>6??? 为什么要对齐？ ????<br/>7??? 在计算机层次结构中，哪一层主要负责提供硬件资源的抽象和管理？并对计算机软硬件资源统一管理。 ????<br/>8??? 在浮点数加减法运算中，首先需要进行的操作是？ ????<br/>9??? 在纠错码中，码距是指两个码字之间不同的位数。对于两个二进制码字 1010 和 1100，它们之间的码距是多少？ ????<br/>10??? 冯·诺依曼计算机体系的核心思想是（  ）。 ????<br/>11??? 在补码一位乘法中，X 是被乘数，Y 是乘数。若乘数最末位 Yn 和 Yn+1 的值分别为 1 和 0，那么下步执行的操作应该是（ ）。 ????<br/>12??? 当数据超出计算机所能表示的数据范围称为溢出，浮点数表示中，数据小于计算机所能表示的最小负数时，发生（ ）。 ????<br/>13??? 移码的符号位中 0 表示负数，1 表示正数。 ????<br/>14??? 原码属于真值，补码属于机器值。 ????<br/>15??? 正数的原码、反码、补码和移码都一样。 ????<br/>16??? 补码又称位模2的补码。 ????<br/>17??? 原码、补码、反码、移码的表示区间在数轴都是对称的，都有两个0，即 +0 和 -0。 ????<br/>18??? 定点数表示数据的小数点位置固定，只能表示固定的小数，不能表示整数。 ????<br/>19??? 对于 8 位的反码，+0 的反码是 00000000；-0 的反码是 11111111。 ????<br/>20??? 移码与补码只有符号位相反，数值位相同。 ????<br/>21??? 在 IEEE 754 标准中，单精度浮点数的阶码部分是用移码表示的。 ????<br/>22??? 原码变为补码的规则是符号位不变，数值位取反末尾加 1。 ????<br/>23??? 简述：冯诺依曼计算机的主要思想。 ????<br/>24??? 简述，计算机的层次结构。 ????<br/>25??? 已知 x 和 y，用变形补码计算 x+y，同时指出结果是否溢出。（1）x=-11011，y=-10001 （2）x=+11100，y=+10001 ????<br/>26??? 若 X= -43/2048, Y=14/256，设阶码 3 位，尾数 6 位（均不含符号位），阶码和尾数均采用双符号位，且都用补码表示，按浮点运算步骤计算 X+Y。 ????\",\"code\":200}', 0, NULL, '2025-11-21 13:37:07', 838);
