INSERT INTO `sys_oper_log` VALUES (686, '试卷', 2, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/paper', '183.21.174.91', 'XX XX', '{\"enableAntiCheat\":true,\"endTime\":\"2026-01-01 00:00:00\",\"paperId\":89,\"paperName\":\"lll\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"无\",\"correct\":\"A\",\"id\":74,\"itemOrder\":0,\"items\":[{\"content\":\"打印的字符数\",\"prefix\":\"A\"},{\"content\":\"返回0表示成功\",\"prefix\":\"B\"},{\"content\":\"返回1表示失败\",\"prefix\":\"C\"},{\"content\":\"没有返回值\",\"prefix\":\"D\"}],\"questionTitle\":\"在C语言中，printf函数的返回值是：\",\"questionType\":1,\"score\":1,\"subjectId\":2},{\"analysis\":\"无\",\"correct\":\"C\",\"id\":71,\"itemOrder\":1,\"items\":[{\"content\":\"1st_variable\",\"prefix\":\"A\"},{\"content\":\"first-variable\",\"prefix\":\"B\"},{\"content\":\"first_variable\",\"prefix\":\"C\"},{\"content\":\"first variable\",\"prefix\":\"D\"}],\"questionTitle\":\"C语言中，以下哪个选项是合法的变量名？\",\"questionType\":1,\"score\":1,\"subjectId\":2},{\"analysis\":\"无\",\"correct\":\"B\",\"id\":70,\"itemOrder\":2,\"items\":[{\"content\":\"print$\",\"prefix\":\"A\"},{\"content\":\"print_var\",\"prefix\":\"B\"},{\"content\":\"3print\",\"prefix\":\"C\"},{\"content\":\"print-\",\"prefix\":\"D\"}],\"questionTitle\":\"以下哪个是合法的C语言标识符?\",\"questionType\":1,\"score\":1,\"subjectId\":2},{\"analysis\":\"1\",\"correct\":\"D\",\"id\":67,\"itemOrder\":3,\"items\":[{\"content\":\"+\",\"prefix\":\"A\"},{\"content\":\"/\",\"prefix\":\"B\"},{\"content\":\"*\",\"prefix\":\"C\"},{\"content\":\"%\",\"prefix\":\"D\"}],\"questionTitle\":\"在C语言中，运算对象必须是整形的运算符是\",\"questionType\":1,\"score\":1,\"subjectId\":2},{\"analysis\":\"无\",\"correct\":\"B\",\"id\":69,\"itemOrder\":4,\"items\":[{\"content\":\"11 \",\"prefix\":\"A\"},{\"content\":\"12 \",\"prefix\":\"B\"},{\"content\":\"不确定\",\"prefix\":\"C\"},{\"content\":\"需要分配的内存容量取决于编译器实现 答案：B\",\"prefix\":\"D\"}],\"questionTitle\":\"C语言中，字符串\\\"Hello World!\\\"所占的内存字节数为\",\"questionType\":1,\"score\":1,\"subjectId\":2},{\"analysis\":\"无\",\"correct\":\"A\",\"id\":68,\"itemOrder\":5,\"items\":[{\"content\":\"x=y==1\",\"prefix\":\"A\"},{\"content\":\"x=5=y\",\"prefix\":\"B\"},{\"content\":\"x+y=5\",\"prefix\":\"C\"},{\"content\":\"x==y=1\",\"prefix\":\"D\"}],\"questionTitle\":\"若变量已定义且已赋值，以下合法的C语言赋值表达式是\",\"questionType\":1,\"score\":1,\"subjectId\":2},{\"analysis\":\"无\",\"correct\":\"B\",\"id\":72,\"itemOrder\":6,\"items\":[{\"content\":\"计算变量的值\",\"prefix\":\"A\"},{\"content\":\"获取变量所占的字节数\",\"prefix\":\"B\"},{\"content\":\"计算数组的长度\",', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2025-12-23 17:20:34', 132);
