INSERT INTO `sys_oper_log` VALUES (690, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoCompose()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose', '120.85.40.97', 'XX XX', '{\"enableAntiCheat\":false,\"rules\":[{\"questionCount\":2,\"questionType\":1,\"sectionName\":\"\"},{\"questionCount\":1,\"questionType\":2,\"sectionName\":\"\"}],\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"<p>6666</p><p><br></p><p><img src=\\\"/dev-apiquiz/paper/answer/2025/11/24/e8279544864f48299cf4afedd815ed6d.jpg\\\"></p>\",\"correct\":\"B\",\"id\":141,\"itemOrder\":0,\"items\":[{\"content\":\"1\",\"prefix\":\"A\"},{\"content\":\"2\",\"prefix\":\"B\"},{\"content\":\"3\",\"prefix\":\"C\"},{\"content\":\"4\",\"prefix\":\"D\"}],\"questionTitle\":\"1+1等于几\",\"questionType\":1,\"score\":1,\"subjectId\":1},{\"analysis\":\"瀑布模型阶段按固定顺序一次完成，属于线性顺序模型；B/C 带迭代含义，D 更像原型/增量。\",\"correct\":\"A\",\"id\":87,\"itemOrder\":1,\"items\":[{\"content\":\"线性顺序模型\",\"prefix\":\"A\"},{\"content\":\"顺序迭代模型\",\"prefix\":\"B\"},{\"content\":\"线性迭代模型\",\"prefix\":\"C\"},{\"content\":\"及早见产品的模型\",\"prefix\":\"D\"}],\"questionTitle\":\"瀑布模型本质上是一种( )。\",\"questionType\":1,\"score\":1,\"subjectId\":1}]},{\"name\":\"多选题\",\"questionDtos\":[{\"analysis\":\"解析：多选题有多个正确答案，答案用英文逗号分隔，这里选择A、B、C\",\"correctArray\":[\"A\",\"B\",\"C\"],\"id\":156,\"itemOrder\":2,\"items\":[{\"content\":\"选项A内容\",\"prefix\":\"A\"},{\"content\":\"选项B内容\",\"prefix\":\"B\"},{\"content\":\"选项C内容\",\"prefix\":\"C\"},{\"content\":\"选项D内容\",\"prefix\":\"D\"}],\"questionTitle\":\"示例：这是一道多选题题干？（多选）\",\"questionType\":2,\"score\":10,\"subjectId\":1}]}],\"questionCount\":3,\"score\":12,\"subjectId\":1}}', 0, NULL, '2025-12-24 16:25:08', 13);
