INSERT INTO `sys_oper_log` VALUES (692, '个人信息', 2, 'com.ruoyi.web.controller.system.SysProfileController.updateProfile()', 'PUT', 1, 'admin', '研发部门', '/system/user/profile', '120.85.42.69', 'XX XX', '{\"admin\":false,\"avatar\":\"https://daming-paper.oss-cn-guangzhou.aliyuncs.com/quiz/paper/answer/2026/01/02/f9e1deeebc2048d8aa6cfe34409b4195.jpg\",\"params\":{}}', NULL, 1, '\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'avatar\' at row 1\n### The error may exist in URL [jar:file:/root/paper/ruoyi-admin.jar!/BOOT-INF/lib/ruoyi-system-3.8.8.jar!/mapper/system/SysUserMapper.xml]\n### The error may involve com.ruoyi.system.mapper.SysUserMapper.updateUser-Inline\n### The error occurred while setting parameters\n### SQL: update sys_user     SET dept_id = ?,     user_name = ?,     nick_name = ?,     email = ?,     phonenumber = ?,     sex = ?,     avatar = ?,     password = ?,     status = ?,     login_ip = ?,     login_date = ?,          remark = ?,     update_time = sysdate()     where user_id = ?\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'avatar\' at row 1\n; Data truncation: Data too long for column \'avatar\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'avatar\' at row 1', '2026-01-02 14:23:04', 242);
INSERT INTO `sys_oper_log` VALUES (693, '科目管理', 1, 'com.ruoyi.web.controller.quiz.admin.DamingSubjectController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/subject', '120.85.42.69', 'XX XX', '{\"createTime\":\"2026-01-02 21:09:43\",\"delFlag\":0,\"params\":{},\"subjectId\":4,\"subjectName\":\"计算机网络\",\"updateTime\":\"2026-01-02 21:09:43\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-02 21:09:43', 18);
INSERT INTO `sys_oper_log` VALUES (694, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.69', 'XX XX', '{\"analysis\":\"<p>计算机网络从逻辑功能上可以分为 <strong>通信子网</strong> 和 <strong>资源子网</strong> 两部分。</p><p>这是计算机网络的一种经典逻辑结构划分，通过将“传输”与“处理”分离，使得网络结构更加清晰。</p><h3>1. 通信子网 (Communication Subnet)</h3><p>通信子网负责网络中的<strong>数据传输、转发和通信控制</strong>。它由各种传输介质（如光纤、双绞线）和网络设备（如路由器、交换机、中继器）组成。</p><ul><li><strong>功能</strong>：路由选择、拥塞控制、差错校验、数据交换。</li><li><strong>对应OSI层级</strong>：主要对应下三层（物理层、数据链路层、网络层）。</li></ul><h3>2. 资源子网 (Resource Subnet)</h3><p>资源子网负责整个网络的<strong>数据处理和资源共享</strong>。它由联网的各类主机（服务器、个人电脑）、终端设备、外部设备（如打印机）以及相关的软件和数据库组成。</p><ul><li><strong>功能</strong>：提供网络资源（硬件/软件/数据资源）、进行信息处理、为用户提供访问接口。</li><li><strong>对应OSI层级</strong>：主要对应上三层（会话层、表示层、应用层），传输层则起到连接两者的桥梁作用。</li></ul><h3>核心区别总结</h3><p><strong>维度通信子网资源子网核心组成</strong>路由器、交换机、传输介质主机(Host)、服务器、终端<strong>主要任务“怎么传”</strong>（搬运数据）<strong>“传什么/怎么用”</strong>（处理数据）<strong>位置</strong>网络的内层（核心部分）网络的外层（用户边缘）</p>\",\"correct\":\"资源子网,通信子网\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>计算机网络从逻辑上可分为____和____两部分。</p>\",\"questionType\":5,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-02 21:19:14', 124);
