INSERT INTO `sys_oper_log` VALUES (697, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoCompose()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose', '120.85.42.69', 'XX XX', '{\"enableAntiCheat\":false,\"paperName\":\"计网期末复习\",\"paperType\":2,\"rules\":[{\"questionCount\":1,\"questionType\":5,\"sectionName\":\"\"}],\"subjectId\":4,\"suggestTime\":1}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperName\":\"计网期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"填空题\",\"questionDtos\":[{\"analysis\":\"<p>计算机网络从逻辑功能上可以分为 <strong>通信子网</strong> 和 <strong>资源子网</strong> 两部分。</p><p>这是计算机网络的一种经典逻辑结构划分，通过将“传输”与“处理”分离，使得网络结构更加清晰。</p><h3>1. 通信子网 (Communication Subnet)</h3><p>通信子网负责网络中的<strong>数据传输、转发和通信控制</strong>。它由各种传输介质（如光纤、双绞线）和网络设备（如路由器、交换机、中继器）组成。</p><ul><li><strong>功能</strong>：路由选择、拥塞控制、差错校验、数据交换。</li><li><strong>对应OSI层级</strong>：主要对应下三层（物理层、数据链路层、网络层）。</li></ul><h3>2. 资源子网 (Resource Subnet)</h3><p>资源子网负责整个网络的<strong>数据处理和资源共享</strong>。它由联网的各类主机（服务器、个人电脑）、终端设备、外部设备（如打印机）以及相关的软件和数据库组成。</p><ul><li><strong>功能</strong>：提供网络资源（硬件/软件/数据资源）、进行信息处理、为用户提供访问接口。</li><li><strong>对应OSI层级</strong>：主要对应上三层（会话层、表示层、应用层），传输层则起到连接两者的桥梁作用。</li></ul><h3>核心区别总结</h3><p><strong>维度通信子网资源子网核心组成</strong>路由器、交换机、传输介质主机(Host)、服务器、终端<strong>主要任务“怎么传”</strong>（搬运数据）<strong>“传什么/怎么用”</strong>（处理数据）<strong>位置</strong>网络的内层（核心部分）网络的外层（用户边缘）</p>\",\"correct\":\"资源子网,通信子网\",\"id\":161,\"itemOrder\":0,\"items\":[],\"questionTitle\":\"<p>计算机网络从逻辑上可分为____和____两部分。</p>\",\"questionType\":5,\"score\":1,\"subjectId\":4}]}],\"paperType\":2,\"questionCount\":1,\"score\":1,\"subjectId\":4,\"suggestTime\":1}}', 0, NULL, '2026-01-02 21:20:23', 6);
INSERT INTO `sys_oper_log` VALUES (698, '试卷', 1, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/paper', '120.85.42.69', 'XX XX', '{\"enableAntiCheat\":false,\"paperName\":\"计网期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"填空题\",\"questionDtos\":[{\"analysis\":\"<p>计算机网络从逻辑功能上可以分为 <strong>通信子网</strong> 和 <strong>资源子网</strong> 两部分。</p><p>这是计算机网络的一种经典逻辑结构划分，通过将“传输”与“处理”分离，使得网络结构更加清晰。</p><h3>1. 通信子网 (Communication Subnet)</h3><p>通信子网负责网络中的<strong>数据传输、转发和通信控制</strong>。它由各种传输介质（如光纤、双绞线）和网络设备（如路由器、交换机、中继器）组成。</p><ul><li><strong>功能</strong>：路由选择、拥塞控制、差错校验、数据交换。</li><li><strong>对应OSI层级</strong>：主要对应下三层（物理层、数据链路层、网络层）。</li></ul><h3>2. 资源子网 (Resource Subnet)</h3><p>资源子网负责整个网络的<strong>数据处理和资源共享</strong>。它由联网的各类主机（服务器、个人电脑）、终端设备、外部设备（如打印机）以及相关的软件和数据库组成。</p><ul><li><strong>功能</strong>：提供网络资源（硬件/软件/数据资源）、进行信息处理、为用户提供访问接口。</li><li><strong>对应OSI层级</strong>：主要对应上三层（会话层、表示层、应用层），传输层则起到连接两者的桥梁作用。</li></ul><h3>核心区别总结</h3><p><strong>维度通信子网资源子网核心组成</strong>路由器、交换机、传输介质主机(Host)、服务器、终端<strong>主要任务“怎么传”</strong>（搬运数据）<strong>“传什么/怎么用”</strong>（处理数据）<strong>位置</strong>网络的内层（核心部分）网络的外层（用户边缘）</p>\",\"correct\":\"资源子网,通信子网\",\"id\":161,\"itemOrder\":0,\"items\":[],\"questionTitle\":\"<p>计算机网络从逻辑上可分为____和____两部分。</p>\",\"questionType\":5,\"score\":1,\"subjectId\":4}]}],\"paperType\":2,\"questionCount\":1,\"score\":1,\"subjectId\":4,\"suggestTime\":1}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperId\":96,\"paperName\":\"计网期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"填空题\",\"questionDtos\":[{\"analysis\":\"<p>计算机网络从逻辑功能上可以分为 <strong>通信子网</strong> 和 <strong>资源子网</strong> 两部分。</p><p>这是计算机网络的一种经典逻辑结构划分，通过将“传输”与“处理”分离，使得网络结构更加清晰。</p><h3>1. 通信子网 (Communication Subnet)</h3><p>通信子网负责网络中的<strong>数据传输、转发和通信控制</strong>。它由各种传输介质（如光纤、双绞线）和网络设备（如路由器、交换机、中继器）组成。</p><ul><li><strong>功能</strong>：路由选择、拥塞控制、差错校验、数据交换。</li><li><strong>对应OSI层级</strong>：主要对应下三层（物理层、数据链路层、网络层）。</li></ul><h3>2. 资源子网 (Resource Subnet)</h3><p>资源子网负责整个网络的<strong>数据处理和资源共享</strong>。它由联网的各类主机（服务器、个人电脑）、终端设备、外部设备（如打印机）以及相关的软件和数据库组成。</p><ul><li><strong>功能</strong>：提供网络资源（硬件/软件/数据资源）、进行信息处理、为用户提供访问接口。</li><li><strong>对应OSI层级</strong>：主要对应上三层（会话层、表示层、应用层），传输层则起到连接两者的桥梁作用。</li></ul><h3>核心区别总结</h3><p><strong>维度通信子网资源子网核心组成</strong>路由器、交换机、传输介质主机(Host)、服务器、终端<strong>主要任务“怎么传”</strong>（搬运数据）<strong>“传什么/怎么用”</strong>（处理数据）<strong>位置</strong>网络的内层（核心部分）网络的外层（用户边缘）</p>\",\"correct\":\"资源子网,通信子网\",\"id\":161,\"itemOrder\":0,\"items\":[],\"questionTitle\":\"<p>计算机网络从逻辑上可分为____和____两部分。</p>\",\"questionType\":5,\"score\":1,\"subjectId\":4}]}],\"paperType\":2,\"questionCount\":1,\"score\":1,\"subjectId\":4,\"suggestTime\":1}}', 0, NULL, '2026-01-02 21:20:25', 28);
INSERT INTO `sys_oper_log` VALUES (699, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.69', 'XX XX', '{\"analysis\":\"无\",\"correct\":\"传输介质,接口特性,信号编码,同步方式\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>物理层的主要功能包括____、____、____、____</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-02 22:19:21', 112);
INSERT INTO `sys_oper_log` VALUES (700, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.69', 'XX XX', '{\"analysis\":\"<h3>1. 传输介质 (Transmission Media)</h3><p>这是通信的物理通路，决定了信号能传多远、有多快。</p><p><br></p><ul><li><strong>导引型传输介质：</strong> 有具体的物理边界。</li><li class=\\\"ql-indent-1\\\"><strong>双绞线（网线）：</strong> 价格便宜，安装方便，广泛用于局域网。</li><li class=\\\"ql-indent-1\\\"><strong>同轴电缆：</strong> 抗干扰能力强，常用于有线电视。</li><li class=\\\"ql-indent-1\\\"><strong>光纤：</strong> 利用光脉冲传输，带宽极大，损耗极低，是现代骨干网的核心。</li><li><strong>非导引型传输介质：</strong> 自由空间。</li><li class=\\\"ql-indent-1\\\"><strong>无线电、微波、红外线：</strong> 用于 WiFi、蓝牙、卫星通信等。</li></ul><h3>2. 接口特性 (Interface Characteristics)</h3><p>物理层定义了连接设备时必须遵守的标准化规格，确保不同厂家生产的设备能“插得上、用得了”。</p><p><br></p><ul><li><strong>机械特性：</strong> 规定接口的形状、尺寸、引脚数量和排列方式（比如 RJ45 水晶头的样子）。</li><li><strong>电气特性：</strong> 规定引脚上的电压范围、阻抗匹配等。</li><li><strong>功能特性：</strong> 规定某条线上出现某一电平代表什么意义（例如：这条线是用来传输数据的，还是用来请求发送的）。</li><li><strong>过程特性：</strong> 规定发送比特流的时间顺序和动作序列（类似于“握手”协议的物理步骤）。</li></ul><h3>3. 信号编码 (Signal Encoding)</h3><p>计算机内部处理的是二进制数字信号，但在传输介质中，需要将其转换成适合传输的信号形式。</p><p><br></p><ul><li><strong>数字到数字（基带传输）：</strong></li><li class=\\\"ql-indent-1\\\"><strong>不归零编码 (NRZ)：</strong> 高电平代表 1，低电平代表 0。</li><li class=\\\"ql-indent-1\\\"><strong>曼彻斯特编码：</strong> 用信号中间的跳变来表示 0 或 1（例如：向上跳变是 1，向下是 0），这自带了时钟同步信号。</li><li><strong>数字到模拟（频带传输）：</strong></li><li class=\\\"ql-indent-1\\\">通过调制（ASK、FSK、PSK）将数字信号加载到模拟载波上，常见于移动通信和早期的拨号上网。</li></ul><h3>4. 同步方式 (Synchronization)</h3><p>为了确保接收方能准确识别发送方发出的每一个比特位，双方的时钟必须步调一致。</p><p><br></p><ul><li><strong>异步传输 (Asynchronous)：</strong> 以字符为单位传输。每个字符前后加上“起始位”和“停止位”。虽然简单，但开销较大（因为有很多冗余位）。</li><li><strong>同步传输 (Synchronous)：</strong> 以数据块为单位传输。发送方和接收方由同一个时钟源控制，或者从信号流中提取时钟信息。它的传输效率更高，适合高速通信。</li></ul><p><strong>介口码步</strong></p>\",\"correct\":\"传输介质,接口特性,信号编码,同步方式\",\"correctArray\":[],\"id\":162,\"items\":[],\"questionTitle\":\"<p>物理层的主要功能包括____、____、____、____</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-02 22:26:23', 76);
INSERT INTO `sys_oper_log` VALUES (701, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.69', 'XX XX', '{\"analysis\":\"<h3>1. 传输介质 (Transmission Media)</h3><p>这是通信的物理通路，决定了信号能传多远、有多快。</p><p><br></p><ul><li><strong>导引型传输介质：</strong> 有具体的物理边界。</li><li class=\\\"ql-indent-1\\\"><strong>双绞线（网线）：</strong> 价格便宜，安装方便，广泛用于局域网。</li><li class=\\\"ql-indent-1\\\"><strong>同轴电缆：</strong> 抗干扰能力强，常用于有线电视。</li><li class=\\\"ql-indent-1\\\"><strong>光纤：</strong> 利用光脉冲传输，带宽极大，损耗极低，是现代骨干网的核心。</li><li><strong>非导引型传输介质：</strong> 自由空间。</li><li class=\\\"ql-indent-1\\\"><strong>无线电、微波、红外线：</strong> 用于 WiFi、蓝牙、卫星通信等。</li></ul><h3>2. 接口特性 (Interface Characteristics)</h3><p>物理层定义了连接设备时必须遵守的标准化规格，确保不同厂家生产的设备能“插得上、用得了”。</p><p><br></p><ul><li><strong>机械特性：</strong> 规定接口的形状、尺寸、引脚数量和排列方式（比如 RJ45 水晶头的样子）。</li><li><strong>电气特性：</strong> 规定引脚上的电压范围、阻抗匹配等。</li><li><strong>功能特性：</strong> 规定某条线上出现某一电平代表什么意义（例如：这条线是用来传输数据的，还是用来请求发送的）。</li><li><strong>过程特性：</strong> 规定发送比特流的时间顺序和动作序列（类似于“握手”协议的物理步骤）。</li></ul><h3>3. 信号编码 (Signal Encoding)</h3><p>计算机内部处理的是二进制数字信号，但在传输介质中，需要将其转换成适合传输的信号形式。</p><p><br></p><ul><li><strong>数字到数字（基带传输）：</strong></li><li class=\\\"ql-indent-1\\\"><strong>不归零编码 (NRZ)：</strong> 高电平代表 1，低电平代表 0。</li><li class=\\\"ql-indent-1\\\"><strong>曼彻斯特编码：</strong> 用信号中间的跳变来表示 0 或 1（例如：向上跳变是 1，向下是 0），这自带了时钟同步信号。</li><li><strong>数字到模拟（频带传输）：</strong></li><li class=\\\"ql-indent-1\\\">通过调制（ASK、FSK、PSK）将数字信号加载到模拟载波上，常见于移动通信和早期的拨号上网。</li></ul><h3>4. 同步方式 (Synchronization)</h3><p>为了确保接收方能准确识别发送方发出的每一个比特位，双方的时钟必须步调一致。</p><p><br></p><ul><li><strong>异步传输 (Asynchronous)：</strong> 以字符为单位传输。每个字符前后加上“起始位”和“停止位”。虽然简单，但开销较大（因为有很多冗余位）。</li><li><strong>同步传输 (Synchronous)：</strong> 以数据块为单位传输。发送方和接收方由同一个时钟源控制，或者从信号流中提取时钟信息。它的传输效率更高，适合高速通信。</li></ul><p><strong>介口码步</strong></p>\",\"correct\":\"传输介质,接口特性,信号编码,同步方式\",\"correctArray\":[],\"id\":162,\"items\":[],\"questionTitle\":\"<p>物理层的主要功能包括____、____、____、____</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-02 22:26:38', 75);
INSERT INTO `sys_oper_log` VALUES (702, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<h4>1. 封装成帧 (Framing)</h4><p>封装成帧是指在一段数据的<strong>前后分别添加首部和尾部</strong>，从而构成一个帧。</p><p><br></p><ul><li><strong>作用：</strong> 首部和尾部包含了很多控制信息（如地址、协议类型等），最重要的作用之一就是<strong>帧定界</strong>，让接收端能够从物理层收到的比特流中识别出一个帧的开始和结束。</li><li><strong>最大传送单元 (MTU)：</strong> 每种链路层协议都规定了帧的数据部分长度上限。</li></ul><h4>2. 透明传输 (Transparent Transmission)</h4><p>透明传输是指无论发送什么样的比特组合（即便数据中出现了和“帧定界符”一模一样的代码），都能够按照原样发送并正确接收。</p><p><br></p><ul><li><strong>问题所在：</strong> 如果数据中出现了与帧尾部标识符相同的字符，接收端会错误地认为帧已经结束。</li><li><strong>解决方法：</strong> * <strong>字节填充 (Byte Stuffing)：</strong> 在特殊字符前插入转义字符（如 <code>ESC</code>）。</li><li class=\\\"ql-indent-1\\\"><strong>比特填充 (Bit Stuffing)：</strong> 在特定数量的连续 <code>1</code> 之后强制插入一个 <code>0</code>（如 HDLC 协议）。</li></ul><h4>3. 差错检测 (Error Detection)</h4><p>现实中的通信链路并不是理想的，比特在传输过程中可能会产生<strong>差错</strong>（1 变成 0，或 0 变成 1）。</p><p><br></p><ul><li><strong>方法：</strong> 发送方在数据后添加<strong>检错码</strong>（如 <strong>CRC 循环冗余检验</strong>）。</li><li><strong>处理机制：</strong> 接收方收到帧后，通过 CRC 计算校验，如果发现有误，则丢弃该帧，以防错误数据交付给上层（网络层）。</li><li><br></li></ul><blockquote><strong>注意：</strong> 传统的以太网只负责“检错”而不负责“纠错”或“可靠传输”。如果需要可靠传输，通常由传输层（如 TCP）来处理。</blockquote><p><br></p>\",\"correct\":\"封装成帧,透明传输,差错检测\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>数据链路层的三个基本问题是__,__,__</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 12:25:22', 50);
INSERT INTO `sys_oper_log` VALUES (703, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<p>IP地址（以最常用的 IPv4 为例）是一个 32 位的二进制数值。为了方便管理和路由选择，它被逻辑地划分为两个层级结构：</p><p><br></p><h4>1. 网络号 (Network ID)</h4><ul><li><strong>作用：</strong> 标识互联网中特定的一个<strong>物理网络</strong>。</li><li><strong>地位：</strong> 同一个物理网络上的所有主机和路由器的端口，其网络号必须是相同的。路由器主要根据网络号来转发数据包。</li></ul><h4>2. 主机号 (Host ID)</h4><ul><li><strong>作用：</strong> 标识该特定网络中的某一台<strong>具体主机</strong>（或接口）。</li><li><strong>地位：</strong> 在同一个网络号范围内，主机号必须是唯一的。</li></ul><h3>如何区分这两部分？</h3><p>在实际应用中，我们不能一眼看出哪部分是网络号，哪部分是主机号，这取决于<strong>子网掩码 (Subnet Mask)</strong>：</p><p><br></p><ul><li><strong>子网掩码中为 \\\"1\\\" 的位</strong>：对应 IP 地址中的网络号部分。</li><li><strong>子网掩码中为 \\\"0\\\" 的位</strong>：对应 IP 地址中的主机号部分。</li></ul><h4>示例：</h4><p>假设 IP 地址为 <code>192.168.1.10</code>，子网掩码为 <code>255.255.255.0</code>：</p><p><br></p><ul><li><strong>网络号</strong>是：<code>192.168.1</code></li><li><strong>主机号</strong>是：<code>10</code></li></ul><p>这意味着这台设备处于 <code>192.168.1.0</code> 这个网络中，它是该网络里的第 <code>10</code> 号主机。</p>\",\"correct\":\"网络标识,主机标识\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>IP地址由__、__两部分组成。</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 12:34:24', 26);
INSERT INTO `sys_oper_log` VALUES (704, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<p>TCP 协议中，流量控制是通过<strong>滑动窗口 (Sliding Window)</strong> 机制实现的。</p><h3>详细解析</h3><p>流量控制（Flow Control）的目的是为了让<strong>发送方的发送速率不要太快</strong>，要让接收方来得及接收，防止由于接收端缓冲区溢出而导致的数据丢失。</p><p><br></p><h4>1. 工作原理：接收窗口 (rwnd)</h4><p>在 TCP 报文段的首部中，有一个 16 位的“<strong>窗口 (Window)</strong>”字段。</p><p><br></p><ul><li><strong>通知机制：</strong> 接收方在发送确认报文（ACK）时，会将自己目前的接收缓冲区剩余大小填入这个字段，告知发送方。这个值被称为<strong>接收窗口 (rwnd, receiver window)</strong>。</li><li><strong>发送限制：</strong> 发送方在发送数据时，必须保证：<strong>已发送但未收到确认的数据量 ≤ 接收方通告的窗口大小</strong>。</li></ul><h4>2. “滑动”的含义</h4><p>之所以称为“滑动窗口”，是因为随着数据的发送和确认：</p><p><br></p><ul><li>当发送方收到新的 ACK 时，窗口的左边界会向右移动（代表数据已成功交付）。</li><li>根据接收方反馈的新窗口大小，窗口的右边界也会相应调整（代表允许发送的新数据范围）。</li></ul><h4>3. 零窗口与持续计时器 (Persist Timer)</h4><p>如果接收方的缓冲区满了，它会发送一个 <code>window = 0</code> 的报文。此时发送方必须停止发送。</p><p><br></p><ul><li><strong>潜在问题：</strong> 如果之后接收方缓冲区有了空间并发送了窗口更新报文，但该报文在网络中丢失了，双方就会陷入死锁。</li><li><strong>解决方法：</strong> TCP 为每一个连接设有一个<strong>持续计时器</strong>。只要发送方收到零窗口通知，就启动计时器。若超时，发送方会发送一个极小的“<strong>零窗口探测报文</strong>”，迫使接收方再次告知当前的窗口状态。</li></ul><h3>💡 易混淆概念：流量控制 vs 拥塞控制</h3><ul><li><strong>流量控制：</strong> 是<strong>端到端</strong>的问题。解决的是“发送方发太快，接收方处理不过来”的问题。</li><li><strong>拥塞控制：</strong> 是<strong>全局性</strong>的问题。解决的是“网络中数据太多，导致路由器排队或丢包”的问题（涉及慢启动、拥塞避免等算法）。</li></ul><p><br></p>\",\"correct\":\"滑动窗口\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>TCP 协议中，流量控制是通过__机制实现的。</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 12:36:40', 33);
INSERT INTO `sys_oper_log` VALUES (705, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"correct\":\"非流水线持久连接,流水线持久连接\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>HTTP协议中，持久连接分为__、__两种方式。</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 12:37:19', 27);
INSERT INTO `sys_oper_log` VALUES (706, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<p>在网络安全中，用于验证消息完整性的技术是 <strong>散列函数 (Hash Function)</strong> 或 <strong>消息认证码 (MAC)</strong>（也可以填 <strong>数字签名</strong>）。</p><h3>详细解析</h3><p>完整性（Integrity）是指确保信息在传输或存储过程中<strong>未被未经授权地篡改或损坏</strong>。为了实现这一目标，通常会使用以下几种技术：</p><h4>1. 散列函数 (Hash Function / Cryptographic Hash)</h4><ul><li><strong>原理：</strong> 将任意长度的消息映射为固定长度的“指纹”或“摘要”（Digest）。常用的算法有 SHA-256、SM3 等。</li><li><strong>特点：</strong> 只要原始数据发生 1 比特的改变，生成的散列值就会发生巨大的变化（雪崩效应）。</li><li><strong>局限：</strong> 仅靠散列函数无法防御“中间人攻击”。如果攻击者同时修改了消息和散列值，接收者无法察觉。因此，散列值通常需要配合加密技术使用。</li></ul><h4>2. 消息认证码 (MAC, Message Authentication Code)</h4><ul><li><strong>原理：</strong> 在散列函数的基础上引入了<strong>共享密钥</strong>。发送方使用密钥对消息计算 MAC 值，接收方使用同一个密钥进行验证。</li><li><strong>作用：</strong> 它不仅能验证<strong>完整性</strong>（数据没变），还能实现<strong>身份认证</strong>（确认消息确实来自持有密钥的发送者）。</li><li><strong>常见算法：</strong> HMAC（基于哈希的消息认证码）。</li></ul><h4>3. 数字签名 (Digital Signature)</h4><ul><li><strong>原理：</strong> 结合了散列函数和<strong>非对称加密</strong>（公钥/私钥）。发送方用自己的私钥对消息摘要进行签名。</li><li><strong>作用：</strong> 除了提供<strong>完整性</strong>和<strong>身份认证</strong>，数字签名还具备<strong>不可否认性</strong>（Non-repudiation），即发送者事后无法抵赖发送过该消息。</li></ul><h3>技术对比表</h3><p><strong>技术完整性验证身份认证不可否认性核心工具散列函数</strong>✅❌❌算法 (如 SHA-256)<strong>消息认证码 (MAC)</strong>✅✅❌共享密钥 + 算法<strong>数字签名</strong>✅✅✅私钥 + 散列函数</p>\",\"correct\":\"数字签名,散列函数\",\"correctArray\":[],\"items\":[],\"questionTitle\":\"<p>网络安全中，用于验证消息完整性的技术是__或__</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 12:40:08', 22);
INSERT INTO `sys_oper_log` VALUES (707, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<p>在网络安全中，用于验证消息完整性的技术是 <strong>散列函数 (Hash Function)</strong> 或 <strong>消息认证码 (MAC)</strong>（也可以填 <strong>数字签名</strong>）。</p><p><br></p><h3>详细解析</h3><p>完整性（Integrity）是指确保信息在传输或存储过程中<strong>未被未经授权地篡改或损坏</strong>。为了实现这一目标，通常会使用以下几种技术：</p><p><br></p><h4>1. 散列函数 (Hash Function / Cryptographic Hash)</h4><ul><li><strong>原理：</strong> 将任意长度的消息映射为固定长度的“指纹”或“摘要”（Digest）。常用的算法有 SHA-256、SM3 等。</li><li><strong>特点：</strong> 只要原始数据发生 1 比特的改变，生成的散列值就会发生巨大的变化（雪崩效应）。</li><li><strong>局限：</strong> 仅靠散列函数无法防御“中间人攻击”。如果攻击者同时修改了消息和散列值，接收者无法察觉。因此，散列值通常需要配合加密技术使用。</li></ul><h4>2. 消息认证码 (MAC, Message Authentication Code)</h4><ul><li><strong>原理：</strong> 在散列函数的基础上引入了<strong>共享密钥</strong>。发送方使用密钥对消息计算 MAC 值，接收方使用同一个密钥进行验证。</li><li><strong>作用：</strong> 它不仅能验证<strong>完整性</strong>（数据没变），还能实现<strong>身份认证</strong>（确认消息确实来自持有密钥的发送者）。</li><li><strong>常见算法：</strong> HMAC（基于哈希的消息认证码）。</li></ul><h4>3. 数字签名 (Digital Signature)</h4><ul><li><strong>原理：</strong> 结合了散列函数和<strong>非对称加密</strong>（公钥/私钥）。发送方用自己的私钥对消息摘要进行签名。</li><li><strong>作用：</strong> 除了提供<strong>完整性</strong>和<strong>身份认证</strong>，数字签名还具备<strong>不可否认性</strong>（Non-repudiation），即发送者事后无法抵赖发送过该消息。</li></ul><h3>技术对比表</h3><p><strong>技术完整性验证身份认证不可否认性核心工具散列函数</strong>✅❌❌算法 (如 SHA-256)<strong>消息认证码 (MAC)</strong>✅✅❌共享密钥 + 算法<strong>数字签名</strong>✅✅✅私钥 + 散列函数</p>\",\"correct\":\"数字签名,散列函数\",\"correctArray\":[],\"id\":167,\"items\":[],\"questionTitle\":\"<p>网络安全中，用于验证消息完整性的技术是__或__</p>\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 12:42:22', 82);
INSERT INTO `sys_oper_log` VALUES (708, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"<h3>答案详解</h3><ul><li><strong>正确答案：</strong> 指数（或 二倍、$2^n$）</li><li><strong>增长机制：</strong> 在慢启动阶段，每当发送方接收到一个确认报文段（ACK）时，拥塞窗口的大小就会加 1（以最大报文段长度 MSS 为单位）。</li><li><strong>数学规律：</strong> 假设初始窗口为 1。</li></ul><ol><li class=\\\"ql-indent-1\\\">发送 1 个报文段，收到 1 个 ACK $\\\\rightarrow$ 窗口变成 <strong>2</strong>。</li><li class=\\\"ql-indent-1\\\">发送 2 个报文段，收到 2 个 ACK $\\\\rightarrow$ 窗口变成 <strong>4</strong>。</li><li>发送 4 个报文段，收到 4 个 ACK $\\\\rightarrow$ 窗口变成 8。</li><li class=\\\"ql-indent-1\\\">以此类推，窗口大小随传输轮次（RTT）呈 $2^n$ 的指数级增长。</li></ol><h3>为什么叫“慢”启动？</h3><p>虽然它的增长速度很快（指数级），但之所以被称为“慢”启动，是因为它在连接建立之初将拥塞窗口设置为 <strong>1 个 MSS</strong>。其目的是为了探测网络的承受能力，避免在一开始就向网络注入大量数据导致拥塞。</p><h3>阶段转换：慢启动阈值 (ssthresh)</h3><p>慢启动并不会无限持续。当拥塞窗口大小达到 <strong>慢启动阈值（ssthresh）</strong> 时，TCP 就会停止指数增长，转而进入 <strong>拥塞避免（Congestion Avoidance）</strong> 阶段，此时窗口增长变为 <strong>线性增长</strong>（加性增加）。</p>\",\"analysisFormat\":\"html\",\"correct\":\"指数\",\"correctArray\":[],\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>在 TCP拥塞控制中，慢启动阶段拥塞窗口大小按__增长。</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 16:13:32', 581);
INSERT INTO `sys_oper_log` VALUES (709, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"常用的多路复用技术包括 **频分复用（FDM）**、**时分复用（TDM）**、**波分复用（WDM）**。\\n\\n（注：在不同的考试或教材语境下，**码分复用（CDM）** 也常被列为四大常用技术之一。）\\n\\n* * *\\n\\n### 详细解析\\n\\n多路复用（Multiplexing）技术是为了提高传输线路的利用率，让多个用户或多个信号能够同时共享同一条物理信道。\\n\\n| 技术名称     | 英文全称 | 核心原理                                             | 典型应用               |\\n| ------------ | -------- | ---------------------------------------------------- | ---------------------- |\\n| **频分复用** | **FDM**  | 将信道带宽划分为多个子频带，每个信号占用一个频带。   | 无线广播、有线电视     |\\n| **时分复用** | **TDM**  | 将传输时间划分为等长的时隙，每个信号占用一个时隙。   | 电话网络（PCM）、GSM   |\\n| **波分复用** | **WDM**  | **光的频分复用**。在一根光纤中传输不同波长的光信号。 | 光纤骨干网             |\\n| **码分复用** | **CDM**  | 利用不同的码序列（正交码）来区分不同用户的信号。     | 3G/4G 移动通信（CDMA） |\\n\\n* * *\\n\\n### 技术特点对比\\n\\n1.  **频分复用 (FDM)**：所有信号在时间上是**并行**的，但在频率上是**隔离**的。为了防止干扰，各子信道间通常留有“保护频带”。\\n2.  **时分复用 (TDM)**：所有信号在频率上是相同的，但在时间上是**轮流**的。现代通信多使用**统计时分复用（STDM）**，它能根据需求动态分配时隙，效率更高。\\n3.  **波分复用 (WDM)**：本质上是在光通信领域应用的 FDM。\\n\\n频分复用类似短跑同时跑\\n时分复用相当于长跑在内道串行跑步\",\"analysisFormat\":\"markdown\",\"correct\":\"频分复用,时分复用,波分复用\",\"correctArray\":[],\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>常用的多路复用技术包括__、__、__。</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 16:19:06', 47);
INSERT INTO `sys_oper_log` VALUES (710, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"OSI 七层模型是理论上的“标准”，而 TCP/IP 四层模型是事实上的“标准”。简而言之，TCP/IP 是对 OSI 七层模型的简化和合并。\\n\\n它们的对应关系可以用 **“上三合一，下二合一”** 来快速记忆：\\n\\n* * *\\n\\n### OSI 七层与 TCP/IP 四层对应表\\n\\n| OSI 七层模型层级               | 对应关系     | TCP/IP 四层模型层级    | 常见协议 / 硬件       |\\n| ------------------------------ | ------------ | ---------------------- | --------------------- |\\n| **7\\\\. 应用层** (Application)   | 合并为       | **1\\\\. 应用层**         | HTTP, FTP, DNS, SMTP  |\\n| **6\\\\. 表示层** (Presentation)  | $\\\\uparrow$   |                        | (处理数据格式、加密)  |\\n| **5\\\\. 会话层** (Session)       | $\\\\uparrow$   |                        | (管理会话连接)        |\\n| **4\\\\. 传输层** (Transport)     | **一一对应** | **2\\\\. 传输层**         | **TCP, UDP**          |\\n| **3\\\\. 网络层** (Network)       | **一一对应** | **3\\\\. 网际层** (IP 层) | **IP**, ICMP, ARP     |\\n| **2\\\\. 数据链路层** (Data Link) | 合并为       | **4\\\\. 网络接口层**     | 以太网、Wi-Fi、交换机 |\\n| **1\\\\. 物理层** (Physical)      | $\\\\downarrow$ | (也称网络访问层)       | 网线、集线器、比特流  |\\n\\n* * *\\n\\n### 关键点解析\\n\\n1.  **“上三层”合并：** 在 OSI 模型中，应用、表示、会话层分工明确（如加密属于表示层）。但在 TCP/IP 模型中，这些功能都统称为**应用层**。这更符合软件开发的实际情况，因为程序员在写程序时，通常会把这些逻辑都写在同一个应用进程里。\\n2.  **中间两层不变：** **传输层**和**网络层**（网际层）是互联网的核心，无论在哪个模型里都是独立且极其重要的。你可以把它们想象成网络通信的“腰部”。\\n3.  **“下两层”合并：** OSI 严格区分了**物理硬件**（物理层）和**数据链路**（如 MAC 地址、帧封装）。TCP/IP 将其合并为**网络接口层**，因为它主要关注如何将 IP 数据报发送到特定的物理网络上。\\n\\n* * *\\n\\n### 考试技巧：TCP/IP 到底几层？\\n\\n*   **四层模型**：这是最经典的（如上表）。\\n*   **五层模型**：这是教学中常用的（为了方便对比，把 TCP/IP 的底层重新拆回物理层和数据链路层）。如果考试问“五层”，通常指的是：应用层、传输层、网络层、数据链路层、物理层。\",\"analysisFormat\":\"markdown\",\"correct\":\"0SI应用层、表示展、会话层-TCP/IP应用层\\n\\n0SI传输层→ TCP/IP 传输层\\n\\n0SI网络层→ TCP/IP网络层\\n\\n0SI数据链路层、物理层 → TCP/IP 网络接口层 \",\"correctArray\":[],\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>简述 0SI七层模型与 TCP/IP四层模型的对应关系</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 16:24:16', 55);
INSERT INTO `sys_oper_log` VALUES (711, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"OSI 七层模型是理论上的“标准”，而 TCP/IP 四层模型是事实上的“标准”。简而言之，TCP/IP 是对 OSI 七层模型的简化和合并。\\n\\n它们的对应关系可以用 **“上三合一，下二合一”** 来快速记忆：\\n\\n* * *\\n\\n### OSI 七层与 TCP/IP 四层对应表\\n\\n| OSI 七层模型层级               | 对应关系     | TCP/IP 四层模型层级    | 常见协议 / 硬件       |\\n| ------------------------------ | ------------ | ---------------------- | --------------------- |\\n| **7\\\\. 应用层** (Application)   | 合并为       | **1\\\\. 应用层**         | HTTP, FTP, DNS, SMTP  |\\n| **6\\\\. 表示层** (Presentation)  | $\\\\uparrow$   |                        | (处理数据格式、加密)  |\\n| **5\\\\. 会话层** (Session)       | $\\\\uparrow$   |                        | (管理会话连接)        |\\n| **4\\\\. 传输层** (Transport)     | **一一对应** | **2\\\\. 传输层**         | **TCP, UDP**          |\\n| **3\\\\. 网络层** (Network)       | **一一对应** | **3\\\\. 网络层** (IP 层) | **IP**, ICMP, ARP     |\\n| **2\\\\. 数据链路层** (Data Link) | 合并为       | **4\\\\. 网络接口层**     | 以太网、Wi-Fi、交换机 |\\n| **1\\\\. 物理层** (Physical)      | $\\\\downarrow$ | (也称网络访问层)       | 网线、集线器、比特流  |\\n\\n* * *\\n\\n### 关键点解析\\n\\n1.  **“上三层”合并：** 在 OSI 模型中，应用、表示、会话层分工明确（如加密属于表示层）。但在 TCP/IP 模型中，这些功能都统称为**应用层**。这更符合软件开发的实际情况，因为程序员在写程序时，通常会把这些逻辑都写在同一个应用进程里。\\n2.  **中间两层不变：** **传输层**和**网络层**（网际层）是互联网的核心，无论在哪个模型里都是独立且极其重要的。你可以把它们想象成网络通信的“腰部”。\\n3.  **“下两层”合并：** OSI 严格区分了**物理硬件**（物理层）和**数据链路**（如 MAC 地址、帧封装）。TCP/IP 将其合并为**网络接口层**，因为它主要关注如何将 IP 数据报发送到特定的物理网络上。\\n\\n* * *\\n\\n### 考试技巧：TCP/IP 到底几层？\\n\\n*   **四层模型**：这是最经典的（如上表）。\\n*   **五层模型**：这是教学中常用的（为了方便对比，把 TCP/IP 的底层重新拆回物理层和数据链路层）。如果考试问“五层”，通常指的是：应用层、传输层、网络层、数据链路层、物理层。\",\"analysisFormat\":\"markdown\",\"correct\":\"0SI应用层、表示展、会话层-TCP/IP应用层\\n\\n0SI传输层→ TCP/IP 传输层\\n\\n0SI网络层→ TCP/IP网络层\\n\\n0SI数据链路层、物理层 → TCP/IP 网络接口层 \",\"correctArray\":[],\"id\":170,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>简述 0SI七层模型与 TCP/IP四层模型的对应关系</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":4}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 16:30:22', 57);
INSERT INTO `sys_oper_log` VALUES (712, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.43.2', 'XX XX', '{\"analysis\":\"\\n**CSMA/CD** 的全称是 **载波监听多点接入/碰撞检测**（Carrier Sense Multiple Access with Collision Detection）。\\n\\n它是以太网中最为经典的一种协议。如果把信道比作一个房间，把数据包比作说话，它的核心逻辑就是：**“先听后说，边说边听；一旦冲突，立即停说，等待重发。”**\\n\\n* * *\\n\\n### 一、 CSMA/CD 的工作过程\\n\\n我们可以将其拆解为四个关键步骤：\\n\\n1.  **先听后说（载波监听）：** 发送数据前，节点会先检测信道上是否有信号在传输。\\n    *   若信道**忙**：继续等待，直到信道空闲。\\n    *   若信道**闲**：等待一个极短的时间（帧间最小间隔）后，开始发送数据。\\n2.  **边说边听（碰撞检测）：** 节点在发送数据帧的过程中，会持续监测信道电压。\\n    *   由于电信号在导线上传播需要时间，可能会出现两个节点同时检测到“空闲”并同时发报的情况，导致信号重叠，即\\\\*\\\\*“碰撞（冲突）”\\\\*\\\\*。\\n3.  **冲突停说（强化告知）：** 一旦检测到碰撞，节点立即停止发送该数据帧，并发送一个 **人为干扰信号（Jamming Signal）**。\\n    *   目的是让网络上所有节点都知道发生了冲突，让大家一起停止发送。\\n4.  **随机重发（二进制指数退避）：** 为了避免两个节点在停止后又同时尝试重发，它们会执行“退避算法”。\\n    *   每个节点随机等待一段时间，再回到第一步重新尝试。等待的时间通常采用 **二进制指数退避算法**。\\n简单来说，**共享式以太网（Shared Ethernet）** 就像是\\\\*\\\\*“一群人在同一个房间里用同一个麦克风说话”\\\\*\\\\*。\\n\\n它是早期局域网的主流组网方式，以下是它的详细定义和特点：\\n\\n### 1\\\\. 核心定义\\n\\n在共享式以太网中，所有的计算机都连接到**同一根传输介质**（如早期的同轴电缆）或同一个\\\\*\\\\*集线器（Hub）\\\\*\\\\*上。\\n\\n*   **共享带宽**：如果网络总带宽是 10Mbps，有 10 台电脑，那么这 10 台电脑要平分这 10Mbps。\\n*   **单一冲突域**：在同一时刻，**只能有一台**电脑发送数据。如果两台电脑同时说话，信号就会在电缆里“撞车”（冲突），导致谁也听不清。\\n\\n### 2\\\\. 硬件标志：集线器（Hub）\\n\\n如果你看到网络连接的核心设备是 **集线器（Hub）** 而不是 **交换机（Switch）**，那么这个网络就是共享式以太网。\\n\\n*   集线器是个“傻瓜”设备：它收到一个数据包后，会盲目地广播给所有端口，不管是不是发给你的，你都会收到。\\n\\n### 3\\\\. 为什么它需要 CSMA/CD？\\n\\n正因为大家都在抢同一个通道，所以必须有一套规则来维持秩序。这就是你前面问到的 **CSMA/CD**：\\n\\n*   **先听再讲**：看看有没有人在用线。\\n*   **边听边讲**：一旦发现别人也在讲（冲突），立刻闭嘴。\\n\\n*   * *\\n\\n### 4\\\\. 共享式 vs. 交换式（现代网络）\\n\\n为了让你更清楚，我们对比一下现在的网络：\\n\\n| 特性         | 共享式以太网 (老旧)        | 交换式以太网 (现代)          |\\n| ------------ | -------------------------- | ---------------------------- |\\n| **核心设备** | **集线器 (Hub)**           | **交换机 (Switch)**          |\\n| **通信方式** | 半双工（不能同时收发）     | 全双工（可以同时收发）       |\\n| **带宽分配** | 所有人共享总带宽           | 每个接口独享带宽             |\\n| **冲突风险** | 经常碰撞，需要 CSMA/CD     | **无碰撞**，不再需要 CSMA/CD |\\n| **形象比喻** | 像单车道，对面来车得停下等 | 像双向多车道，各走各的       |\\n\\n### 总结\\n\\n**共享式以太网**就是指那些使用**集线器**连接、所有设备处于**同一个冲突域**、必须依靠 **CSMA/CD** 协议来协调数据发送的有线局域网。\\n\\n虽然现在家庭和办公室基本都换成了交换机（交换式以太网），但在计算机网络的考试和教材中，它仍然是理解网络基础逻辑（如碰撞检测）的核心场', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-03 16:36:31', 34);
