\"id\":147,\"itemOrder\":3,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"填666\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":2}]},{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"<p><img src=\\\"https://daming-paper.oss-cn-guangzhou.aliyuncs.com/quiz/paper/answer/2025/11/24/0ab473366e94454fa6c55e5f55db8e93.jpg\\\"></p>\",\"analysisFormat\":\"html\",\"correct\":\"666\",\"correctFormat\":\"html\",\"id\":145,\"itemOrder\":4,\"items\":[],\"', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-05 12:44:27', 126);
