INSERT INTO `sys_oper_log` VALUES (774, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">分层的DFD图可以用于可行性研究阶段，描述系统的物理结构。( )</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":4,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:29:47', 22);
INSERT INTO `sys_oper_log` VALUES (775, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><br></p><p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">在需求分析阶段主要采用图形工具来描述的原因是图形的信息量大，图形容易画，同时便于描述规模大的软件系统。( )</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":4,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:31:02', 26);
INSERT INTO `sys_oper_log` VALUES (776, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>答案是：<strong>正确 (√)</strong>。</p><h3>💡 大白话解析</h3><p>我们可以把<strong>状态图</strong>想象成一个人的“<strong>入职到离职</strong>”或者“<strong>APP 运行</strong>”的过程：</p><p><br></p><ul><li><strong>初态（起点）只能有一个</strong>：</li><li>一个逻辑的开始必须是明确的。你不能同时从两个不同的地方“出生”或者“启动”。所以，状态图里用<strong>实心黑圆点</strong>表示的初态，必须有且仅有一个。</li><li><strong>终态（终点）可以有多个</strong>：</li><li>事情的结局往往不止一种。</li><li class=\\\"ql-indent-1\\\">比如<strong>购物流程</strong>：最后可能是“交易成功”，也可能是“取消订单”，还可能是“退款完成”。这些都是终点。</li><li class=\\\"ql-indent-1\\\">在图中用<strong>牛眼圆圈</strong>（圆圈内套一个实心圆点）表示。</li><li><strong>终态可以没有</strong>：</li><li>有些系统是<strong>永不停歇</strong>的。</li><li class=\\\"ql-indent-1\\\">比如<strong>操作系统</strong>的调度逻辑，或者是<strong>时钟</strong>的走动逻辑。只要不断电，它就在几个状态之间反复横跳，永远不会进入“终止”状态。</li></ul><h3>总结考点：</h3><ol><li><strong>初态</strong>：必须有，且只能有一个。</li><li><strong>终态</strong>：可以没有，也可以有 1 到 N 个。</li></ol><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><br></p><p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(32, 32, 32);\\\">在一张状态图中只能有一个初态，而终态则可以没有，也可以有多个。( )</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":4,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:31:41', 15);
