INSERT INTO `sys_oper_log` VALUES (783, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>软件可靠性定义表明了一个程序按照用户的要求和设计的目标，执行其功能的正确程度。一个可靠的程序应要求是正确的、完整</p><p>的、一致的和健壮的，是指能够以数字概念来描述可靠性的数学表达式中所使用的量。</p><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>硬件可靠性的定量度量</p>\",\"prefix\":\"A\"},{\"content\":\"<p>软件可靠性的定量指标</p>\",\"prefix\":\"B\"},{\"content\":\"<p>系统的定量度量</p>\",\"prefix\":\"C\"},{\"content\":\"<p>可靠性的度量</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>（ ）是指能够以数字概念来描述可靠性的数学表达式中所使用的量。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:47:29', 24);
INSERT INTO `sys_oper_log` VALUES (784, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>代码行度量</p>\",\"prefix\":\"A\"},{\"content\":\"<p>环路度量</p>\",\"prefix\":\"B\"},{\"content\":\"<p>程序量度量</p>\",\"prefix\":\"C\"},{\"content\":\"<p>功能性度量</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>McCabe复杂性度量又称为（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:48:23', 21);
INSERT INTO `sys_oper_log` VALUES (785, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(168, 168, 179);\\\">McCabe度量法是由Thomas McCabe提出的一种基于程序控制流的复杂性度量方法。McCabe复杂性度量又称环路度量，它认为程序的复杂性很大程度上取决于控制的复杂性。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":228,\"items\":[{\"content\":\"<p>代码行度量</p>\",\"prefix\":\"A\"},{\"content\":\"<p>环路度量</p>\",\"prefix\":\"B\"},{\"content\":\"<p>程序量度量</p>\",\"prefix\":\"C\"},{\"content\":\"<p>功能性度量</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>McCabe复杂性度量又称为（ ）。</h3>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:48:41', 16);
INSERT INTO `sys_oper_log` VALUES (786, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>通用性</p>\",\"prefix\":\"A\"},{\"content\":\"<p>效率</p>\",\"prefix\":\"B\"},{\"content\":\"<p>质量</p>\",\"prefix\":\"C\"},{\"content\":\"<p> 人机界面</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>软件可移植性是用来衡量软件的（ ）重要尺度之一。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:49:25', 13);
INSERT INTO `sys_oper_log` VALUES (787, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>错误检测</p>\",\"prefix\":\"A\"},{\"content\":\"<p>故障排除</p>\",\"prefix\":\"B\"},{\"content\":\"<p>调试</p>\",\"prefix\":\"C\"},{\"content\":\"<p>测试</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>从已经发现故障的存在到找到准确的故障位置并确定故障的性质，这一过程称为（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:50:06', 13);
INSERT INTO `sys_oper_log` VALUES (788, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>回归测试指在软件维护阶段，为了检测代码修改而引入的错误所进行的测试活动。回归测试是软件维护阶段的重要工作，同时也</p><p>是校正性维护中最常用的方法。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>校正性维护</p>\",\"prefix\":\"A\"},{\"content\":\"<p>适应性维护</p>\",\"prefix\":\"B\"},{\"content\":\"<p> 完善性维护</p>\",\"prefix\":\"C\"},{\"content\":\"<p>预防性维护</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>回归测试是（ ）中最常用的方法。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:50:48', 15);
INSERT INTO `sys_oper_log` VALUES (789, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><br></p><p>在模块测试过程中，自底向上的测试随着上移，驱动模块逐步减少，测试开销小，而自顶向上的测试需要设计较多的桩模块，测</p><p>试开销大，所以采用自底向上的测试比自顶向下的测试好。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>好</p>\",\"prefix\":\"A\"},{\"content\":\"<p>差</p>\",\"prefix\":\"B\"},{\"content\":\"<p>一样</p><p><br></p>\",\"prefix\":\"C\"},{\"content\":\"<p>未知</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>在模块测试的过程中，采用自底向上的测试比自顶向下的测试（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:51:29', 13);
INSERT INTO `sys_oper_log` VALUES (790, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(168, 168, 179);\\\">测试是对软件规格说明、设计和编码的最后复审，所以软件测试贯穿在整个软件开发期的全过程。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>程序编程阶段</p>\",\"prefix\":\"A\"},{\"content\":\"<p>软件开发全过程</p>\",\"prefix\":\"B\"},{\"content\":\"<p>软件允许阶段</p>\",\"prefix\":\"C\"},{\"content\":\"<p>软件设计阶段</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>软件测试是保证软件质量的重要措施，它的实施应该在（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:53:02', 17);
INSERT INTO `sys_oper_log` VALUES (791, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><br></p><h3><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(168, 168, 179);\\\">软件开发需求分析对应的是测试阶段的确认测试，软件设计对应的是集成测试（组装测试），编码阶段对应的是单元测试。</span></h3><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>组装测试、确认测试、单元测试</p><p><br></p>\",\"prefix\":\"A\"},{\"content\":\"<p>单元测试、组装测试、确认测试</p>\",\"prefix\":\"B\"},{\"content\":\"<p> 单元测试、确认测试、组装测试</p>\",\"prefix\":\"C\"},{\"content\":\"<p>确认测试、组装测试、单元测试</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>从下列叙述中选出能够与软件开发需求分析、设计、编码相对应的软件测试（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:54:40', 13);
INSERT INTO `sys_oper_log` VALUES (792, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>使用的方便性</p>\",\"prefix\":\"A\"},{\"content\":\"<p>简洁性</p>\",\"prefix\":\"B\"},{\"content\":\"<p>可靠性</p>\",\"prefix\":\"C\"},{\"content\":\"<p>设备独立性</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>为了提高软件的可移植性，应注意提高软件的（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:55:45', 17);
INSERT INTO `sys_oper_log` VALUES (793, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><br></p><p>因果图的基本原理是通过画因果图，把自然语言描述的功能说明转换为判定表，最后为判定表的每一列设计一个测试用例，它能</p><p>有效地检测输入条件的各种组合可能会引起的错误。</p>\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>等价类划分法</p>\",\"prefix\":\"A\"},{\"content\":\"<p>边界值分析法</p>\",\"prefix\":\"B\"},{\"content\":\"<p>错误推测法</p>\",\"prefix\":\"C\"},{\"content\":\"<p> 因果图法</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>在黑盒测试中，着重检查输入条件的组合是（ ）。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:58:36', 14);
INSERT INTO `sys_oper_log` VALUES (794, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><br></p><p>单元测试主要从下面五个基本特征进行测试，分别是：模块接口、局部数据结构、独立路径和出错处理。而系统功能通常是在系</p><p>统测试时进行的。</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>系统功能</p>\",\"prefix\":\"A\"},{\"content\":\"<p>局部数据结构</p>\",\"prefix\":\"B\"},{\"content\":\"<p>重要的执行路径</p>\",\"prefix\":\"C\"},{\"content\":\"<p>错误处理</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>单元测试主要针对模块的几个基本特征进行测试，该阶段不能完成的测试是（ ）。</h3><p> </p><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 15:59:53', 18);
