INSERT INTO `sys_oper_log` VALUES (800, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>等价类划分</p>\",\"prefix\":\"A\"},{\"content\":\"<p>边界值分析</p>\",\"prefix\":\"B\"},{\"content\":\"<p>因果图</p>\",\"prefix\":\"C\"},{\"content\":\"<p>判定表</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>在设计测试用例时，( )是用得最多的一种黑盒测试方法。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:12:21', 14);
INSERT INTO `sys_oper_log` VALUES (801, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>对象模型、动态模型、功能模型</p>\",\"prefix\":\"A\"},{\"content\":\"<p>对象模型、数据模型、功能模型</p>\",\"prefix\":\"B\"},{\"content\":\"<p>数据模型、动态模型、功能模型</p>\",\"prefix\":\"C\"},{\"content\":\"<p>对象模型、动态模型、数据模型</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>面向对象模型主要由以下哪些模型组成( )</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:16:13', 14);
INSERT INTO `sys_oper_log` VALUES (802, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>答案是：<strong>B、边界值分析测试</strong>。</p><h3>💡 大白话解析</h3><p>要区分白盒和黑盒测试，最简单的办法就是看测试员**“盯着哪儿看”**：</p><p><br></p><ul><li><strong>白盒测试（看代码内部）</strong>：测试员像有“透视眼”一样，盯着程序的<strong>源代码、逻辑结构、路径</strong>去测。</li><li class=\\\"ql-indent-1\\\"><strong>A、基本路径测试</strong>：检查代码里的每一条路是不是都能走通。</li><li class=\\\"ql-indent-1\\\"><strong>C、循环覆盖测试</strong>：专门盯着 <code>for</code> 或 <code>while</code> 循环，看循环 0 次、1 次、多次有没有问题。</li><li class=\\\"ql-indent-1\\\"><strong>D. 逻辑覆盖测试</strong>：看代码里的 <code>if...else</code> 判定条件是否都执行到了。</li><li><strong>黑盒测试（只看输入输出）</strong>：测试员把软件当成一个“看不见内部的黑盒子”。他不关心代码怎么写，只关心：<strong>我输入这个，你能不能给我正确的结果？</strong></li><li class=\\\"ql-indent-1\\\"><strong>B、边界值分析测试</strong>：这就是典型的黑盒法。比如输入框规定填 1-100，我试一下 1 和 100。我不需要看代码是怎么写的，我只需要看界面反馈对不对。</li></ul><h3>🚀 考试速记口诀</h3><ul><li><strong>白盒看“逻辑”</strong>：只要选项里带**“覆盖”<strong>、</strong>“路径”<strong>、</strong>“结构”**，基本都是白盒。</li><li><strong>黑盒看“数据”</strong>：只要选项里带**“等价类”<strong>、</strong>“边界值”<strong>、</strong>“错误推测”<strong>、</strong>“因果图”**，都是黑盒。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(24, 30, 51);\\\">基本路径测试</span></p>\",\"prefix\":\"A\"},{\"content\":\"<p>边界值分析测试</p><p><br></p>\",\"prefix\":\"B\"},{\"content\":\"<p>循环覆盖测试</p>\",\"prefix\":\"C\"},{\"content\":\"<p>逻辑覆盖测试</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>以下哪种测试方法不属于白盒测试技术( )</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:17:39', 22);
INSERT INTO `sys_oper_log` VALUES (803, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"OOA,OOD,OOP\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>软件的面向对象开发方法包括____ ， ____，&nbsp;____三部分。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:18:37', 13);
INSERT INTO `sys_oper_log` VALUES (804, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"单元测试,集成测试,确认测试\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>面向对象的软件测试策略一般包括 ____、____、和____等三个步骤。</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:19:12', 14);
INSERT INTO `sys_oper_log` VALUES (805, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<h3>耦合用于衡量一个模块内部的各个元素彼此结合的紧密程度。( )</h3><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":4,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:19:24', 16);
INSERT INTO `sys_oper_log` VALUES (806, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>内容耦合&lt;控制耦合&lt;标记耦合&lt;数据耦合</p>\",\"prefix\":\"A\"},{\"content\":\"<p>数据耦合&lt;控制耦合&lt;标记耦合&lt;内容耦合</p>\",\"prefix\":\"B\"},{\"content\":\"<p>数据耦合&lt;标记耦合&lt;控制耦合&lt;内容耦合</p>\",\"prefix\":\"C\"},{\"content\":\"<p>标记耦合&lt;数据耦合&lt;控制耦合&lt;内容耦合</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">在耦合度从低到高的排序中，下列哪组排序是正确的？</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:28:00', 12);
INSERT INTO `sys_oper_log` VALUES (807, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><span style=\\\"background-color: rgb(196, 238, 208); color: rgb(31, 31, 31);\\\">传递整个数据结构而非单一数据项，即为标记耦合。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"A\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"<p>标记耦合（Stamp Coupling)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>数据耦合</p>\",\"prefix\":\"B\"},{\"content\":\"<p>公共耦合</p>\",\"prefix\":\"C\"},{\"content\":\"<p>控制耦合</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">当一个模块通过参数表传递的是一个复杂的数据结构（如整个记录、数组或对象），而目标模块只使用了其中的一部分数据时，这种耦合被称为：</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:28:26', 14);
INSERT INTO `sys_oper_log` VALUES (808, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.143.100', 'XX XX', '{\"analysis\":\"<p><span style=\\\"background-color: rgb(196, 238, 208); color: rgb(31, 31, 31);\\\">根据笔记：初态只有一个，终态可以有多个（或没有）。</span></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">判断：在状态转换图中，初态可以有多个，但终态只能有一个。</span></p><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":4,\"requireOrder\":false,\"score\":1,\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-14 16:29:37', 13);
INSERT INTO `sys_oper_log` VALUES (809, '题目表', 3, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.remove()', 'DELETE', 1, 'admin', '研发部门', '/quiz/question/71,70,69,68,67,66', '120.85.143.100', 'XX XX', '{}', '{\"msg\":\"该试卷下有答题记录，请先删除\",\"code\":500}', 0, NULL, '2026-01-14 16:30:48', 23);
INSERT INTO `sys_oper_log` VALUES (810, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoComposeByDate()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose-by-date', '120.85.143.100', 'XX XX', '{\"beginTime\":\"2026-01-14\",\"enableAntiCheat\":false,\"endTime\":\"2026-01-14\",\"subjectId\":1}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"<p>简单来说，软件生命周期的<strong>定义时期</strong>就是动工前的“<strong>搞清楚阶段</strong>”，主要分这三步：</p><p><br></p><ol><li><strong>问题定义</strong>：弄明白<strong>你要解决什么麻烦</strong>？（定目标）</li><li><strong>可行性研究</strong>：分析这事儿<strong>值不值得做、能不能做成</strong>？（避坑）</li><li><strong>需求分析</strong>：定好软件<strong>具体要实现哪些功能</strong>。（列清单）</li></ol><p><strong>一句话总结：</strong></p><p>就是先看<strong>干什么</strong>，再看<strong>能不能干</strong>，最后定好<strong>怎么算干完</strong>。</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"correctFormat\":\"html\",\"id\":191,\"itemOrder\":0,\"items\":[{\"content\":\"<p>需求分析、总体设计、测试</p>\",\"prefix\":\"A\"},{\"content\":\"<p>总体设计、详细设计、编码</p>\",\"prefix\":\"B\"},{\"content\":\"<p>问题定义、可行性研究、需求分析</p>\",\"prefix\":\"C\"},{\"content\":\"<p>业务建模、需求分析、体系结构设计</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"color: rgb(31, 31, 31); background-color: rgb(255, 255, 255);\\\">在软件生命周期的软件定义时期，主要包括哪三个阶段</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1},{\"analysis\":\"<p>瀑布模型（Waterfall Model）是软件工程中最经典的开发模型。用大白话讲，它就像<strong>工厂的流水线</strong>或是<strong>盖房子</strong>。</p><p>其主要特征可以概括为以下三点：</p><p><br></p><h3>1. 顺序性（按部就班）</h3><p>像下楼梯一样，必须<strong>走完一步才能走下一步</strong>。你不能还没画好图纸（设计）就开始砌墙（编码），也不能还没砌墙就开始刷漆（测试）。</p><p><br></p><h3>2. 依赖性（承上启下）</h3><p>每个阶段的<strong>产出</strong>就是下一个阶段的<strong>输入</strong>。</p><p><br></p><ul><li>比如：只有拿到了“需求说明书”，设计人员才能开始画架构图。</li></ul><p><br></p><p>**</p><h3>3. 推迟实现（见效晚）</h3><p>在瀑布模型中，只有到整个流程的<strong>后期</strong>（编码和测试阶段），才能看到实际运行的代码。前期基本都在写文档、开会。</p><h3>💡 解析小贴士：</h3><ul><li><strong>优点</strong>：非常规范，每个阶段都有文档，适合需求明确、变动小的项目（如航天、银行核心系统）。</li><li><strong>缺点</strong>：太死板。如果最后测试发现需求搞错了，回头改的成本极高（就像房子盖好了发现地基歪了）。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctFormat\":\"html\",\"id\":192,\"itemOrder\":1,\"items\":[{\"content\":\"<p>强调减少文档，增加沟通</p>\",\"prefix\":\"A\"},{\"content\":\"<p>阶段间具有顺序性和依赖性</p>\",\"prefix\":\"B\"},{\"content\":\"<p>以用户原型驱动开发</p>\",\"prefix\":\"C\"', 0, NULL, '2026-01-14 16:52:09', 2037);
INSERT INTO `sys_oper_log` VALUES (811, '试卷', 1, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/paper', '120.85.143.100', 'XX XX', '{\"enableAntiCheat\":false,\"paperName\":\"软件工程期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"<p>简单来说，软件生命周期的<strong>定义时期</strong>就是动工前的“<strong>搞清楚阶段</strong>”，主要分这三步：</p><p><br></p><ol><li><strong>问题定义</strong>：弄明白<strong>你要解决什么麻烦</strong>？（定目标）</li><li><strong>可行性研究</strong>：分析这事儿<strong>值不值得做、能不能做成</strong>？（避坑）</li><li><strong>需求分析</strong>：定好软件<strong>具体要实现哪些功能</strong>。（列清单）</li></ol><p><strong>一句话总结：</strong></p><p>就是先看<strong>干什么</strong>，再看<strong>能不能干</strong>，最后定好<strong>怎么算干完</strong>。</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"correctFormat\":\"html\",\"id\":191,\"itemOrder\":0,\"items\":[{\"content\":\"<p>需求分析、总体设计、测试</p>\",\"prefix\":\"A\"},{\"content\":\"<p>总体设计、详细设计、编码</p>\",\"prefix\":\"B\"},{\"content\":\"<p>问题定义、可行性研究、需求分析</p>\",\"prefix\":\"C\"},{\"content\":\"<p>业务建模、需求分析、体系结构设计</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"color: rgb(31, 31, 31); background-color: rgb(255, 255, 255);\\\">在软件生命周期的软件定义时期，主要包括哪三个阶段</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1},{\"analysis\":\"<p>瀑布模型（Waterfall Model）是软件工程中最经典的开发模型。用大白话讲，它就像<strong>工厂的流水线</strong>或是<strong>盖房子</strong>。</p><p>其主要特征可以概括为以下三点：</p><p><br></p><h3>1. 顺序性（按部就班）</h3><p>像下楼梯一样，必须<strong>走完一步才能走下一步</strong>。你不能还没画好图纸（设计）就开始砌墙（编码），也不能还没砌墙就开始刷漆（测试）。</p><p><br></p><h3>2. 依赖性（承上启下）</h3><p>每个阶段的<strong>产出</strong>就是下一个阶段的<strong>输入</strong>。</p><p><br></p><ul><li>比如：只有拿到了“需求说明书”，设计人员才能开始画架构图。</li></ul><p><br></p><p>**</p><h3>3. 推迟实现（见效晚）</h3><p>在瀑布模型中，只有到整个流程的<strong>后期</strong>（编码和测试阶段），才能看到实际运行的代码。前期基本都在写文档、开会。</p><h3>💡 解析小贴士：</h3><ul><li><strong>优点</strong>：非常规范，每个阶段都有文档，适合需求明确、变动小的项目（如航天、银行核心系统）。</li><li><strong>缺点</strong>：太死板。如果最后测试发现需求搞错了，回头改的成本极高（就像房子盖好了发现地基歪了）。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctFormat\":\"html\",\"id\":192,\"itemOrder\":1,\"items\":[{\"content\":\"<p>强调减少文档，增加沟通</p>\",\"prefix\":\"A\"},{\"content\":\"<p>阶段间具有顺序性和依赖性</p>\",\"prefix\":\"B\"},{\"content\":\"<p>以用户原型驱动开发</p>\",\"prefix\":\"C\"},{\"conte', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperId\":98,\"paperName\":\"软件工程期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"<p>简单来说，软件生命周期的<strong>定义时期</strong>就是动工前的“<strong>搞清楚阶段</strong>”，主要分这三步：</p><p><br></p><ol><li><strong>问题定义</strong>：弄明白<strong>你要解决什么麻烦</strong>？（定目标）</li><li><strong>可行性研究</strong>：分析这事儿<strong>值不值得做、能不能做成</strong>？（避坑）</li><li><strong>需求分析</strong>：定好软件<strong>具体要实现哪些功能</strong>。（列清单）</li></ol><p><strong>一句话总结：</strong></p><p>就是先看<strong>干什么</strong>，再看<strong>能不能干</strong>，最后定好<strong>怎么算干完</strong>。</p>\",\"analysisFormat\":\"html\",\"correct\":\"C\",\"correctFormat\":\"html\",\"id\":191,\"itemOrder\":0,\"items\":[{\"content\":\"<p>需求分析、总体设计、测试</p>\",\"prefix\":\"A\"},{\"content\":\"<p>总体设计、详细设计、编码</p>\",\"prefix\":\"B\"},{\"content\":\"<p>问题定义、可行性研究、需求分析</p>\",\"prefix\":\"C\"},{\"content\":\"<p>业务建模、需求分析、体系结构设计</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"color: rgb(31, 31, 31); background-color: rgb(255, 255, 255);\\\">在软件生命周期的软件定义时期，主要包括哪三个阶段</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":1},{\"analysis\":\"<p>瀑布模型（Waterfall Model）是软件工程中最经典的开发模型。用大白话讲，它就像<strong>工厂的流水线</strong>或是<strong>盖房子</strong>。</p><p>其主要特征可以概括为以下三点：</p><p><br></p><h3>1. 顺序性（按部就班）</h3><p>像下楼梯一样，必须<strong>走完一步才能走下一步</strong>。你不能还没画好图纸（设计）就开始砌墙（编码），也不能还没砌墙就开始刷漆（测试）。</p><p><br></p><h3>2. 依赖性（承上启下）</h3><p>每个阶段的<strong>产出</strong>就是下一个阶段的<strong>输入</strong>。</p><p><br></p><ul><li>比如：只有拿到了“需求说明书”，设计人员才能开始画架构图。</li></ul><p><br></p><p>**</p><h3>3. 推迟实现（见效晚）</h3><p>在瀑布模型中，只有到整个流程的<strong>后期</strong>（编码和测试阶段），才能看到实际运行的代码。前期基本都在写文档、开会。</p><h3>💡 解析小贴士：</h3><ul><li><strong>优点</strong>：非常规范，每个阶段都有文档，适合需求明确、变动小的项目（如航天、银行核心系统）。</li><li><strong>缺点</strong>：太死板。如果最后测试发现需求搞错了，回头改的成本极高（就像房子盖好了发现地基歪了）。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctFormat\":\"html\",\"id\":192,\"itemOrder\":1,\"items\":[{\"content\":\"<p>强调减少文档，增加沟通</p>\",\"prefix\":\"A\"},{\"content\":\"<p>阶段间具有顺序性和依赖性</p>\",\"prefix\":\"B\"},{\"cont', 0, NULL, '2026-01-14 16:52:31', 944);
