INSERT INTO `sys_oper_log` VALUES (818, '科目管理', 1, 'com.ruoyi.web.controller.quiz.admin.DamingSubjectController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/subject', '120.85.42.178', 'XX XX', '{\"createTime\":\"2026-01-15 10:02:44\",\"delFlag\":0,\"params\":{},\"subjectId\":5,\"subjectName\":\"操作系统\",\"updateTime\":\"2026-01-15 10:02:44\"}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 10:02:44', 27);
INSERT INTO `sys_oper_log` VALUES (819, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<h3>1. 并发：大厨“左右开弓”</h3><ul><li><strong>大白话：</strong> 厨师同时炒几份菜。</li><li><strong>记忆点：</strong> 虽然大厨只有双手，但他一会儿翻这个锅，一会儿撒那个盐，<strong>看起来</strong>像是在同时炒好几道菜。</li></ul><h3>2. 共享：调料“大家共用”</h3><ul><li><strong>大白话：</strong> 一罐盐，你用完我再用。</li><li><strong>记忆点：</strong> 厨房里的调料（资源）是公用的，大家<strong>分时</strong>或者<strong>一起</strong>使用，而不是每个人都买一套。</li></ul><h3>3. 虚拟：给你“专属错觉”</h3><ul><li><strong>大白话：</strong> 让你觉得整个食堂只有你一个顾客。</li><li><strong>记忆点：</strong> 操作系统像个高级管家，通过技术手段让你觉得 CPU 全是你的、内存无限大，就像**“空手套白狼”**。</li></ul><h3>4. 异步：走走“停停等位”</h3><ul><li><strong>大白话：</strong> 谁先吃完不一定。</li><li><strong>记忆点：</strong> 即使你先点餐，但可能因为你的菜难做（IO阻塞），导致后点餐的人先吃完走人。程序运行的速度是<strong>不可预知</strong>的。</li></ul><h3>记忆口诀（四字经）：</h3><blockquote><strong>并</strong>发——假装同时；</blockquote><blockquote><strong>共</strong>享——资源公用；</blockquote><blockquote><strong>虚</strong>拟——空手套白狼；</blockquote><blockquote><strong>异</strong>步——走走又停停。</blockquote><p>——————————兵工蓄意</p>\",\"analysisFormat\":\"html\",\"correct\":\"并发性,共享性,虚拟性,异步性\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>操作系统的基本特征</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 10:04:45', 23);
INSERT INTO `sys_oper_log` VALUES (820, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"中断机制\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>Cpu的并行基础是什么</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 10:05:36', 14);
INSERT INTO `sys_oper_log` VALUES (821, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>简述批处理系统，分时操作系统，实时操作系统的特点</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', NULL, 1, '\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'correct\' at row 1\n### The error may exist in URL [jar:file:/root/paper/ruoyi-admin.jar!/BOOT-INF/lib/dm_questionBank-3.8.8.jar!/mapper/quiz/DamingQuestionMapper.xml]\n### The error may involve com.dm.quiz.mapper.DamingQuestionMapper.insertDamingQuestion-Inline\n### The error occurred while setting parameters\n### SQL: insert into daming_question          ( question_type,             question_info_id,             correct,             score,                          subject_id )           values ( ?,             ?,             ?,             ?,                          ? )\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'correct\' at row 1\n; Data truncation: Data too long for column \'correct\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'correct\' at row 1', '2026-01-15 11:05:34', 267);
INSERT INTO `sys_oper_log` VALUES (822, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\",\"analysisFormat\":\"markdown\",\"correct\":\"11\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>简述批处理系统，分时操作系统，实时操作系统的特点</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:05:56', 26);
INSERT INTO `sys_oper_log` VALUES (823, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\\n\\n\\n\\n| 特性         | 批处理系统         | 分时系统                | 实时系统               |\\n| ------------ | ------------------ | ----------------------- | ---------------------- |\\n| **首要目标** | 资源利用率、吞吐量 | **人机交互、响应速度**  | **及时响应、高可靠性** |\\n| **交互性**   | 极差（几乎无）     | **强**                  | 弱（主要与设备交互）   |\\n| **可靠性**   | 一般               | 一般                    | **极高**               |\\n| **调度方式** | 作业调度           | **时间片轮转**          | **优先级抢占**         |\\n| **应用领域** | 科学计算、数据处理 | 通用计算机（Win/Linux） | 导弹、航天、工业控制   |\\n\\n* * *\\n\\n### \",\"analysisFormat\":\"markdown\",\"correct\":\"11\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":254,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>简述批处理系统，分时操作系统，实时操作系统的特点</p>\",\"questionTitleFormat\":\"', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:07:17', 21);
INSERT INTO `sys_oper_log` VALUES (824, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\\n\\n\\n\\n| 特性         | 批处理系统         | 分时系统                | 实时系统               |\\n| ------------ | ------------------ | ----------------------- | ---------------------- |\\n| **首要目标** | 资源利用率、吞吐量 | **人机交互、响应速度**  | **及时响应、高可靠性** |\\n| **交互性**   | 极差（几乎无）     | **强**                  | 弱（主要与设备交互）   |\\n| **可靠性**   | 一般               | 一般                    | **极高**               |\\n| **调度方式** | 作业调度           | **时间片轮转**          | **优先级抢占**         |\\n| **应用领域** | 科学计算、数据处理 | 通用计算机（Win/Linux） | 导弹、航天、工业控制   |\\n\\n* * *\\n\\n### \",\"analysisFormat\":\"markdown\",\"correct\":\"11\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":254,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>简述批处理系统，分时操作系统，实时操作系统的特点</p>\",\"questionTitleFormat\":\"', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:07:24', 21);
INSERT INTO `sys_oper_log` VALUES (825, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>在操作系统考试中，如果问到“<strong>提高单机资源利用率的关键</strong>”，最核心的得分点是**“多道程序设计技术”（Multi-programming）**。</p><p>以下是针对考试的“踩点”分析：</p><h3>1. 核心技术：多道程序设计</h3><p>这是提高利用率的<strong>根本手段</strong>。</p><p><br></p><ul><li><strong>定义：</strong> 在内存中同时存放多道作业，使它们共享系统资源。</li><li><strong>关键点：</strong> 当一道程序因 I/O 请求而暂停执行时，CPU 立即转去执行另一道程序，从而使 CPU 保持忙碌。</li></ul><h3>2. 提高利用率的三个具体维度</h3><p>考试大题通常需要从以下三个方面展开说明：</p><p><br></p><h4>① CPU 与 I/O 设备并行</h4><ul><li><strong>单道系统：</strong> CPU 必须等待 I/O 完成（如打印、读盘），此时 CPU 空闲，浪费极大。</li><li><strong>多道系统：</strong> 利用<strong>中断技术</strong>，实现 CPU 与外设、外设与外设之间的<strong>并行工作</strong>，大幅减少 CPU 的等待时间。</li></ul><h4>② 内存利用率</h4><ul><li>通过<strong>作业调度</strong>和<strong>存储管理</strong>（如请求分页存储管理），将内存划分给多个作业，避免了大块内存闲置。</li></ul><h4>③ 外部设备均衡使用</h4><ul><li>通过合理的<strong>设备分配策略</strong>，让打印机、磁盘等各类设备尽可能同时运转。</li></ul><h3>3. 实现利用率最大化的支撑技术</h3><p>如果题目较难，需要补充这些支撑技术：</p><p><br></p><ul><li><strong>中断机制：</strong> 它是并行工作的物理基础，没有中断，CPU 就无法在任务间切换。</li><li><strong>通道技术（Channel）：</strong> 专门负责 I/O 的处理器，把 CPU 从繁重的 I/O 事务中解放出来。</li><li><strong>缓冲技术（Buffering）：</strong> 缓解 CPU 与低速外设速度不匹配的矛盾，进一步减少 CPU 等待。</li></ul><h3>4. 考试陷阱：利用率是越高越好吗？</h3><p>有时会有简答题问“利用率的极限”。</p><p><br></p><ul><li><strong>踩点答法：</strong> 不是。如果内存中程序过多，会导致**“抖动”（Thrashing）**，即系统大部分时间在进行页面交换（置换算法），反而导致有效处理时间骤降。</li></ul><p><strong>总结成一句话：</strong> 提高单机利用率的关键是<strong>引入多道程序设计</strong>，利用<strong>并行技术</strong>消除 CPU 等待 I/O 的空闲时间。</p>\",\"analysisFormat\":\"html\",\"correct\":\"多道程序设计\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>提高单机利用率关键</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:09:36', 21);
INSERT INTO `sys_oper_log` VALUES (826, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\\n\\n**缺点：**\\n\\n1.资源利用率低（预留资源给高优先级的任务使用，防止VIP来了还得花点时间腾座）\\n2.开销大，因为抢占式的要切换来切换去的\\n\\n| 特性         | 批处理系统         | 分时系统                | 实时系统               |\\n| ------------ | ------------------ | ----------------------- | ---------------------- |\\n| **首要目标** | 资源利用率、吞吐量 | **人机交互、响应速度**  | **及时响应、高可靠性** |\\n| **交互性**   | 极差（几乎无）     | **强**                  | 弱（主要与设备交互）   |\\n| **可靠性**   | 一般               | 一般                    | **极高**               |\\n| **调度方式** | 作业调度           | **时间片轮转**          | **优先级抢占**         |\\n| **应用领域** | 科学计算、数据处理 | 通用计算机（Win/Linux） | 导弹、航天、工业控制   |\\n\\n* * *\\n\\n### \",\"analysisFormat\":\"markdown\",\"correct\":\"11\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":254,\"items\":[],\"optionFormat\":\"html\",', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:16:07', 25);
INSERT INTO `sys_oper_log` VALUES (827, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"空闲让进      临界区没有进程则放进来执行\\n\\n忙着等待      临界区有人了，其他人进不来，**互斥**防止共享数据被修改导致混乱\\n\\n有限等待      防止死等或者死被人插队导致望眼欲穿，饥饿死   **超时机制**\\n\\n让权等待     当被挡在临界区门外时应该进入阻塞状态，**不应该盲等占用cpu资源**搁那一直判断检查，**提高了cpu利用率，** \",\"analysisFormat\":\"markdown\",\"correct\":\"空闲让进,忙则等待,有限等待,让权等待\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>同步机制的准则包括哪四个\\t\\t</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:19:09', 28);
INSERT INTO `sys_oper_log` VALUES (828, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(51, 51, 51);\\\">一次仅允许一个进程使用的资源</span></p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>什么是临界资源？</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:19:57', 15);
INSERT INTO `sys_oper_log` VALUES (829, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"<p>进程中访问临界资源的那段代码程序</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>什么是临界区\\t\\t\\t</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:21:05', 23);
INSERT INTO `sys_oper_log` VALUES (830, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"<p>两个或两个以上的进程互相持有对方资源且不释放导致所有进程阻塞的状态</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>什么是死锁状态</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:25:35', 15);
INSERT INTO `sys_oper_log` VALUES (831, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"互斥,请求和保持,循环等待,不可剥夺\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>死锁的四个必要条件__条件，__条件,__条件,__条件</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:27:00', 20);
INSERT INTO `sys_oper_log` VALUES (832, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<h3>1. 预防死锁 (Deadlock Prevention)</h3><p><strong>核心思路：</strong> 破坏产生死锁的四个必要条件中的一个或多个。</p><ul><li><strong>破坏“请求和保持”条件：</strong> 采用<strong>一次性分配策略</strong>。要求作业在运行前必须一次性申请完全部资源，否则不投入运行。</li><li><strong>破坏“不可剥夺”条件：</strong> 当一个进程请求新资源得不到满足时，必须<strong>释放已占有的所有资源</strong>，以后再重新申请。</li><li><strong>破坏“循环等待”条件：</strong> 采用<strong>资源有序分配法</strong>。给所有资源编号，进程必须严格按照编号递增的顺序申请资源。</li></ul><blockquote><strong>注意：</strong> “互斥条件”通常无法破坏，因为这是资源的物理属性（如打印机）。</blockquote><h3>2. 避免死锁 (Deadlock Avoidance)</h3><p><strong>核心思路：</strong> 在资源动态分配过程中，防止系统进入<strong>不安全状态</strong>。</p><ul><li><strong>银行家算法 (Banker\'s Algorithm)：</strong> 这是最高频的计算题考点。系统在分配资源前，先计算此次分配后系统是否仍处于<strong>安全状态</strong>（即是否存在一个安全序列让所有进程完成）。</li><li class=\\\"ql-indent-1\\\"><strong>安全状态</strong> $\\\\rightarrow$ 分配。</li><li class=\\\"ql-indent-1\\\"><strong>不安全状态</strong> $\\\\rightarrow$ 拒绝分配，进程阻塞。</li><li><img src=\\\"https://encrypted-tbn0.gstatic.com/licensed-image?q=tbn:ANd9GcSckJsme_oKGeCE10OCGe08XKPV-tSdRkARAVxK6d1qcJ6NMUJ9eHd3jwXu7u_kmrvNDtM8lIrSSeCYLe4ZjDj2c6okGVJ6qoEQOTxkwK5tqa1Z2PE\\\" alt=\\\"Image of Banker\'s Algorithm flowchart\\\" height=\\\"880\\\" width=\\\"551\\\">Shutterstock</li><li>Explore</li></ul><h3>3. 检测死锁 (Deadlock Detection)</h3><p><strong>核心思路：</strong> 允许死锁发生，但系统会定期检测。</p><ul><li><strong>资源分配图 (Resource Allocation Graph)：</strong> 通过“死锁定理”简化图形。</li><li><strong>检测时机：</strong> 当 CPU 利用率下降或定时检测时运行检测程序。如果资源分配图<strong>不可完全简化</strong>，则说明发生了死锁。</li></ul><h3>4. 解除死锁 (Deadlock Recovery)</h3><p><strong>核心思路：</strong> 当检测到死锁后，采取措施强行打破僵局。</p><ul><li><strong>资源剥夺法：</strong> 挂起某些死锁进程，抢占它的资源分配给其他进程。</li><li><strong>撤销进程法（终止进程）：</strong> * <strong>全部撤销：</strong> 撤销所有死锁进程（最简单粗暴）。</li><li class=\\\"ql-indent-1\\\"><strong>逐个撤销：</strong> 按照代价最小原则，逐个杀死进程直到死锁消失。</li><li><strong>进程回退法：</strong> 让死锁进程回退到足以避开死锁的“检查点”，重新执行。</li></ul><p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>预防、避免、检测、解除死锁</p><p><strong>育碧简介</strong></p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>处理死锁的方法</p>\",', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:30:10', 20);
INSERT INTO `sys_oper_log` VALUES (833, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"B\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[{\"content\":\"正确\",\"prefix\":\"A\"},{\"content\":\"错误\",\"prefix\":\"B\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p>不安全的状态一定是死锁状态吗</p>\",\"questionTitleFormat\":\"html\",\"questionType\":4,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:31:56', 21);
INSERT INTO `sys_oper_log` VALUES (834, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"内核态,用户态\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p> CPU 的<strong>指令执行的</strong>两种不同的状态</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:35:52', 19);
INSERT INTO `sys_oper_log` VALUES (835, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"<ul><li><strong>互斥 (Mutual Exclusion)：</strong> 一种资源每次只能被<strong>一个进程</strong>使用。就像独木桥，一次只能过一个人。</li><li><strong>占用等待 (Hold and Wait)：</strong> 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程<strong>既不释放已有的，也不停止索取新的</strong>。</li><li><strong>非抢占性 (No Preemption)：</strong> 资源不能被强制剥夺。只有当进程使用完毕后，才<strong>自愿释放</strong>，别人不能从它手里抢走。</li><li><strong>循环等待 (Circular Wait)：</strong> 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个<strong>闭合的环</strong>（A等B，B等C，C等A）。</li></ul><p><strong>一句话总结：</strong></p><p>大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":260,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>死锁的四个必要条件 </p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:46:41', 18);
INSERT INTO `sys_oper_log` VALUES (836, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"两个或两个以上进程**互相持有对方所需资源且不释放**而导致的所有相关进程处于阻塞状态\\n\\n**四个必要条件**\\n\\n- **互斥 (Mutual Exclusion)：** 一种资源每次只能被**一个进程**使用。就像独木桥，一次只能过一个人。\\n- **非抢占性 (No Preemption)：** 资源不能被强制剥夺。只有当进程使用完毕后，才**自愿释放**，别人不能从它手里抢走。\\n- **占用等待 (Hold and Wait)：** 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程**既不释放已有的，也不停止索取别人的**。\\n- **循环等待 (Circular Wait)：** 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个**闭合的环**（A等B，B等C，C等A）。\\n\\n------\\n\\n**一句话总结：** 大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。\\n\\n \",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":260,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>死锁的四个必要条件 </p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:51:08', 31);
INSERT INTO `sys_oper_log` VALUES (837, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"markdown\",\"correct\":\"两个或两个以上进程**互相持有对方所需资源且不释放**而导致的所有相关进程处于阻塞状态\\n\\n**四个必要条件**\\n\\n- **互斥 (Mutual Exclusion)：** 一种资源每次只能被**一个进程**使用。就像独木桥，一次只能过一个人。\\n- **非抢占性 (No Preemption)：** 资源不能被强制剥夺。只有当进程使用完毕后，才**自愿释放**，别人不能从它手里抢走。\\n- **占用等待 (Hold and Wait)：** 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程**既不释放已有的，也不停止索取别人的**。\\n- **循环等待 (Circular Wait)：** 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个**闭合的环**（A等B，B等C，C等A）。\\n\\n------\\n\\n**一句话总结：** 大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。\\n\\n \",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":260,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>死锁的四个必要条件 </p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:54:24', 35);
INSERT INTO `sys_oper_log` VALUES (838, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"<p>:<strong><u>一类是有结构文件，称为记录文件</u></strong>;<strong><u>另一个是无结构文件，称为流式文件</u></strong></p><p><br></p><p>记录/流式</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>文件的逻辑结构可分为两大类</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 11:56:51', 14);
INSERT INTO `sys_oper_log` VALUES (839, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"<p>1</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\" \\n\\n现有 3 个进程 、、 共享 A、B、C 这 3 类资源，系统的总资源数为 (6,8,9)，各进程占有量和最大需求量如表 2.5 所示。请根据银行家算法解答下列问题：\\n\\n(1) 目前系统是否处于安全状态？\\n\\n(2) 现在如果进程 P1 提出申请 (1,1,1) 个资源，或进程 P3 提出申请 (0,0,1) 个资源，系统是否能为它们分配资源？\\n\\n（注：表 2.5 对应内容为：\\n\\n| 进程 | 占有量 |      |      | 最大需求量 |      |      |      |\\n| :--: | :----: | :--: | :--: | :--------: | :--: | :--: | :--: |\\n|      |   A    |  B   |  C   |     A      |  B   |  C   |      |\\n|  P1  |   2    |  6   |  3   |     2      |  8   |  5   |      |\\n|  P2  |   2    |  0   |  1   |     2      |  0   |  1   |      |\\n|  P3  |   2    |  0   |  0   |     2      |  6   |  1   |  ）  |\\n\\n\",\"questionTitleFormat\":\"markdown\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 12:11:00', 21);
INSERT INTO `sys_oper_log` VALUES (840, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"**就绪态**：万事俱备，只欠 CPU。进程已获得除 CPU 时间片以外的所有必要资源。\\n\\n**运行态**：正在开工。进程已获得 CPU 时间片，程序正在处理机上执行。\\n\\n**阻塞态**：等待补给。因等待 I/O 或其他事件而无法执行，**即使** CPU 空闲也无法运行。\\n\\n\\n\\n就绪->运行：处理机从就绪队列里选一个进程执行\\n\\n运行->就绪：时间片用完或给高优先级进程让出处理机\\n\\n运行->阻塞：因等待IO事件或其他事件而暂时无法继续执行从而进入阻塞状态\\n\\n阻塞->就绪：进程等待的事件完成，进程被唤醒并进入就绪队列\\n\\n\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>进程有哪三种状态，他们之间是如何转换的</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', NULL, 1, '\n### Error updating database.  Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'correct\' at row 1\n### The error may exist in URL [jar:file:/root/paper/ruoyi-admin.jar!/BOOT-INF/lib/dm_questionBank-3.8.8.jar!/mapper/quiz/DamingQuestionMapper.xml]\n### The error may involve com.dm.quiz.mapper.DamingQuestionMapper.insertDamingQuestion-Inline\n### The error occurred while setting parameters\n### SQL: insert into daming_question          ( question_type,             question_info_id,             correct,             score,                          subject_id )           values ( ?,             ?,             ?,             ?,                          ? )\n### Cause: com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'correct\' at row 1\n; Data truncation: Data too long for column \'correct\' at row 1; nested exception is com.mysql.cj.jdbc.exceptions.MysqlDataTruncation: Data truncation: Data too long for column \'correct\' at row 1', '2026-01-15 12:25:49', 13);
INSERT INTO `sys_oper_log` VALUES (841, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"**就绪态**：万事俱备，只欠 CPU。进程已获得除 CPU 时间片以外的所有必要资源。\\n\\n**运行态**：正在开工。进程已获得 CPU 时间片，程序正在处理机上执行。\\n\\n**阻塞态**：等待补给。因等待 I/O 或其他事件而无法执行，**即使** CPU 空闲也无法运行。\\n\\n\\n\\n就绪->运行：处理机从就绪队列里选一个进程执行\\n\\n运行->就绪：时间片用完或给高优先级进程让出处理机\\n\\n运行->阻塞：因等待IO事件或其他事件而暂时无法继续执行从而进入阻塞状态\\n\\n阻塞->就绪：进程等待的事件完成，进程被唤醒并进入就绪队列\\n\\n\",\"analysisFormat\":\"markdown\",\"correct\":\"1\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>进程有哪三种状态，他们之间是如何转换的</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 12:25:58', 17);
INSERT INTO `sys_oper_log` VALUES (842, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>tomasulo算法是什么及其基本思想</strong></h2><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 15:19:10', 15);
INSERT INTO `sys_oper_log` VALUES (843, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.采用组相联映射\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 15:53:41', 32);
INSERT INTO `sys_oper_log` VALUES (844, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":268,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 15:56:41', 26);
INSERT INTO `sys_oper_log` VALUES (845, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频繁阻塞\\n\\n4.**访存频繁**：支持复杂的访存指令，但受限于内存\\n\\n5.**功耗大**：芯片控制逻辑复杂且面积大发热高\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>cics指令集存在哪些问题</strong></h2><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 16:02:24', 14);
INSERT INTO `sys_oper_log` VALUES (846, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"堆栈,累加器,通用寄存器组\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>区分不同指令集结构的主要因素是存放操作数的存储单元类型，有哪些类型</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 16:06:39', 14);
INSERT INTO `sys_oper_log` VALUES (847, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"items\":[{\"content\":\"<p>存储器-存储器型结构 (Memory-to-Memory Architecture)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>通用寄存器型结构(General-Purpose Register Architecture)</p>\",\"prefix\":\"B\"},{\"content\":\"<p>堆栈型结构(Stack Architecture)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>累加器型结构 (Accumulator Architecture)</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">区分不同指令集结构（ISA）的最主要因素是指令中存放操作数的存储单元类型。如果一个指令集结构要求所有操作数都必须显式或隐式地从一个特定的、唯一的存储位置获取，并在运算后将结果存回该位置，这种结构通常被称为：</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 16:07:44', 25);
INSERT INTO `sys_oper_log` VALUES (848, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"细分瓶颈段,重复设置瓶颈段\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>解决流水线瓶颈段问题</strong></h2><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 16:16:26', 16);
INSERT INTO `sys_oper_log` VALUES (849, '题目表', 1, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"<p><img src=\\\"https://daming-paper.oss-cn-guangzhou.aliyuncs.com/quiz/paper/answer/2026/01/15/3da4d837f56b49418d3e8275120378de.png\\\"></p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p class=\\\"ql-align-justify\\\">考虑某一两级Cache：第一级Cache为L1，第二级Cache为L2。</p><p class=\\\"ql-align-justify\\\">（1）假设在1000次访存中，L1的不命中是40次，L2的不命中是20次。求各种局部不命中率和全局不命中率。</p><p class=\\\"ql-align-justify\\\">（2）假设L2的命中时间是10个时钟周期，L2的不命中开销是100时钟周期，L1的命中时间是1个时钟周期，平均每条指令访存1.5次，不考虑写操作的影响。问：平均访存时间是多少？每条指令的平均停顿时间是多少个时钟周期？&nbsp;&nbsp;</p><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 16:27:28', 22);
INSERT INTO `sys_oper_log` VALUES (850, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoComposeByDate()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose-by-date', '120.85.42.178', 'XX XX', '{\"beginTime\":\"2026-01-15\",\"enableAntiCheat\":false,\"endTime\":\"2026-01-15\",\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperQuestionTypeDto\":[{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\\n\\n**缺点：**\\n\\n1.资源利用率低（预留资源给高优先级的任务使用，防止VIP来了还得花点时间腾座）\\n2.开销大，因为抢占式的要切换来切换去的\\n\\n| 特性         | 批处理系统         | 分时系统                | 实时系统               |\\n| ------------ | ------------------ | ----------------------- | ---------------------- |\\n| **首要目标** | 资源利用率、吞吐量 | **人机交互、响应速度**  | **及时响应、高可靠性** |\\n| **交互性**   | 极差（几乎无）     | **强**                  | 弱（主要与设备交互）   |\\n| **可靠性**   | 一般               | 一般                    | **极高**               |\\n| **调度方式** | 作业调度           | **时间片轮转**          | **优先级抢占**         |\\n| **应用领域** | 科学计算、数据处理 | 通用计算机（Win/Linux） | 导弹、航天、工业控制   |\\n\\n* * *\\n\\n### \",\"analysisFormat\":\"m', 0, NULL, '2026-01-15 17:09:07', 106);
INSERT INTO `sys_oper_log` VALUES (851, '试卷', 1, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/paper', '120.85.42.178', 'XX XX', '{\"enableAntiCheat\":false,\"paperName\":\"操作系统期末试卷\",\"paperQuestionTypeDto\":[{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\\n\\n**缺点：**\\n\\n1.资源利用率低（预留资源给高优先级的任务使用，防止VIP来了还得花点时间腾座）\\n2.开销大，因为抢占式的要切换来切换去的\\n\\n| 特性         | 批处理系统         | 分时系统                | 实时系统               |\\n| ------------ | ------------------ | ----------------------- | ---------------------- |\\n| **首要目标** | 资源利用率、吞吐量 | **人机交互、响应速度**  | **及时响应、高可靠性** |\\n| **交互性**   | 极差（几乎无）     | **强**                  | 弱（主要与设备交互）   |\\n| **可靠性**   | 一般               | 一般                    | **极高**               |\\n| **调度方式** | 作业调度           | **时间片轮转**          | **优先级抢占**         |\\n| **应用领域** | 科学计算、数据处理 | 通用计算机（Win/Linux） | 导弹、航天、工业控制   |\\n\\n* * *\\n\\n### \",\"analysisFormat\":\"markdown\",', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperId\":99,\"paperName\":\"操作系统期末试卷\",\"paperQuestionTypeDto\":[{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"**单道批处理系统**：单作业存放内存，资源利用率低，因为CPU很快，但是IO设备很慢，两个独立的装置会出现CPU一人很快做完 然后一直闲着没事干等待IO设备执行完毕\\n\\n且串行，执行完一道CPU还是IO作业再执行下一条\\n\\n1.**单作业存放**\\n\\n2.**资源利用率低**\\n\\n3.**CPU和外设串行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n\\n\\n\\n\\n**多道批处理系统**\\n\\n1.**多作业存放在内存**\\n\\n2.**资源利用率高**（CPU算1+1的时候 打印机在打印）\\n\\n3.**CPU和外设并行**\\n\\n4.**自动切换任务无需人工干预**\\n\\n5.**无交互性，作业一旦提交无法中途调试**\\n\\n>存内存，利用率，并行，自动化，无交互性\\n\\n**分时操作系统**\\n\\n1.引入时间片轮转概念\\n\\n2.==多用户互不干扰的联机且实时人机交互使用同一计算机==\\n\\n第二点一句话概括了以下四个特性，屌爆了\\n\\n多用户联机——**多路性**\\n\\n实时交互——**交互性和及时性**\\n\\n互不干扰——**独立性**\\n\\n时间片-多用户联机实时人机交互计算机互不干扰\\n\\n>云服务器，多用户远程SSH连接\\n\\n**实时操作系统**\\n\\n一句话总结四个特性，医院里病人要死了，用起搏器必须按下去马上触发起搏功能，不能延迟一小时，不然病人就寄了，或者是汽车安全气囊，不及时弹出来可能先撞死死透了才弹出来。还有就是心脏检测仪器，病人可能已经心脏停止跳动了，此时检测仪器没检测出来造成误判，死完了还没察觉到这个就是**及时性和可靠性**\\n\\n然后每5秒检测一次心脏异常，这个5秒间隔的总执行时间是确定的可预期的触发定时任务，执行特定任务所需的时间必须是可预期的、固定的。这就是**确定性**\\n\\n还有就是检测到病人心跳停止，即使当前在执行别的任务，也必须让传感器报警发出嘀嘀嘀的声音提醒医生。这就是高优先级抢占低优先级任务的抢占式特性，也就是**高优先级抢占性的**。你也可以记**抢占式的**\\n\\n\\n\\n以上内容方便理解，必要的时候最好转换成系统的资源调度关系，而非举现实生活的例子，如下\\n\\n>**及时性（Timeliness）：** 系统能对外部请求做出极其迅速的响应。响应时间通常由控制对象的实时要求决定（比如导弹拦截必须在毫秒级响应）。\\n>\\n>**可靠性（Reliability）：** 实时系统通常用于关键领域（航空、医疗、核能），因此要求极高的安全性，系统崩溃可能导致灾难性后果。\\n>\\n>**确定性/确定性行为（Determinism）：** 系统执行特定任务所需的时间必须是可预期的、固定的。\\n>\\n>**高优先级抢占（Priority-based Preemption）：** 允许高优先级的紧急任务（如传感器报警）立即中断正在运行的低优先级任务。\\n\\n**缺点：**\\n\\n1.资源利用率低（预留资源给高优先级的任务使用，防止VIP来了还得花点时间腾座）\\n2.开销大，因为抢占式的要切换来切换去的\\n\\n| 特性         | 批处理系统         | 分时系统                | 实时系统               |\\n| ------------ | ------------------ | ----------------------- | ---------------------- |\\n| **首要目标** | 资源利用率、吞吐量 | **人机交互、响应速度**  | **及时响应、高可靠性** |\\n| **交互性**   | 极差（几乎无）     | **强**                  | 弱（主要与设备交互）   |\\n| **可靠性**   | 一般               | 一般                    | **极高**               |\\n| **调度方式** | 作业调度           | **时间片轮转**          | **优先级抢占**         |\\n| **应用领域** | 科学计算、数据处理 | 通用计算机（Win/Linux） | 导弹、航天、工业控制   |\\n', 0, NULL, '2026-01-15 17:09:20', 74);
INSERT INTO `sys_oper_log` VALUES (852, '试卷', 0, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.autoComposeByDate()', 'POST', 1, 'admin', '研发部门', '/quiz/paper/auto-compose-by-date', '120.85.42.178', 'XX XX', '{\"beginTime\":\"2026-01-15\",\"enableAntiCheat\":false,\"endTime\":\"2026-01-15\",\"paperName\":\"计算机系统结构期末复习\",\"paperType\":2,\"subjectId\":3,\"suggestTime\":555}', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperName\":\"计算机系统结构期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctFormat\":\"html\",\"id\":271,\"itemOrder\":0,\"items\":[{\"content\":\"<p>存储器-存储器型结构 (Memory-to-Memory Architecture)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>通用寄存器型结构(General-Purpose Register Architecture)</p>\",\"prefix\":\"B\"},{\"content\":\"<p>堆栈型结构(Stack Architecture)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>累加器型结构 (Accumulator Architecture)</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">区分不同指令集结构（ISA）的最主要因素是指令中存放操作数的存储单元类型。如果一个指令集结构要求所有操作数都必须显式或隐式地从一个特定的、唯一的存储位置获取，并在运算后将结果存回该位置，这种结构通常被称为：</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":3}]},{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"<p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"correctFormat\":\"html\",\"id\":267,\"itemOrder\":1,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>tomasulo算法是什么及其基本思想</strong></h2><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3},{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctFormat\":\"markdown\",\"id\":268,\"itemOrder\":2,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3},{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频', 0, NULL, '2026-01-15 17:09:37', 32);
INSERT INTO `sys_oper_log` VALUES (853, '试卷', 1, 'com.ruoyi.web.controller.quiz.admin.DamingPaperController.add()', 'POST', 1, 'admin', '研发部门', '/quiz/paper', '120.85.42.178', 'XX XX', '{\"enableAntiCheat\":false,\"paperName\":\"计算机系统结构期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctFormat\":\"html\",\"id\":271,\"itemOrder\":0,\"items\":[{\"content\":\"<p>存储器-存储器型结构 (Memory-to-Memory Architecture)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>通用寄存器型结构(General-Purpose Register Architecture)</p>\",\"prefix\":\"B\"},{\"content\":\"<p>堆栈型结构(Stack Architecture)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>累加器型结构 (Accumulator Architecture)</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">区分不同指令集结构（ISA）的最主要因素是指令中存放操作数的存储单元类型。如果一个指令集结构要求所有操作数都必须显式或隐式地从一个特定的、唯一的存储位置获取，并在运算后将结果存回该位置，这种结构通常被称为：</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":3}]},{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"<p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"correctFormat\":\"html\",\"id\":267,\"itemOrder\":1,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>tomasulo算法是什么及其基本思想</strong></h2><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3},{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctFormat\":\"markdown\",\"id\":268,\"itemOrder\":2,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3},{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频繁阻塞\\n\\n4.**访存频繁**：支持复杂的访存指令，但受限于', '{\"msg\":\"操作成功\",\"code\":200,\"data\":{\"enableAntiCheat\":false,\"paperId\":100,\"paperName\":\"计算机系统结构期末复习\",\"paperQuestionTypeDto\":[{\"name\":\"单选题\",\"questionDtos\":[{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"D\",\"correctFormat\":\"html\",\"id\":271,\"itemOrder\":0,\"items\":[{\"content\":\"<p>存储器-存储器型结构 (Memory-to-Memory Architecture)</p>\",\"prefix\":\"A\"},{\"content\":\"<p>通用寄存器型结构(General-Purpose Register Architecture)</p>\",\"prefix\":\"B\"},{\"content\":\"<p>堆栈型结构(Stack Architecture)</p>\",\"prefix\":\"C\"},{\"content\":\"<p>累加器型结构 (Accumulator Architecture)</p>\",\"prefix\":\"D\"}],\"optionFormat\":\"html\",\"questionTitle\":\"<p><span style=\\\"background-color: rgb(255, 255, 255); color: rgb(31, 31, 31);\\\">区分不同指令集结构（ISA）的最主要因素是指令中存放操作数的存储单元类型。如果一个指令集结构要求所有操作数都必须显式或隐式地从一个特定的、唯一的存储位置获取，并在运算后将结果存回该位置，这种结构通常被称为：</span></p>\",\"questionTitleFormat\":\"html\",\"questionType\":1,\"requireOrder\":false,\"score\":1,\"subjectId\":3}]},{\"name\":\"主观题\",\"questionDtos\":[{\"analysis\":\"<p><br></p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"correctFormat\":\"html\",\"id\":267,\"itemOrder\":1,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>tomasulo算法是什么及其基本思想</strong></h2><p><br></p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3},{\"analysis\":\"<p>无</p>\",\"analysisFormat\":\"html\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctFormat\":\"markdown\",\"id\":268,\"itemOrder\":2,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3},{\"analysis\":\"无\",\"analysisFormat\":\"html\",\"correct\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难', 0, NULL, '2026-01-15 17:09:39', 46);
