INSERT INTO `sys_oper_log` VALUES (863, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>细分瓶颈段</p><p>重复设置瓶颈段</p>\",\"analysisFormat\":\"html\",\"correct\":\"细分瓶颈段,重复设置瓶颈段\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":272,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>解决流水线瓶颈段问题</strong></h2>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:10:35', 17);
INSERT INTO `sys_oper_log` VALUES (864, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频繁阻塞\\n\\n4.**访存频繁**：支持复杂的访存指令，但受限于内存\\n\\n5.**功耗大**：芯片控制逻辑复杂且面积大发热高\",\"analysisFormat\":\"markdown\",\"correct\":\"1.**译码难**：变长指令，格式复杂\\n\\n2.**利用率低**：百分之80的复杂指令没用到，硬件资源浪费\\n\\n3.**流水线难**：CPI差异大，流水线频繁阻塞\\n\\n4.**访存频繁**：支持复杂的访存指令，但受限于内存\\n\\n5.**功耗大**：芯片控制逻辑复杂且面积大发热高\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":269,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>cics指令集存在哪些问题</strong></h2>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:11:30', 18);
INSERT INTO `sys_oper_log` VALUES (865, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"analysisFormat\":\"markdown\",\"correct\":\"**减少命中时间**\\n\\n1.采用容量小，结构简单的cache（硬件越简单处理速度越快）\\n\\n2.使对cache访问流水化并行处理\\n\\n**降低不命中率**\\n\\n1.增加cache的容量或cache块大小\\n\\n2.提高相联度\\n\\n3.采用伪相联cache\\n\\n**减少不命中开销**\\n\\n1.使用两级cache\\n\\n2.让读不命中优先于写\",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":268,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>改进cache性能的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:11:43', 20);
INSERT INTO `sys_oper_log` VALUES (866, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>一种用于指令乱序执行的硬件调度算法</p><p>1.通过寄存器换名解决了读后写和写后写的数据名相关，操作数不再依赖于具体的寄存器而是依赖换名后存放到保留站里的一个将来标识</p><p>2.动态调度和分布式控制，一旦操作数就绪后则从保留站送往对应的功能部件运算而非原来的顺序，且不是集中控制而是由各功能部件类型对应的保留站控制</p><p>3.公共数据总线，功能部件计算得到后的结果广播给正在等待该结果的保留站或寄存器</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":267,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<h2><strong>tomasulo算法是什么及其基本思想</strong></h2>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":3}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:11:56', 20);
INSERT INTO `sys_oper_log` VALUES (867, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>:<strong><u>一类是有结构文件，称为记录文件</u></strong>;<strong><u>另一个是无结构文件，称为流式文件</u></strong></p><p><br></p><p>记录/流式</p>\",\"analysisFormat\":\"html\",\"correct\":\"<p>:<strong><u>一类是有结构文件，称为记录文件</u></strong>;<strong><u>另一个是无结构文件，称为流式文件</u></strong></p><p><br></p><p>记录/流式</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":264,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>文件的逻辑结构可分为两大类</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:12:17', 17);
INSERT INTO `sys_oper_log` VALUES (868, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>内核态  用户态</p>\",\"analysisFormat\":\"html\",\"correct\":\"内核态,用户态\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":263,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p> CPU 的<strong>指令执行的</strong>两种不同的状态</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:12:37', 25);
INSERT INTO `sys_oper_log` VALUES (869, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>预防、避免、检测、解除死锁</p><h3><strong>育碧简介</strong></h3><h3><br></h3><h3>1. 预防死锁 (Deadlock Prevention)</h3><p><strong>核心思路：</strong> 破坏产生死锁的四个必要条件中的一个或多个。</p><p><br></p><ul><li><strong>破坏“请求和保持”条件：</strong> 采用<strong>一次性分配策略</strong>。要求作业在运行前必须一次性申请完全部资源，否则不投入运行。</li><li><strong>破坏“不可剥夺”条件：</strong> 当一个进程请求新资源得不到满足时，必须<strong>释放已占有的所有资源</strong>，以后再重新申请。</li><li><strong>破坏“循环等待”条件：</strong> 采用<strong>资源有序分配法</strong>。给所有资源编号，进程必须严格按照编号递增的顺序申请资源。</li></ul><blockquote><strong>注意：</strong> “互斥条件”通常无法破坏，因为这是资源的物理属性（如打印机）。</blockquote><h3>2. 避免死锁 (Deadlock Avoidance)</h3><p><strong>核心思路：</strong> 在资源动态分配过程中，防止系统进入<strong>不安全状态</strong>。</p><p><br></p><ul><li><strong>银行家算法 (Banker\'s Algorithm)：</strong> 这是最高频的计算题考点。系统在分配资源前，先计算此次分配后系统是否仍处于<strong>安全状态</strong>（即是否存在一个安全序列让所有进程完成）。</li><li class=\\\"ql-indent-1\\\"><strong>安全状态</strong> $\\\\rightarrow$ 分配。</li><li class=\\\"ql-indent-1\\\"><strong>不安全状态</strong> $\\\\rightarrow$ 拒绝分配，进程阻塞。</li><li><img src=\\\"https://encrypted-tbn0.gstatic.com/licensed-image?q=tbn:ANd9GcSckJsme_oKGeCE10OCGe08XKPV-tSdRkARAVxK6d1qcJ6NMUJ9eHd3jwXu7u_kmrvNDtM8lIrSSeCYLe4ZjDj2c6okGVJ6qoEQOTxkwK5tqa1Z2PE\\\" alt=\\\"Image of Banker\'s Algorithm flowchart\\\" height=\\\"880\\\" width=\\\"551\\\">Shutterstock</li><li>Explore</li></ul><h3>3. 检测死锁 (Deadlock Detection)</h3><p><strong>核心思路：</strong> 允许死锁发生，但系统会定期检测。</p><p><br></p><ul><li><strong>资源分配图 (Resource Allocation Graph)：</strong> 通过“死锁定理”简化图形。</li><li><strong>检测时机：</strong> 当 CPU 利用率下降或定时检测时运行检测程序。如果资源分配图<strong>不可完全简化</strong>，则说明发生了死锁。</li></ul><h3>4. 解除死锁 (Deadlock Recovery)</h3><p><strong>核心思路：</strong> 当检测到死锁后，采取措施强行打破僵局。</p><p><br></p><ul><li><strong>资源剥夺法：</strong> 挂起某些死锁进程，抢占它的资源分配给其他进程。</li><li><strong>撤销进程法（终止进程）：</strong> * <strong>全部撤销：</strong> 撤销所有死锁进程（最简单粗暴）。</li><li class=\\\"ql-indent-1\\\"><strong>逐个撤销：</strong> 按照代价最小原则，逐个杀死进程直到死锁消失。</li><li><strong>进程回退法：</strong> 让死锁进程回退到足以避开死锁的“检查点”，重新执行。</li></ul>\",\"analysisFormat\":\"html\",\"correct\":\"<p>预防、避免、检测、解除死锁</p><p><strong>育碧简介</strong></p>\",\"correctArr', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:13:08', 16);
INSERT INTO `sys_oper_log` VALUES (870, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"两个或两个以上进程**互相持有对方所需资源且不释放**而导致的所有相关进程处于阻塞状态\\n\\n**四个必要条件**\\n\\n- **互斥 (Mutual Exclusion)：** 一种资源每次只能被**一个进程**使用。就像独木桥，一次只能过一个人。\\n- **非抢占性 (No Preemption)：** 资源不能被强制剥夺。只有当进程使用完毕后，才**自愿释放**，别人不能从它手里抢走。\\n- **占用等待 (Hold and Wait)：** 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程**既不释放已有的，也不停止索取别人的**。\\n- **循环等待 (Circular Wait)：** 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个**闭合的环**（A等B，B等C，C等A）。\\n\\n------\\n\\n**一句话总结：** 大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。\\n\\n \",\"analysisFormat\":\"markdown\",\"correct\":\"两个或两个以上进程**互相持有对方所需资源且不释放**而导致的所有相关进程处于阻塞状态\\n\\n**四个必要条件**\\n\\n- **互斥 (Mutual Exclusion)：** 一种资源每次只能被**一个进程**使用。就像独木桥，一次只能过一个人。\\n- **非抢占性 (No Preemption)：** 资源不能被强制剥夺。只有当进程使用完毕后，才**自愿释放**，别人不能从它手里抢走。\\n- **占用等待 (Hold and Wait)：** 进程已经持有了至少一个资源，但又提出了新的资源请求，而该资源被他人占用，此时进程**既不释放已有的，也不停止索取别人的**。\\n- **循环等待 (Circular Wait)：** 存在一个进程链，每个进程都在等待下一个进程所持有的资源，形成一个**闭合的环**（A等B，B等C，C等A）。\\n\\n------\\n\\n**一句话总结：** 大家各占一块地（互斥），拿在手里不撒手（非抢占），还想抢别人的（占用等待），结果大家围成一圈互相干瞪眼（循环等待）。\\n\\n \",\"correctArray\":[],\"correctFormat\":\"markdown\",\"id\":260,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>死锁的四个必要条件 </p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:13:38', 16);
INSERT INTO `sys_oper_log` VALUES (871, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"两个或两个以上的进程互相持有对方资源且不释放导致所有进程阻塞的状态\",\"analysisFormat\":\"markdown\",\"correct\":\"<p>两个或两个以上的进程互相持有对方资源且不释放导致所有进程阻塞的状态</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":259,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>什么是死锁状态</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:14:27', 19);
INSERT INTO `sys_oper_log` VALUES (872, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"进程中访问临界资源的那段代码程序\",\"analysisFormat\":\"markdown\",\"correct\":\"<p>进程中访问临界资源的那段代码程序</p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":258,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>什么是临界区\\t\\t\\t</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:14:37', 17);
INSERT INTO `sys_oper_log` VALUES (873, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>多道程序设计</p><p><br></p><p>在操作系统考试中，如果问到“<strong>提高单机资源利用率的关键</strong>”，最核心的得分点是**“多道程序设计技术”（Multi-programming）**。</p><p>以下是针对考试的“踩点”分析：</p><p><br></p><h3>1. 核心技术：多道程序设计</h3><p>这是提高利用率的<strong>根本手段</strong>。</p><p><br></p><p><br></p><ul><li><strong>定义：</strong> 在内存中同时存放多道作业，使它们共享系统资源。</li><li><strong>关键点：</strong> 当一道程序因 I/O 请求而暂停执行时，CPU 立即转去执行另一道程序，从而使 CPU 保持忙碌。</li></ul><h3>2. 提高利用率的三个具体维度</h3><p>考试大题通常需要从以下三个方面展开说明：</p><p><br></p><p><br></p><h4>① CPU 与 I/O 设备并行</h4><ul><li><strong>单道系统：</strong> CPU 必须等待 I/O 完成（如打印、读盘），此时 CPU 空闲，浪费极大。</li><li><strong>多道系统：</strong> 利用<strong>中断技术</strong>，实现 CPU 与外设、外设与外设之间的<strong>并行工作</strong>，大幅减少 CPU 的等待时间。</li></ul><h4>② 内存利用率</h4><ul><li>通过<strong>作业调度</strong>和<strong>存储管理</strong>（如请求分页存储管理），将内存划分给多个作业，避免了大块内存闲置。</li></ul><h4>③ 外部设备均衡使用</h4><ul><li>通过合理的<strong>设备分配策略</strong>，让打印机、磁盘等各类设备尽可能同时运转。</li></ul><h3>3. 实现利用率最大化的支撑技术</h3><p>如果题目较难，需要补充这些支撑技术：</p><p><br></p><p><br></p><ul><li><strong>中断机制：</strong> 它是并行工作的物理基础，没有中断，CPU 就无法在任务间切换。</li><li><strong>通道技术（Channel）：</strong> 专门负责 I/O 的处理器，把 CPU 从繁重的 I/O 事务中解放出来。</li><li><strong>缓冲技术（Buffering）：</strong> 缓解 CPU 与低速外设速度不匹配的矛盾，进一步减少 CPU 等待。</li></ul><h3>4. 考试陷阱：利用率是越高越好吗？</h3><p>有时会有简答题问“利用率的极限”。</p><p><br></p><p><br></p><ul><li><strong>踩点答法：</strong> 不是。如果内存中程序过多，会导致**“抖动”（Thrashing）**，即系统大部分时间在进行页面交换（置换算法），反而导致有效处理时间骤降。</li></ul><p><strong>总结成一句话：</strong> 提高单机利用率的关键是<strong>引入多道程序设计</strong>，利用<strong>并行技术</strong>消除 CPU 等待 I/O 的空闲时间。</p>\",\"analysisFormat\":\"html\",\"correct\":\"多道程序设计\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":255,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>提高单机利用率关键</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:15:25', 18);
INSERT INTO `sys_oper_log` VALUES (874, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>中断机制</p>\",\"analysisFormat\":\"html\",\"correct\":\"中断机制\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":253,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>Cpu的并行基础是什么</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:15:43', 19);
INSERT INTO `sys_oper_log` VALUES (875, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<h3>1. 并发：大厨“左右开弓”</h3><ul><li><strong>大白话：</strong> 厨师同时炒几份菜。</li><li><strong>记忆点：</strong> 虽然大厨只有双手，但他一会儿翻这个锅，一会儿撒那个盐，<strong>看起来</strong>像是在同时炒好几道菜。</li></ul><h3>2. 共享：调料“大家共用”</h3><ul><li><strong>大白话：</strong> 一罐盐，你用完我再用。</li><li><strong>记忆点：</strong> 厨房里的调料（资源）是公用的，大家<strong>分时</strong>或者<strong>一起</strong>使用，而不是每个人都买一套。</li></ul><h3>3. 虚拟：给你“专属错觉”</h3><ul><li><strong>大白话：</strong> 让你觉得整个食堂只有你一个顾客。</li><li><strong>记忆点：</strong> 操作系统像个高级管家，通过技术手段让你觉得 CPU 全是你的、内存无限大，就像**“空手套白狼”**。</li></ul><h3>4. 异步：走走“停停等位”</h3><ul><li><strong>大白话：</strong> 谁先吃完不一定。</li><li><strong>记忆点：</strong> 即使你先点餐，但可能因为你的菜难做（IO阻塞），导致后点餐的人先吃完走人。程序运行的速度是<strong>不可预知</strong>的。</li></ul><h3>记忆口诀（四字经）：</h3><blockquote><strong>并</strong>发——假装同时；</blockquote><blockquote><strong>共</strong>享——资源公用；</blockquote><blockquote><strong>虚</strong>拟——空手套白狼；</blockquote><blockquote><strong>异</strong>步——走走又停停。</blockquote><p>——————————兵工蓄意</p>\",\"analysisFormat\":\"html\",\"correct\":\"并发性,共享性,虚拟性,异步性\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":252,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>操作系统的基本特征</p>\",\"questionTitleFormat\":\"html\",\"questionType\":5,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:16:02', 16);
INSERT INTO `sys_oper_log` VALUES (876, '题目表', 2, 'com.ruoyi.web.controller.quiz.admin.DamingQuestionController.edit()', 'PUT', 1, 'admin', '研发部门', '/quiz/question', '120.85.42.178', 'XX XX', '{\"analysis\":\"<p>预防、避免、检测、解除死锁</p><p><br></p><h3><strong>育碧简介</strong></h3><h3><br></h3>\",\"analysisFormat\":\"html\",\"correct\":\"<p>预防、避免、检测、解除死锁</p><p><strong>育碧简介</strong></p>\",\"correctArray\":[],\"correctFormat\":\"html\",\"id\":261,\"items\":[],\"optionFormat\":\"html\",\"questionTitle\":\"<p>处理死锁的方法</p>\",\"questionTitleFormat\":\"html\",\"questionType\":3,\"requireOrder\":false,\"score\":1,\"subjectId\":5}', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-01-15 22:18:27', 17);
